/* Landing Page */
function LandingPage() {
  const { user, role, profile, getDashboardRoute, loading, isAuthenticated } = useAuth();
  const location = useLocation();
  const navigate = useNavigate();

  useEffect(() => {
    // Only auto-redirect from the actual root path
    if (!loading && isAuthenticated && location.pathname === '/') {
      const dashboardRoute = getDashboardRoute(role, profile);

      // Prevent loop: only navigate if the target is NOT the current page
      if (dashboardRoute && dashboardRoute !== '/') {
        console.log(`[LandingPage] Authenticated user at root. Redirecting to: ${dashboardRoute}`);
        navigate(dashboardRoute, { replace: true });
      }
    }
  }, [isAuthenticated, loading, role, profile, navigate, getDashboardRoute, location.pathname]);

  return (
    <>
      <Navbar />
      <Hero />
      <Popularservices />
      <Fortalent />
      <HowItWorks />
      <Whychooseus />
      <Testimonials />
      <ExperiencedFreelancers />
      <CTASection />
      <Footer />
    </>
  );
}

const ProfileRedirect = () => {
  const { user, profile, loading } = useAuth();
  if (loading) return null;
  if (!user) return <Navigate to="/login" replace />;
  // Prioritize profile id from wizard/context
  const profileId = profile?.id || user?.id;
  return <Navigate to={`/freelancer/${profileId}`} replace />;
};

function ProfileSetupGuard() {
  const { user, role, profile, loading } = useAuth();

  if (loading) return null;

  if (!user) return <Navigate to="/login" replace />;

  const isProfileCompleted = profile?.profile_completion_percentage >= 100 ||
    profile?.profileCompleted === true ||
    profile?.profile_completed === true ||
    profile?.profile_status === 'COMPLETED';

  if (['SUPER_ADMIN', 'ADMIN'].includes(role)) {
    return <Navigate to="/admin/dashboard" replace />;
  }

  if (role === 'FREELANCER' && isProfileCompleted) {
    return <Navigate to="/freelancer/dashboard" replace />;
  }

  if (role === 'CLIENT' && (profile?.is_client_profile_complete || isProfileCompleted)) {
    return <Navigate to="/client/dashboard" replace />;
  }

  return role === 'CLIENT' ? <ClientProfileWizard /> : <ProfileWizard />;
};

import { RealtimeProvider } from './context/RealtimeContext';
import { logger } from './utils/logger';

/* Main App */

function App() {
  const { user, isAuthenticated, loading } = useAuth();
  const location = useLocation();
  const navigate = useNavigate();

  useEffect(() => {
    // Wait for initial auth loading to complete before making redirect decisions
    if (loading) return;

    const token = localStorage.getItem("token") || sessionStorage.getItem("token");
    const publicRoutes = [
      '/', '/login', '/signup', '/forgot-password', '/reset-password', 
      '/verify-email', '/auth/callback', '/success', '/client-welcome',
      '/about', '/solutions', '/app-download', '/legal', '/services', '/service', '/landing',
      '/find-freelancers', '/find-work', '/signup-freelancer', '/signup-client'
    ];

    const isPublicRoute = publicRoutes.some(route => location.pathname === route || location.pathname.startsWith(route + '/'));

    // Check both memory state and persisted token for safety
    if (!loading && !token && !isAuthenticated && !isPublicRoute) {
      logger.log('[App] Unauthenticated access, redirecting to login', { path: location.pathname });
      navigate("/login");
    }

    // Track Page Visit
    analytics.trackVisit(location.pathname);
  }, [location.pathname, navigate, user, isAuthenticated, loading]);

  return (
