                  <PremiumToaster />

                  <GlobalCallManager />
                  <ScrollToTop />
                  <ScrollToHash />
                  <Suspense fallback={<LoadingSpinner />}>
                    <Routes location={location}>
                      {/* Landing page is now the default entry point for all users */}
