const UsersTable = ({
    users,
    onAction,
    pagination,
    onPageChange,
    loading,
    filters,
    onFilterChange
}) => {
    const [activeMenu, setActiveMenu] = React.useState(null);
    const navigate = useNavigate();

    const getRoleBadge = (role) => {
        const styles = {
            ADMIN: 'bg-purple-500/10 text-purple-400 border-purple-500/20',
            CLIENT: 'bg-blue-500/10 text-blue-400 border-blue-500/20',
            FREELANCER: 'bg-accent/10 text-accent border-accent/20'
        };
        return (
            <span className={`px-2.5 py-1 rounded-full text-xs font-medium border ${styles[role] || 'bg-gray-500/10 text-gray-400 border-gray-500/20'}`}>
                {role}
            </span>
        );
    };

    const getStatusBadge = (user) => {
        if (user.is_banned) {
            return (
                <span className="flex items-center gap-1.5 text-red-400 text-xs font-medium bg-red-500/10 px-2.5 py-1 rounded-full border border-red-500/20">
                    <ShieldAlert size={12} />
                    Disabled
                </span>
            );
        }
        return (
            <span className="flex items-center gap-1.5 text-green-400 text-xs font-medium bg-green-500/10 px-2.5 py-1 rounded-full border border-green-500/20">
                <Shield size={12} />
                Active
            </span>
        );
    };

    const formatDate = (date) => {
        if (!date) return 'Never';
        return new Date(date).toLocaleDateString('en-US', {
            month: 'short',
            day: 'numeric',
            year: 'numeric'
        });
    };

    return (
        <div className="bg-transparent border border-white/10 rounded-2xl overflow-hidden shadow-2xl">
            {/* Table Header / Filters */}
            <div className="p-6 border-b border-white/10 flex flex-wrap items-center justify-between gap-4">
                <div className="relative flex-1 min-w-[300px]">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-white/30" size={18} />
                    <input
                        type="text"
                        placeholder="Search by name or email..."
                        className="w-full bg-primary/50 border border-white/10 rounded-xl pl-10 pr-4 py-2.5 text-sm text-white focus:outline-none focus:border-accent/50 transition-all shadow-inner"
                        value={filters.search}
                        onChange={(e) => onFilterChange({ ...filters, search: e.target.value })}
                    />
                </div>

                <div className="flex items-center gap-3">
                    <select
                        className="bg-primary/50 border border-white/10 rounded-xl px-4 py-2.5 text-sm text-white focus:outline-none focus:border-accent/50 transition-all cursor-pointer shadow-inner"
                        value={filters.role}
                        onChange={(e) => onFilterChange({ ...filters, role: e.target.value })}
                    >
                        <option value="">All Roles</option>
                        <option value="CLIENT">Clients</option>
                        <option value="FREELANCER">Freelancers</option>
                        <option value="ADMIN">Admins</option>
                    </select>
                </div>
            </div>

            {/* Table Content */}
            <div className="overflow-x-auto">
                <table className="w-full text-left">
                    <thead>
                        <tr className="bg-white/5 text-white/50 text-xs font-semibold uppercase tracking-wider">
                            <th className="px-6 py-4">User</th>
                            <th className="px-6 py-4">Role & Status</th>
                            <th className="px-6 py-4">Profile Progress</th>
                            <th className="px-6 py-4">Created</th>
                            <th className="px-6 py-4">Last Login</th>
                            <th className="px-6 py-4 text-right">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-white/5">
                        {loading ? (
                            Array.from({ length: 5 }).map((_, i) => (
                                <tr key={i} className="animate-pulse">
                                    <td colSpan="6" className="px-6 py-8 h-20 bg-white/[0.02]"></td>
                                </tr>
                            ))
                        ) : users.length === 0 ? (
                            <tr>
                                <td colSpan="6" className="px-6 py-12 text-center text-white/30 italic">
                                    No users found matching your search.
                                </td>
                            </tr>
                        ) : (
                            users.map((user) => (
                                <tr key={user.id} className="hover:bg-white/[0.02] transition-colors group">
                                    <td className="px-6 py-4">
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 rounded-full overflow-hidden bg-accent/20 flex items-center justify-center text-accent font-bold shadow-lg border border-accent/20">
                                                {user.profile?.avatar_url ? (
                                                    <img src={user.profile.avatar_url} alt="" className="w-full h-full object-cover" />
                                                ) : (
                                                    user.profile?.name?.[0] || user.email[0].toUpperCase()
                                                )}
                                            </div>
                                            <div>
                                                <div className="text-sm font-semibold text-white group-hover:text-accent transition-colors">
                                                    {user.profile?.name || 'Incomplete Profile'}
                                                </div>
                                                <div className="text-xs text-white/40">{user.email}</div>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="px-6 py-4">
                                        <div className="flex flex-col gap-1.5">
                                            {getRoleBadge(user.role)}
                                            <div className="w-fit">{getStatusBadge(user)}</div>
                                        </div>
                                    </td>
                                    <td className="px-6 py-4">
                                        <div className="flex items-center gap-3">
                                            <div className="flex-1 max-w-[100px] h-1.5 bg-white/10 rounded-full overflow-hidden">
                                                <motion.div
                                                    initial={{ width: 0 }}
                                                    animate={{ width: `${user.profile?.profile_completion_percentage || 0}%` }}
                                                    className="h-full bg-accent shadow-[0_0_8px_rgba(122,167,255,0.5)]"
                                                />
                                            </div>
                                            <span className="text-xs font-bold text-white/70">
                                                {user.profile?.profile_completion_percentage || 0}%
                                            </span>
                                        </div>
                                    </td>
                                    <td className="px-6 py-4 text-xs font-medium text-white/60">
                                        {formatDate(user.created_at)}
                                    </td>
                                    <td className="px-6 py-4 text-xs font-medium text-white/60">
                                        {formatDate(user.last_login)}
                                    </td>
                                    <td className="px-6 py-4 text-right">
                                        <div className="relative inline-block text-left">
                                            <button
                                                onClick={() => setActiveMenu(activeMenu === user.id ? null : user.id)}
                                                className="p-2 hover:bg-white/10 rounded-lg text-white/40 hover:text-white transition-all active:scale-90"
                                            >
                                                <MoreVertical size={20} />
                                            </button>

                                            <AnimatePresence>
                                                {activeMenu === user.id && (
                                                    <>
                                                        <div
                                                            className="fixed inset-0 z-10"
                                                            onClick={() => setActiveMenu(null)}
                                                        />
                                                        <motion.div
                                                            initial={{ opacity: 0, scale: 0.95, y: -10 }}
                                                            animate={{ opacity: 1, scale: 1, y: 0 }}
                                                            exit={{ opacity: 0, scale: 0.95, y: -10 }}
                                                            className="absolute right-0 mt-2 w-52 bg-secondary border border-white/10 rounded-xl shadow-2xl z-20 py-1 overflow-hidden"
                                                        >
                                                            <button
                                                                onClick={() => {
                                                                    setActiveMenu(null);
                                                                    if (user.role === 'FREELANCER') {
                                                                        navigate(`/freelancer/${user.id}`);
                                                                    } else {
                                                                        navigate(`/admin/users/${user.id}`);
                                                                    }
                                                                }}
                                                                className="w-full flex items-center gap-2.5 px-4 py-2.5 text-sm text-accent/80 hover:text-accent hover:bg-white/5 transition-colors"
                                                            >
                                                                <ExternalLink size={16} /> View Profile
                                                            </button>
                                                            <div className="h-px bg-white/5 my-1" />
                                                            <button
                                                                onClick={() => { onAction(user.id, 'RESET_PASSWORD'); setActiveMenu(null); }}
                                                                className="w-full flex items-center gap-2.5 px-4 py-2.5 text-sm text-white/70 hover:text-accent hover:bg-white/5 transition-colors"
                                                            >
                                                                <RefreshCcw size={16} /> Reset Password
                                                            </button>
                                                            <button
                                                                onClick={() => { onAction(user.id, 'TOGGLE_STATUS', !user.is_banned); setActiveMenu(null); }}
                                                                className={`w-full flex items-center gap-2.5 px-4 py-2.5 text-sm transition-colors ${user.is_banned ? 'text-green-400/70 hover:text-green-400' : 'text-orange-400/70 hover:text-orange-400'} hover:bg-white/5`}
                                                            >
                                                                {user.is_banned ? <UserCheck size={16} /> : <UserX size={16} />}
                                                                {user.is_banned ? 'Enable Account' : 'Disable Account'}
                                                            </button>
                                                            <div className="h-px bg-white/5 my-1" />
                                                            <button
                                                                onClick={() => { onAction(user.id, 'DELETE'); setActiveMenu(null); }}
                                                                className="w-full flex items-center gap-2.5 px-4 py-2.5 text-sm text-red-400/70 hover:text-red-400 hover:bg-red-500/5 transition-colors"
                                                            >
                                                                <Trash2 size={16} /> Delete User
                                                            </button>
                                                        </motion.div>
                                                    </>
                                                )}
                                            </AnimatePresence>
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            {/* Pagination */}
            <div className="p-6 border-t border-white/10 flex items-center justify-between gap-4 bg-white/5">
                <div className="text-xs font-semibold text-white/40 uppercase tracking-widest">
                    Showing <span className="text-white">{(pagination.offset || 0) + 1}</span> to <span className="text-white">{Math.min((pagination.offset || 0) + pagination.limit, pagination.total)}</span> of <span className="text-white">{pagination.total}</span> entries
                </div>
                <div className="flex items-center gap-2">
                    <button
                        disabled={pagination.offset === 0 || loading}
                        onClick={() => onPageChange(pagination.offset - pagination.limit)}
                        className="p-2 hover:bg-white/10 disabled:opacity-30 disabled:hover:bg-transparent rounded-lg text-white transition-all active:scale-90"
                    >
                        <ChevronLeft size={20} />
                    </button>
                    <button
                        disabled={(pagination.offset + pagination.limit) >= pagination.total || loading}
                        onClick={() => onPageChange(pagination.offset + pagination.limit)}
                        className="p-2 hover:bg-white/10 disabled:opacity-30 disabled:hover:bg-transparent rounded-lg text-white transition-all active:scale-90"
                    >
                        <ChevronRight size={20} />
                    </button>
                </div>
            </div>
        </div>
    );
};

export default UsersTable;

import React, { useState, useEffect } from 'react';
import { Clock, User, Briefcase, CreditCard, ShieldCheck, Zap } from 'lucide-react';
import { fetchAdminLogs } from '../../../services/adminService';

const ActivityPanel = ({ limit = 6 }) => {
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadActivities = async () => {
      try {
        const response = await fetchAdminLogs({ limit });
        setActivities(response.data || []);
      } catch (error) {
        console.error("Failed to load activities", error);
      } finally {
        setLoading(false);
      }
    };

    loadActivities();
    const interval = setInterval(loadActivities, 30000);
    return () => clearInterval(interval);
  }, [limit]);

  const getActivityIcon = (type) => {
    if (type.includes('USER')) return <User size={18} className="text-blue-400" />;
    if (type.includes('JOB')) return <Briefcase size={18} className="text-purple-400" />;
    if (type.includes('PAYMENT') || type.includes('WITHDRAWAL')) return <CreditCard size={18} className="text-green-400" />;
    if (type.includes('VERIFICATION')) return <ShieldCheck size={18} className="text-accent" />;
    return <Zap size={18} className="text-yellow-400" />;
  };


  const formatTime = (date) => {
    if (!date) return '--:--';
    const d = new Date(date);
    if (isNaN(d.getTime())) return '--:--';
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  // Simple grouping: Items from today vs older
  const today = new Date().toDateString();
  const todayActivities = activities.filter(a => new Date(a.created_at).toDateString() === today);
  const otherActivities = activities.filter(a => new Date(a.created_at).toDateString() !== today);

  const ActivityGroup = ({ title, items }) => (
    <div className="space-y-6">
      <h4 className="text-white/20 text-[10px] font-black uppercase tracking-[0.2em] mb-4">
        {title}
      </h4>
      <div className="space-y-8 relative">
        {/* Timeline line */}
        <div className="absolute left-4 top-2 bottom-2 w-px bg-white/5 z-0" />

        {items.map((activity, idx) => (
          <div key={activity.id} className="flex gap-4 group relative z-10">
            <div className="w-8 h-8 shrink-0 flex items-center justify-center transition-all group-hover:scale-110">
              {getActivityIcon(activity.action_type || 'SYSTEM')}
            </div>

            <div className="flex-1 min-w-0 -mt-0.5">
              <p className="text-[10px] text-white/40 font-black uppercase tracking-tight mb-1">
                {formatTime(activity.created_at)}
              </p>
              <p className="text-xs text-slate-300 leading-snug group-hover:text-white transition-colors">
                <span className="font-bold text-white pr-1">{activity.admin_email ? activity.admin_email.split('@')[0] : 'System'}</span>
                {activity.description}
              </p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );


  return (
    <div className="bg-transparent border border-white/5 rounded-[32px] p-8 h-full shadow-sm">
      <div className="flex items-center justify-between mb-8">
        <h3 className="text-white/40 text-[10px] font-black uppercase tracking-[0.2em]">
          Recent Activities
        </h3>
        <button className="p-2 hover:bg-white/5 rounded-full transition-colors">
          <Clock size={16} className="text-white/20" />
        </button>
      </div>

      <div className="space-y-12">
        {loading ? (
          <div className="py-10 text-center text-white/20 text-xs italic">Syncing platform events...</div>
        ) : activities.length === 0 ? (
          <div className="py-10 text-center text-white/20 text-xs italic">No recent activity detected.</div>
        ) : (
          <>
            {todayActivities.length > 0 && <ActivityGroup title="Today" items={todayActivities} />}
            {otherActivities.length > 0 && <ActivityGroup title="Earlier" items={otherActivities} />}
          </>
        )}
      </div>
    </div>
  );
};

export default ActivityPanel;

