import React from 'react';
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  BarChart, Bar, LineChart, Line, PieChart, Pie, Cell, Legend
} from 'recharts';
import { formatINR } from '../../../utils/currencyUtils';

const ChartCard = ({ title, type = 'area', data, dataKey = 'value', categoryKey = 'name', height = 300, color = '#3B82F6', isCurrency = false }) => {

  // Safe ID for SVG gradients
  const gradientId = React.useMemo(() => `gradient-${title.replace(/[^a-zA-Z0-9]/g, '-').toLowerCase()}`, [title]);

  // Premium Blue Shades
  const COLORS = ['#3B82F6', '#60A5FA', '#93C5FD', '#2563EB', '#1D4ED8', '#1E40AF', '#1E3A8A'];


  const CustomTooltip = ({ active, payload, label }) => {
    if (active && payload && payload.length) {
      const displayLabel = label || payload[0].name;

      return (
        <div className="bg-white/95 dark:bg-[#1E293B]/95 backdrop-blur-xl border border-gray-200/50 dark:border-white/10 p-3.5 rounded-2xl shadow-[0_10px_40px_-10px_rgba(0,0,0,0.1)] dark:shadow-2xl min-w-[160px]">
          {displayLabel && (
            <p className="text-[10px] font-black uppercase tracking-[0.15em] text-gray-400 dark:text-white/30 mb-2.5 border-b border-gray-100 dark:border-white/5 pb-2">
              {displayLabel}
            </p>
          )}
          <div className="space-y-2">
            {payload.map((item, index) => (
              <div key={index} className="flex items-center justify-between gap-4">
                <div className="flex items-center gap-2.5">
                  <div 
                    className="w-2 h-2 rounded-full shadow-[0_0_8px_rgba(0,0,0,0.1)]" 
                    style={{ backgroundColor: item.color || item.fill || color }}
                  ></div>
                  <span className="text-[11px] font-bold text-gray-600 dark:text-white/60 uppercase tracking-wide">
                    {item.name || 'Value'}
                  </span>
                </div>
                <p className="text-sm font-black text-gray-900 dark:text-white">
                  {isCurrency ? formatINR(item.value) : item.value?.toLocaleString()}
                </p>
              </div>
            ))}
          </div>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="bg-transparent border border-gray-100 dark:border-white/5 rounded-[32px] p-8 shadow-sm hover:border-accent/30 transition-all flex flex-col min-h-[400px] overflow-hidden">
      <div className="flex items-center justify-between mb-8">
        <h3 className="text-gray-400 dark:text-white/40 text-[10px] font-black uppercase tracking-[0.2em]">
          {title}
        </h3>
        <div className="flex gap-2">
          <div className="w-1.5 h-1.5 rounded-full bg-accent animate-pulse"></div>
        </div>
      </div>

      <div className="w-full flex-1 relative min-h-[350px]">
        {(!data || data.length === 0) ? (
          <div className="absolute inset-0 flex items-center justify-center text-gray-300 dark:text-white/20 text-xs font-medium">
            No data available for {title}
          </div>
        ) : (
          <ResponsiveContainer width="100%" height={300} debounce={50}>
            {type === 'line' ? (
              <LineChart data={data} margin={{ top: 20, right: 30, left: 10, bottom: 20 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="var(--color-border)" vertical={false} opacity={0.5} />
                <XAxis 
                  dataKey="name" 
                  stroke="var(--color-border)" 
                  fontSize={10} 
                  tick={{ fill: 'var(--color-text-muted)' }} 
                  axisLine={false} 
                  tickLine={false} 
                  dy={10} 
                />
                <YAxis 
                  stroke="var(--color-border)" 
                  fontSize={10} 
                  tick={{ fill: 'var(--color-text-muted)' }} 
                  axisLine={false} 
                  tickLine={false}
                  tickFormatter={(val) => isCurrency ? formatINR(val).replace('₹', '') : val}
                />
                <Tooltip content={<CustomTooltip />} isAnimationActive={false} cursor={{ stroke: 'var(--color-border)', strokeWidth: 1 }} />
                <Legend verticalAlign="top" align="right" wrapperStyle={{ fontSize: '10px', paddingBottom: '20px', color: 'var(--color-text-muted)' }} />
                {Array.isArray(dataKey) ? (
                  dataKey.map((line, idx) => (
                    <Line
                      key={line.key}
                      name={line.name}
                      type="monotone"
                      dataKey={line.key}
                      stroke={line.color}
                      strokeWidth={3}
                      dot={{ fill: line.color, r: 4 }}
                      activeDot={{ r: 6, stroke: '#fff', strokeWidth: 2 }}
                      isAnimationActive={false}
                    />
                  ))
                ) : (
                  <Line type="monotone" dataKey={dataKey} stroke={color} strokeWidth={3} dot={{ fill: color, r: 4 }} isAnimationActive={false} />
                )}
              </LineChart>
            ) : type === 'pie' ? (
              <PieChart>
                <Pie
                  data={data}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={85}
                  paddingAngle={5}
                  dataKey={dataKey}
                  nameKey={categoryKey || 'name'}
                  isAnimationActive={false}
                >
                  {data?.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip content={<CustomTooltip />} isAnimationActive={false} />
                <Legend verticalAlign="bottom" align="center" wrapperStyle={{ fontSize: '10px', color: 'var(--color-text-muted)' }} />
              </PieChart>
            ) : type === 'bar' ? (
              <BarChart data={data} margin={{ top: 20, right: 30, left: 10, bottom: 20 }}>
                <defs>
                   <linearGradient id={gradientId} x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor={color} stopOpacity={0.8} />
                    <stop offset="95%" stopColor={color} stopOpacity={0.3} />
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" stroke="var(--color-border)" vertical={false} opacity={0.5} />
                <XAxis 
                  dataKey={categoryKey || 'name'} 
                  stroke="var(--color-border)" 
                  fontSize={10} 
                  tick={{ fill: 'var(--color-text-muted)' }} 
                  axisLine={false} 
                  tickLine={false} 
                  dy={10} 
                />
                <YAxis 
                  stroke="var(--color-border)" 
                  fontSize={10} 
                  tick={{ fill: 'var(--color-text-muted)' }} 
                  axisLine={false} 
                  tickLine={false} 
                  tickFormatter={(val) => isCurrency ? formatINR(val).replace('₹', '') : val}
                />
                <Tooltip 
                  cursor={false}
                  content={<CustomTooltip />}
                  isAnimationActive={false}
                />
                <Bar 
                  dataKey={dataKey} 
                  fill={`url(#${gradientId})`} 
                  radius={[6, 6, 0, 0]} 
                  barSize={40}
                  isAnimationActive={false}
                />
              </BarChart>
            ) : (

              <AreaChart data={data} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
                <defs>
                  <linearGradient id={gradientId} x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor={color} stopOpacity={0.4} />
                    <stop offset="95%" stopColor={color} stopOpacity={0} />
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" stroke="var(--color-border)" vertical={false} opacity={0.5} />
                <XAxis 
                  dataKey="name" 
                  stroke="var(--color-border)" 
                  fontSize={10} 
                  tick={{ fill: 'var(--color-text-muted)' }} 
                />
                <YAxis 
                   stroke="var(--color-border)" 
                   fontSize={10}
                   tick={{ fill: 'var(--color-text-muted)' }}
                   tickFormatter={(val) => isCurrency ? formatINR(val).replace('₹', '') : val}
                />
                <Tooltip content={<CustomTooltip />} isAnimationActive={false} />
                <Area type="monotone" dataKey={Array.isArray(dataKey) ? dataKey[0].key : dataKey} stroke={color} strokeWidth={3} fillOpacity={1} fill={`url(#${gradientId})`} isAnimationActive={false} />
              </AreaChart>
            )}

          </ResponsiveContainer>
        )}
      </div>

    </div>
  );
};

export default ChartCard;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Plus, Edit2, Trash2, X, BarChart2,
  Eye, MousePointer, XCircle, ToggleLeft, ToggleRight, Tag
} from 'lucide-react';
import axios from 'axios';
import { toast } from 'react-hot-toast';

const API_URL = import.meta.env.VITE_API_URL || 'http://localhost:5001';

const OFFER_TYPES = [
  { value: 'limited_offer',   label: '🔥 Limited Offer' },
  { value: 'flash_sale',      label: '⚡ Flash Sale' },
  { value: 'seasonal_deal',   label: '🎉 Seasonal Deal' },
  { value: 'launch_offer',    label: '🚀 Launch Offer' },
  { value: 'platform_update', label: '📢 Platform Update' },
  { value: 'feature_release', label: '✨ Feature Release' },
];

const defaultForm = {
  title: '',
  message: '',
  type: 'limited_offer',
  start_time: '',
  end_time: '',
  is_active: true,
};

const toLocalInput = (iso) => {
  if (!iso) return '';
  const d = new Date(iso);
  const pad = (n) => String(n).padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`;
};

const timeLeft = (end) => {
  const diff = new Date(end) - Date.now();
  if (diff <= 0) return 'Expired';
  const h = Math.floor(diff / 3600000);
  const m = Math.floor((diff % 3600000) / 60000);
  if (h > 24) return `${Math.floor(h / 24)}d ${h % 24}h left`;
  return `${h}h ${m}m left`;
};

const OffersManagement = () => {
  const [offers, setOffers] = useState([]);
  const [analytics, setAnalytics] = useState({});
  const [isLoading, setIsLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editing, setEditing] = useState(null);
  const [form, setForm] = useState(defaultForm);
  const [showAnalytics, setShowAnalytics] = useState(false);

  const currentUser = JSON.parse(localStorage.getItem('user')) || {};
  const isSuperAdmin = (currentUser.role || '') === 'SUPER_ADMIN';

  const getHeaders = () => {
    const token = localStorage.getItem('token');
    return { Authorization: `Bearer ${token}` };
  };

  const fetchAll = async () => {
    try {
      setIsLoading(true);
      const [offRes, analyticsRes] = await Promise.all([
        axios.get(`${API_URL}/api/announcements/admin/all`, { headers: getHeaders() }),
        axios.get(`${API_URL}/api/announcements/admin/analytics`, { headers: getHeaders() }),
      ]);
      if (offRes.data.success) setOffers(offRes.data.data);
      if (analyticsRes.data.success) setAnalytics(analyticsRes.data.data);
    } catch {
      toast.error('Failed to load offers');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { fetchAll(); }, []);

  const openCreate = () => {
    if (!isSuperAdmin) return toast.error('Only Super Admins can create offers');
    setEditing(null);
    const now = new Date();
    const next7 = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);
    setForm({ ...defaultForm, start_time: toLocalInput(now.toISOString()), end_time: toLocalInput(next7.toISOString()) });
    setIsModalOpen(true);
  };

  const openEdit = (offer) => {
    if (!isSuperAdmin) return toast.error('Only Super Admins can edit offers');
    setEditing(offer);
    setForm({
      title: offer.title,
      message: offer.message,
      type: offer.type || 'limited_offer',
      start_time: toLocalInput(offer.start_time),
      end_time: toLocalInput(offer.end_time),
      is_active: offer.is_active,
    });
    setIsModalOpen(true);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!isSuperAdmin) return;
    if (!form.end_time) return toast.error('End time is required');
    const payload = {
      ...form,
      start_time: form.start_time ? new Date(form.start_time).toISOString() : new Date().toISOString(),
      end_time: new Date(form.end_time).toISOString(),
    };
    try {
      if (editing) {
        await axios.patch(`${API_URL}/api/announcements/admin/${editing.id}`, payload, { headers: getHeaders() });
        toast.success('Offer updated');
      } else {
        await axios.post(`${API_URL}/api/announcements/admin/create`, payload, { headers: getHeaders() });
        toast.success('Offer published');
      }
      setIsModalOpen(false);
      fetchAll();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to save offer');
    }
  };

  const handleDelete = async (id) => {
    if (!isSuperAdmin || !window.confirm('Delete this offer?')) return;
    try {
      await axios.delete(`${API_URL}/api/announcements/admin/${id}`, { headers: getHeaders() });
      toast.success('Offer deleted');
      fetchAll();
    } catch { toast.error('Failed to delete'); }
  };

  const handleToggleActive = async (offer) => {
    if (!isSuperAdmin) return toast.error('Only Super Admins can do this');
    try {
      await axios.patch(`${API_URL}/api/announcements/admin/${offer.id}`, { is_active: !offer.is_active }, { headers: getHeaders() });
      toast.success(offer.is_active ? 'Offer hidden' : 'Offer is now live');
      fetchAll();
    } catch { toast.error('Failed to toggle'); }
  };

  const getOfferLabel = (val) => OFFER_TYPES.find(t => t.value === val)?.label || val;

