              <div className="flex items-end gap-1.5">
                <p className="text-2xl font-black text-white">₹{plan.offer_price}</p>
                {plan.discount_percentage > 0 && (
                  <span className="text-[10px] font-bold text-emerald-400 mb-0.5">
