                  <span className="text-xs text-white/60 leading-tight">{feature}</span>
                </div>
              ))}
            </div>
          </div>
        ))}
        {plans.length === 0 && (
          <div className="col-span-full py-16 text-center text-white/30 border border-white/5 border-dashed rounded-2xl text-sm">
