                      <option value="monthly">Monthly</option>
                      <option value="yearly">Yearly</option>
                    </select>
                  </div>
                  <div className="flex flex-col justify-end">
                    <label className="flex items-center gap-2.5 bg-white/5 py-2.5 px-3 rounded-xl border border-white/10 cursor-pointer hover:bg-white/8 transition-colors">
                      <input
                        type="checkbox"
                        className="w-3.5 h-3.5 rounded border-white/20 text-accent"
                        checked={formData.is_popular}
                        onChange={(e) => setFormData({ ...formData, is_popular: e.target.checked })}
                      />
                      <span className="text-xs font-semibold text-white/60">Mark as Popular</span>
                    </label>
                  </div>
                </div>

                <div>
                  <label className="text-[10px] font-black uppercase tracking-widest text-white/40 pl-1 block mb-1.5">Features (One per line)</label>
                  <textarea
                    rows={4}
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-3 py-2.5 text-white text-sm focus:border-accent/50 outline-none transition-all placeholder:text-white/20 resize-none"
                    placeholder={"80 Connects per month\nVerified Pro Badge\nPriority Support"}
                    value={formData.features}
                    onChange={(e) => setFormData({ ...formData, features: e.target.value })}
                  />
                </div>

                <div className="pt-2 flex justify-end gap-2">
                  <button type="button" onClick={() => setIsModalOpen(false)} className="px-5 py-2 rounded-xl text-xs font-bold text-white/50 hover:text-white hover:bg-white/5 transition-colors">
                    Cancel
                  </button>
                  <button type="submit" className="px-5 py-2 rounded-xl text-xs font-bold bg-accent text-primary hover:bg-white hover:text-primary active:scale-95 transition-all shadow-lg">
                    {editingPlan ? 'Save Changes' : 'Create Plan'}
