    const handleMouseEnter = (e, label) => {
        if (isSidebarOpen) return;
        const rect = e.currentTarget.getBoundingClientRect();
        // Centers tooltip vertically with the item, and places it to the right
        setTooltip({
            visible: true,
            text: label,
            top: rect.top + (rect.height / 2),
            left: rect.right + 10
        });
