                            to="/admin/profile" 
                            className="px-5 py-2 bg-rose-500/20 hover:bg-rose-500/30 text-rose-100 text-[11px] font-black uppercase tracking-widest rounded-full transition-all border border-rose-500/20 hover:border-rose-500/40"
                        >
                            Change Password
                        </NavLink>
                    </motion.div>
                )}

                {/* Page Content */}
                <main className="flex-1 overflow-auto p-6 bg-primary custom-scrollbar">
                    <Outlet />
                </main>
            </div>
            <HelpSupportModal isOpen={isHelpOpen} onClose={() => setIsHelpOpen(false)} />

            {/* Global Tooltip Portal Component */}
            {tooltip.visible && !isSidebarOpen && (
                <div 
                    className={`fixed z-[9999] px-3 py-1.5 backdrop-blur-xl border rounded-xl pointer-events-none text-[11px] font-black uppercase tracking-[0.2em] whitespace-nowrap shadow-2xl transition-opacity duration-150 ${
                        isDark 
                            ? 'bg-[#0B1121]/90 border-white/10 text-white/90' 
                            : 'bg-white/95 border-slate-200/60 text-slate-800 drop-shadow-sm'
                    }`}
                    style={{ 
                        top: tooltip.top, 
                        left: tooltip.left,
                        transform: 'translateY(-50%)' // Perfect vertical centering 
                    }}
                >
                    {tooltip.text}
                </div>
            )}
        </div>
    );
};

