    const [isAddModalOpen, setIsAddModalOpen] = useState(false);
    const [newAdmin, setNewAdmin] = useState({ email: '', role: 'ADMIN', password: '' });
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedAdmin, setSelectedAdmin] = useState(null);
    const [isViewModalOpen, setIsViewModalOpen] = useState(false);

    const handleViewAdmin = (admin) => {
        setSelectedAdmin(admin);
        setIsViewModalOpen(true);
    };

    const loadAdmins = useCallback(async () => {
        setLoading(true);
        try {
            const result = await adminService.fetchAdmins();
            if (result.success) {
                setAdmins(result.data);
            }
        } catch (error) {
            console.error('Error loading admins:', error);
            toast.error('Failed to load admins');
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        loadAdmins();
    }, [loadAdmins]);

    const handleAddAdmin = async (e) => {
        e.preventDefault();
        try {
            const result = await adminService.addAdmin(newAdmin);
            if (result.success) {
                toast.success(result.message || 'Admin added successfully');
                setIsAddModalOpen(false);
                setNewAdmin({ email: '', role: 'ADMIN', password: '' });
                loadAdmins();
            }
        } catch (error) {
            toast.error(error.response?.data?.message || 'Failed to add admin');
        }
    };

    const handleRemoveAdmin = async (id) => {
        if (!window.confirm('Are you sure you want to remove this admin?')) return;
        try {
            const result = await adminService.removeAdmin(id);
            if (result.success) {
                toast.success('Admin removed successfully');
                loadAdmins();
            }
        } catch (error) {
            toast.error(error.response?.data?.message || 'Failed to remove admin');
        }
    };

    const handleRoleChange = async (id, newRole) => {
        try {
            const result = await adminService.updateAdminRole(id, newRole);
            if (result.success) {
                toast.success(`Role updated to ${newRole}`);
                loadAdmins();
            }
        } catch (error) {
            toast.error(error.response?.data?.message || 'Failed to update role');
        }
    };



    const filteredAdmins = admins.filter(admin => {
        const name = (admin.name || '').toLowerCase();
        const email = (admin.email || '').toLowerCase();
        const search = searchTerm.toLowerCase();
        return name.includes(search) || email.includes(search);
    });

    return (
        <div className="space-y-8 animate-in fade-in duration-500">
            {/* Header */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <motion.div
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                >
                    <h1 className="text-3xl font-bold text-white mb-2 flex items-center gap-3">
                        <img src="/Icons/icons8-critical-thinking-80.png" alt="Admin Management" className="w-8 h-8 object-contain" />
                        Admin Management
                    </h1>
                    <p className="text-white/50 text-sm">Add or remove system administrators and manage their permissions.</p>
                </motion.div>

                <div className="flex items-center gap-4 flex-1 justify-end">
                    <div className="relative w-64">
                        <Shield className="absolute left-3 top-1/2 -translate-y-1/2 text-white/40" size={18} />
                        <input
                            type="text"
                            placeholder="Search admins..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full bg-transparent border border-white/10 rounded-xl pl-10 pr-4 py-2 text-white text-sm focus:outline-none focus:border-accent transition-all"
                        />
                    </div>
                    <button 
                        onClick={() => setIsAddModalOpen(true)}
                        className="flex items-center gap-2 bg-accent hover:bg-accent/90 text-white px-6 py-2.5 rounded-xl transition-all font-bold shadow-lg shadow-accent/20 shrink-0"
                    >
                        <UserPlus size={18} />
                        Add New Admin
                    </button>
                </div>
            </div>

            {/* Admin Table */}
            <div className="bg-transparent border border-white/10 rounded-2xl overflow-hidden shadow-xl shadow-black/40">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-white/5 text-white/40 text-xs uppercase tracking-widest font-bold border-b border-white/10">
                                <th className="px-6 py-5">Administrator</th>
                                <th className="px-6 py-5">Role</th>
                                <th className="px-6 py-5">Joined At</th>
                                <th className="px-6 py-5 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-white/5">
                            {loading ? (
                                <tr><td colSpan="4" className="px-6 py-12 text-center text-white/30">Loading administrators...</td></tr>
                            ) : filteredAdmins.length === 0 ? (
                                <tr><td colSpan="4" className="px-6 py-12 text-center text-white/30">No administrators found matching your search</td></tr>
                            ) : filteredAdmins.map((admin) => (
                                <tr key={admin.id} className="hover:bg-white/[0.02] transition-colors group">
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <div className="flex items-center gap-4">
                                            <div className="w-10 h-10 rounded-full bg-accent/20 flex items-center justify-center text-accent font-bold border border-accent/20 shadow-inner">
                                                {admin.photo_url ? (
                                                    <img src={admin.photo_url} alt="" className="w-full h-full object-cover rounded-full" />
                                                ) : (
                                                    admin.email.charAt(0).toUpperCase()
                                                )}
                                            </div>
                                            <div>
                                                <div className="text-white font-medium">{admin.name || admin.email.split('@')[0]}</div>
                                                <div className="text-white/40 text-xs">{admin.email}</div>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <select
                                            value={admin.role}
                                            onChange={(e) => handleRoleChange(admin.id, e.target.value)}
                                            className={`text-xs font-bold px-3 py-1.5 rounded-full border transition-all appearance-none cursor-pointer focus:outline-none ${
                                                admin.role === 'SUPER_ADMIN' 
                                                ? 'bg-accent/10 text-accent border-accent/20 hover:bg-accent/20' 
                                                : 'bg-white/5 text-white border-white/10 hover:bg-white/10'
                                            }`}
                                        >
                                            <option value="ADMIN" className="bg-secondary">ADMIN</option>
                                            <option value="SUPER_ADMIN" className="bg-secondary">SUPER ADMIN</option>
                                        </select>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-white/50 text-sm">
                                        {new Date(admin.created_at).toLocaleDateString()}
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-right">
                                        <div className="flex justify-end gap-2">
                                            <button 
                                                onClick={() => handleViewAdmin(admin)}
                                                className="p-2 text-white/40 hover:text-accent hover:bg-accent/10 rounded-lg transition-all opacity-0 group-hover:opacity-100"
                                                title="View Admin Details"
                                            >
                                                <Eye size={18} />
                                            </button>
                                            <button 
                                                onClick={() => handleRemoveAdmin(admin.id)}
                                                className="p-2 text-white/40 hover:text-red-400 hover:bg-red-400/10 rounded-lg transition-all opacity-0 group-hover:opacity-100"
                                                title="Remove Admin"
                                            >
                                                <Trash2 size={18} />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Add Modal */}
            {isAddModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
                    <motion.div 
                        initial={{ opacity: 0, scale: 0.95 }}
                        animate={{ opacity: 1, scale: 1 }}
                        className="bg-secondary border border-border rounded-2xl p-8 max-w-md w-full shadow-2xl"
                    >
                        <h2 className="text-2xl font-bold text-white mb-2 flex items-center gap-3">
                            <UserPlus className="text-accent" />
                            Add Admin
                        </h2>
                        <p className="text-white/50 text-sm mb-6">Enter details to grant or update administrative access. If the user doesn't exist, they will be created.</p>

                        <form onSubmit={handleAddAdmin} className="space-y-4">
                            <div>
                                <label className="block text-xs font-bold text-white/40 uppercase tracking-widest mb-2">Email Address</label>
                                <div className="relative">
                                    <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-white/40" size={18} />
                                    <input
                                        type="email"
                                        required
                                        placeholder="admin@email.com"
                                        value={newAdmin.email}
                                        onChange={(e) => setNewAdmin({ ...newAdmin, email: e.target.value })}
                                        className="w-full pl-10 pr-4 py-3 bg-white/5 border border-white/10 rounded-xl text-white focus:outline-none focus:border-accent transition-all"
                                    />
                                </div>
                            </div>

                            <div>
                                <label className="block text-xs font-bold text-white/40 uppercase tracking-widest mb-2">Role</label>
                                <div className="relative">
                                    <Shield className="absolute left-3 top-1/2 -translate-y-1/2 text-white/40" size={18} />
                                    <select
                                        value={newAdmin.role}
                                        onChange={(e) => setNewAdmin({ ...newAdmin, role: e.target.value })}
                                        className="w-full pl-10 pr-4 py-3 bg-white/5 border border-white/10 rounded-xl text-white focus:outline-none focus:border-accent appearance-none transition-all"
                                    >
                                        <option value="ADMIN" className="bg-secondary">Standard Admin</option>
                                        <option value="SUPER_ADMIN" className="bg-secondary">Super Admin</option>
                                    </select>
                                </div>
                            </div>

                            <div>
                                <label className="block text-xs font-bold text-white/40 uppercase tracking-widest mb-2">Initial Password / Credentials</label>
                                <div className="relative">
                                    <Key className="absolute left-3 top-4 text-white/40" size={18} />
                                    <textarea
                                        required
                                        placeholder="Enter initial password or credentials..."
                                        value={newAdmin.password}
                                        onChange={(e) => setNewAdmin({ ...newAdmin, password: e.target.value })}
                                        rows={3}
                                        className="w-full pl-10 pr-4 py-3 bg-white/5 border border-white/10 rounded-xl text-white focus:outline-none focus:border-accent transition-all resize-none"
                                    />
                                </div>
                            </div>

                            <div className="flex gap-3 pt-4">
                                <button
                                    type="button"
                                    onClick={() => setIsAddModalOpen(false)}
                                    className="flex-1 px-4 py-3 bg-white/5 hover:bg-white/10 text-white rounded-xl transition-all font-bold"
                                >
                                    Cancel
                                </button>
                                <button
                                    type="submit"
                                    className="flex-1 px-4 py-3 bg-accent hover:bg-accent/90 text-white rounded-xl transition-all font-bold shadow-lg shadow-accent/20"
                                >
                                    Add Admin
                                </button>
                            </div>
                        </form>
                    </motion.div>
                </div>
            )}

            {/* View Modal */}
            {isViewModalOpen && selectedAdmin && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
                    <motion.div 
                        initial={{ opacity: 0, scale: 0.95 }}
                        animate={{ opacity: 1, scale: 1 }}
                        className="bg-secondary border border-white/10 rounded-2xl p-8 max-w-md w-full shadow-2xl relative"
                    >
                        <button 
                            onClick={() => setIsViewModalOpen(false)}
                            className="absolute top-4 right-4 text-white/40 hover:text-white transition-colors"
                        >
                            <X size={24} />
                        </button>

                        <div className="flex flex-col items-center mb-6">
                            <div className="w-20 h-20 rounded-full bg-accent/20 flex items-center justify-center text-accent text-2xl font-bold border-2 border-accent/20 shadow-inner mb-4">
                                {selectedAdmin.photo_url ? (
                                    <img src={selectedAdmin.photo_url} alt="" className="w-full h-full object-cover rounded-full" />
                                ) : (
                                    selectedAdmin.email.charAt(0).toUpperCase()
                                )}
                            </div>
                            <h2 className="text-2xl font-bold text-white text-center">{selectedAdmin.name || selectedAdmin.email.split('@')[0]}</h2>
                            <p className="text-white/50 text-sm mt-1">{selectedAdmin.role.replace('_', ' ')}</p>
                        </div>

                        <div className="space-y-4 bg-white/5 border border-white/10 rounded-xl p-5 mb-6">
                            <div>
                                <span className="block text-[10px] uppercase font-bold text-white/40 tracking-widest mb-1">Email Address</span>
                                <span className="text-white text-sm">{selectedAdmin.email}</span>
                            </div>
                            <div>
                                <span className="block text-[10px] uppercase font-bold text-white/40 tracking-widest mb-1">Joined Date</span>
                                <span className="text-white text-sm">{new Date(selectedAdmin.created_at).toLocaleDateString(undefined, { year: 'numeric', month: 'long', day: 'numeric' })}</span>
                            </div>
                            <div>
                                <span className="block text-[10px] uppercase font-bold text-white/40 tracking-widest mb-1">Status</span>
                                <div className="flex items-center gap-2 mt-1">
                                    <div className="w-2 h-2 rounded-full bg-emerald-400"></div>
                                    <span className="text-emerald-400 text-xs font-bold uppercase">Active</span>
                                </div>
                            </div>
                        </div>

                        <button
                            onClick={() => setIsViewModalOpen(false)}
                            className="w-full px-4 py-3 bg-white/5 hover:bg-white/10 text-white rounded-xl transition-all font-bold"
                        >
                            Close Details
                        </button>
                    </motion.div>
                </div>
            )}
        </div>
    );
};

export default AdminManagementPage;

import { useState, useEffect } from 'react';
import { Megaphone, Send, Users, UserCheck, Briefcase, Info, X, History, Clock } from 'lucide-react';
import { createAnnouncement, fetchAnnouncements } from '../../services/adminService';
import toast from 'react-hot-toast';
import { motion, AnimatePresence } from 'framer-motion';

const AnnouncementsPage = () => {
    const [announcement, setAnnouncement] = useState({
        title: '',
        message: '',
        target_role: 'ALL',
        type: 'PLATFORM_UPDATE'
    });
    const [loading, setLoading] = useState(false);
    const [showHistory, setShowHistory] = useState(false);
    const [history, setHistory] = useState([]);
    const [loadingHistory, setLoadingHistory] = useState(false);

    useEffect(() => {
        // Shared loading of history if needed
    }, []);

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            setLoading(true);
            await createAnnouncement(announcement);
            toast.success('Announcement published successfully!');
            setAnnouncement({ 
                title: '', 
                message: '', 
                target_role: 'ALL', 
                type: 'PLATFORM_UPDATE' 
            });
            if (showHistory) loadHistory();
        } catch (error) {
            toast.error(error.response?.data?.message || 'Failed to publish announcement');
        } finally {
            setLoading(false);
        }
    };

    const loadHistory = async () => {
        setLoadingHistory(true);
        try {
            const result = await fetchAnnouncements();
            if (result.success) {
                setHistory(result.data);
            }
        } catch (error) {
            toast.error('Failed to load history');
        } finally {
            setLoadingHistory(false);
        }
    };

    const toggleHistory = () => {
        if (!showHistory && history.length === 0) {
            loadHistory();
        }
        setShowHistory(!showHistory);
    };

    const formatDate = (dateString) => {
        return new Date(dateString).toLocaleDateString(undefined, {
            year: 'numeric',
            month: 'short',
            day: 'numeric'
        });
    };

    return (
        <div className="space-y-8 pb-10">
            {/* Header Section */}
            <div className="flex flex-col md:flex-row items-center justify-between gap-6">
                <div>
                    <div className="flex items-center gap-3 mb-2">
                        <Megaphone size={18} className="text-[#38BDF8]" />
                        <h1 className="text-xl font-bold text-white tracking-tight">Platform Announcements</h1>
                    </div>
                    <p className="text-white/40 text-xs">
                        Broadcast general updates, news, and platform changes to users
                    </p>
                </div>

                <button
                    onClick={toggleHistory}
                    className="flex items-center gap-2 bg-white/5 hover:bg-white/10 text-white px-5 py-2.5 rounded-xl border border-white/10 transition-all text-xs font-semibold"
                >
                    <History size={14} />
                    View History
                </button>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-[1fr_350px] gap-8">
                {/* Form Section */}
                <div className="bg-[#111827] border border-white/5 rounded-3xl p-8 shadow-xl">
                    <form onSubmit={handleSubmit} className="space-y-6">
                        <div className="space-y-3">
                            <label className="text-white/40 text-[9px] font-bold uppercase tracking-widest pl-1">Audience</label>
                            <div className="grid grid-cols-3 gap-3">
                                {[
                                    { id: 'ALL', label: 'Everyone', icon: <Users size={14} /> },
                                    { id: 'FREELANCER', label: 'Freelancers', icon: <UserCheck size={14} /> },
                                    { id: 'CLIENT', label: 'Clients', icon: <Briefcase size={14} /> }
                                ].map((role) => (
                                    <button
                                        key={role.id}
                                        type="button"
                                        onClick={() => setAnnouncement({ ...announcement, target_role: role.id })}
                                        className={`flex items-center justify-center gap-2 py-3 rounded-xl border transition-all text-xs font-medium ${announcement.target_role === role.id
                                            ? 'bg-[#38BDF8] border-[#38BDF8] text-white shadow-lg shadow-sky-600/20'
                                            : 'bg-white/[0.02] border-white/5 text-white/40 hover:border-white/10'
                                            }`}
                                    >
                                        {role.icon}
                                        {role.label}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="space-y-3">
                            <label className="text-white/40 text-[10px] font-bold uppercase tracking-widest pl-1">Headline</label>
                            <input
                                required
                                type="text"
                                value={announcement.title}
                                onChange={(e) => setAnnouncement({ ...announcement, title: e.target.value })}
                                placeholder="What's new on the platform?"
                                className="w-full bg-white/[0.03] border border-white/10 rounded-xl px-4 py-3 text-white text-sm focus:outline-none focus:border-blue-500/50 transition-all placeholder:text-white/10"
                            />
                        </div>

                        <div className="space-y-3">
                            <label className="text-white/40 text-[10px] font-bold uppercase tracking-widest pl-1">Content</label>
                            <textarea
                                required
                                rows="6"
                                value={announcement.message}
                                onChange={(e) => setAnnouncement({ ...announcement, message: e.target.value })}
                                placeholder="Describe the update in detail..."
                                className="w-full bg-white/[0.03] border border-white/10 rounded-xl px-4 py-4 text-white text-sm focus:outline-none focus:border-blue-500/50 transition-all resize-none placeholder:text-white/10 leading-relaxed"
                            ></textarea>
                        </div>

                        <button
                            type="submit"
                            disabled={loading}
                            className="w-full py-3 bg-[#38BDF8] hover:bg-[#0EA5E9] text-white font-bold rounded-xl transition-all flex items-center justify-center gap-2 text-xs disabled:opacity-50 shadow-lg shadow-sky-500/10"
                        >
                            {loading ? (
                                <div className="w-4 h-4 border-2 border-white/20 border-t-white rounded-full animate-spin"></div>
                            ) : (
                                <>
                                    <Send size={14} />
                                    Publish Announcement
                                </>
                            )}
                        </button>
                    </form>
                </div>

                {/* Info Sidebar */}
                <div className="space-y-6">
                    <div className="bg-transparent border border-[#38BDF8]/10 rounded-2xl p-6 flex gap-4 items-start">
                        <Info className="text-[#38BDF8] shrink-0" size={16} />
                        <div className="space-y-1">
                            <h4 className="text-[#38BDF8] font-bold text-[10px] uppercase tracking-widest">Platform Updates</h4>
                            <p className="text-white/30 text-[9px] leading-relaxed">
                                Use this section for non-promotional news, maintenance notices, and general feature releases.
                            </p>
                        </div>
                    </div>
                </div>
            </div>

            {/* History Modal */}
            <AnimatePresence>
                {showHistory && (
                    <div className="fixed inset-0 z-[100] flex items-center justify-end p-4 bg-black/60 backdrop-blur-sm">
                        <motion.div
                            initial={{ x: '100%' }}
                            animate={{ x: 0 }}
                            exit={{ x: '100%' }}
                            className="w-full max-w-xl h-full bg-[#0b0f1a] border-l border-white/5 p-8 overflow-y-auto"
                        >
                            <div className="flex items-center justify-between mb-8">
                                <h2 className="text-xl font-bold text-white">Announcement History</h2>
                                <button onClick={() => setShowHistory(false)} className="p-2 hover:bg-white/5 rounded-lg">
                                    <X size={20} className="text-white/40" />
                                </button>
                            </div>

                            <div className="space-y-4">
                                {loadingHistory ? (
                                    <div className="py-20 text-center">
                                        <div className="w-8 h-8 border-2 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
                                        <span className="text-white/20 text-xs">Fetching records...</span>
                                    </div>
                                ) : history.length === 0 ? (
                                    <div className="text-center py-20 border border-white/5 rounded-2xl">
                                        <p className="text-white/20 text-sm">No announcements yet.</p>
                                    </div>
                                ) : (
                                    history.map((record) => (
                                        <div key={record.id} className="bg-white/5 border border-white/5 rounded-2xl p-5 space-y-3">
                                            <div className="flex items-center justify-between">
                                                <span className="px-2 py-0.5 rounded-full text-[8px] font-bold bg-blue-500/10 text-blue-400 uppercase tracking-widest">
                                                    {record.target_role}
                                                </span>
                                                <span className="text-white/20 text-[9px] flex items-center gap-1">
                                                    <Clock size={10} />
                                                    {formatDate(record.created_at)}
                                                </span>
                                            </div>
                                            <h3 className="text-white font-bold text-sm">{record.title}</h3>
                                            <p className="text-white/40 text-xs leading-relaxed line-clamp-3">{record.message}</p>
                                        </div>
                                    ))
                                )}
                            </div>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>
        </div>
    );
};

export default AnnouncementsPage;

import React, { useState, useEffect } from 'react';
import { Search, Eye, XCircle, AlertTriangle, X, IndianRupee, Calendar, Clock, User, Mail, Briefcase, FileText } from 'lucide-react';
import { formatINR } from '../../utils/currencyUtils';
import Button from '../../components/ui/Button';
import * as adminService from '../../services/adminService';
import { toast } from 'react-hot-toast';

const ContractsPage = () => {
    const [contracts, setContracts] = useState([]);
    const [isLoading, setIsLoading] = useState(true);
    const [statusFilter, setStatusFilter] = useState('');
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedContract, setSelectedContract] = useState(null);
    const [isCancelling, setIsCancelling] = useState(false);
    const [showRequirements, setShowRequirements] = useState(false);

    useEffect(() => {
        if (!selectedContract) {
            setShowRequirements(false);
        }
    }, [selectedContract]);

    useEffect(() => {
        fetchContracts();
    }, [statusFilter]);

    const fetchContracts = async () => {
        setIsLoading(true);
        try {
            const result = await adminService.fetchContracts({ status: statusFilter });
            if (result.success) {
                setContracts(result.data);
            }
        } catch (err) {
            console.error('Failed to fetch contracts', err);
            toast.error('Failed to load contracts');
        } finally {
            setIsLoading(false);
        }
    };

    const handleCancel = async (contractId) => {
        const reason = window.prompt('Please enter a reason for cancellation:');
        if (reason === null) return;

        setIsCancelling(true);
        try {
            const result = await adminService.cancelContract(contractId, reason);
            if (result.success) {
                toast.success('Contract cancelled successfully');
                fetchContracts();
            }
        } catch (err) {
            console.error('Failed to cancel contract', err);
            toast.error('Failed to cancel contract');
        } finally {
            setIsCancelling(false);
        }
    };

    const filteredContracts = contracts.filter(c =>
        (c.job?.title || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
        (c.client?.email || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
        (c.freelancer?.email || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
