import { useState, useEffect } from 'react';
import { UserSearch, AlertTriangle, ShieldCheck, ShieldAlert, Clock, Mail } from 'lucide-react';
import { fetchSuspiciousUsers, toggleUserStatus } from '../../services/adminService';
import toast from 'react-hot-toast';

const FraudPage = () => {
    const [suspiciousUsers, setSuspiciousUsers] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');

    useEffect(() => {
        loadSuspicious();
    }, []);

    const loadSuspicious = async () => {
        try {
            setLoading(true);
            const response = await fetchSuspiciousUsers();
            setSuspiciousUsers(response.data);
        } catch (error) {
            toast.error('Failed to load fraud data');
        } finally {
            setLoading(false);
        }
    };

    const handleAction = async (userId, action) => {
        try {
            // action: SUSPEND or IGNORE
            if (action === 'SUSPEND') {
                await toggleUserStatus(userId, true);
                toast.success('User suspended successfully');
            } else {
                toast.success('User marked as safe');
            }
            loadSuspicious();
        } catch (error) {
            toast.error('Action failed');
        }
    };



    const filteredUsers = suspiciousUsers.filter(user => {
        const name = (user.profiles?.[0]?.name || '').toLowerCase();
        const email = (user.email || '').toLowerCase();
        const search = searchTerm.toLowerCase();
        return name.includes(search) || email.includes(search);
    });

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-white flex items-center gap-2">
                        <img src="/Icons/icons8-fraud-80.png" alt="Fraud" className="w-8 h-8 object-contain" />
                        Fraud & Suspicious Activity
                    </h1>
                    <p className="text-white/60 text-sm mt-1">Monitor potentially fraudulent behavior and multiple account attempts</p>
                </div>
                <div className="flex items-center gap-4 w-full sm:w-auto">
                    <div className="relative flex-1 sm:w-64">
                        <UserSearch className="absolute left-3 top-1/2 -translate-y-1/2 text-white/40" size={18} />
                        <input
                            type="text"
                            placeholder="Search by name or email..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full bg-transparent border border-white/10 rounded-xl pl-10 pr-4 py-2 text-white text-sm focus:outline-none focus:border-red-500/50 transition-all"
                        />
                    </div>
                    <button onClick={loadSuspicious} className="px-4 py-2 bg-white/5 border border-white/10 rounded-xl text-white/60 hover:text-white transition flex items-center gap-2 text-sm font-medium shrink-0">
                        <Clock size={16} /> Refresh Feed
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-1 gap-4">
                {loading ? (
                    <div className="py-20 text-center text-white/40">Analyzing platform activity...</div>
                ) : filteredUsers.length === 0 ? (
                    <div className="bg-transparent border border-white/10 rounded-2xl p-12 text-center space-y-4">
                        <div className="w-16 h-16 bg-blue-500/10 text-blue-500 rounded-full flex items-center justify-center mx-auto">
                            <ShieldCheck size={32} />
                        </div>
                        <h3 className="text-xl font-bold text-white">No matches found</h3>
                        <p className="text-white/60 max-w-sm mx-auto">None of the flagged users match your search query.</p>
                    </div>
                ) : filteredUsers.map((user) => (
                    <div key={user.id} className="bg-transparent border border-red-500/20 rounded-2xl p-6 flex flex-col md:flex-row md:items-center justify-between gap-6 hover:border-red-500/40 transition">
                        <div className="flex gap-4">
                            <div className="w-12 h-12 bg-red-500/10 text-red-500 rounded-2xl flex items-center justify-center shrink-0">
                                <AlertTriangle size={24} />
                            </div>
                            <div className="space-y-1">
                                <div className="flex items-center gap-2">
                                    <h3 className="text-lg font-bold text-white">{user.profiles?.[0]?.name || 'Anonymous User'}</h3>
                                    <span className="px-2 py-0.5 bg-red-500 text-white text-[10px] font-bold rounded-full uppercase tracking-widest">High Risk</span>
                                </div>
                                <p className="text-white/40 text-sm flex items-center gap-2"><Mail size={14} /> {user.email}</p>
                                <div className="pt-2 flex flex-wrap gap-2">
                                    <span className="px-2 py-1 bg-white/5 rounded text-[10px] text-white/60 border border-white/10">Frequent Cancellations</span>
                                    <span className="px-2 py-1 bg-white/5 rounded text-[10px] text-white/60 border border-white/10">Recent Large Refund</span>
                                </div>
                            </div>
                        </div>

                        <div className="flex gap-3 shrink-0">
                            <button
                                onClick={() => handleAction(user.id, 'IGNORE')}
                                className="px-4 py-2 bg-white/5 hover:bg-white/10 text-white/60 hover:text-white rounded-xl transition text-sm font-bold"
                            >
                                Mark as Safe
                            </button>
                            <button
                                onClick={() => handleAction(user.id, 'SUSPEND')}
                                className="px-6 py-2 bg-red-600 text-white hover:bg-red-700 rounded-xl transition text-sm font-bold flex items-center gap-2 shadow-lg shadow-red-600/20"
                            >
                                <ShieldAlert size={18} /> Suspend Account
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default FraudPage;

import React, { useState, useEffect } from 'react';
import { Search, Eye, Trash2, CheckSquare, XCircle, X, Briefcase, IndianRupee, User, Mail, Calendar, Clock } from 'lucide-react';
import { formatINR } from '../../utils/currencyUtils';
import Button from '../../components/ui/Button';
import * as adminService from '../../services/adminService';
import { toast } from 'react-hot-toast';

const JobsPage = () => {
    const [jobs, setJobs] = useState([]);
    const [isLoading, setIsLoading] = useState(true);
    const [statusFilter, setStatusFilter] = useState('');
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedJob, setSelectedJob] = useState(null);

    useEffect(() => {
        fetchJobs();
    }, [statusFilter]);

    const fetchJobs = async () => {
        setIsLoading(true);
        try {
            const result = await adminService.fetchJobs({ status: statusFilter });
            if (result.success) {
                setJobs(result.data);
            }
        } catch (err) {
            console.error('Failed to fetch jobs', err);
            toast.error('Failed to load jobs');
        } finally {
            setIsLoading(false);
        }
    };

    const handleApprove = async (jobId) => {
        try {
            const result = await adminService.approveJob(jobId);
            if (result.success) {
                toast.success('Job approved successfully');
                fetchJobs();
            }
        } catch (err) {
            toast.error('Approval failed');
        }
    };

    const handleReject = async (jobId) => {
        const reason = window.prompt('Please enter a reason for rejection:');
        if (reason === null) return;

        try {
            const result = await adminService.rejectJob(jobId, reason);
            if (result.success) {
                toast.success('Job rejected successfully');
                fetchJobs();
            }
        } catch (err) {
            toast.error('Rejection failed');
        }
    };

    const handleDelete = async (jobId) => {
        if (!confirm('Are you sure you want to permanently delete this job?')) return;

        try {
            const result = await adminService.deleteJob(jobId);
            if (result.success) {
                toast.success('Job deleted successfully');
                setJobs(jobs.filter(j => j.id !== jobId));
            }
        } catch (err) {
            toast.error('Deletion failed');
        }
    };

    const filteredJobs = jobs.filter(j =>
        (j.title || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
        (j.client?.email || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
        (j.client?.name || '').toLowerCase().includes(searchTerm.toLowerCase())
    );

    const Modal = ({ isOpen, onClose, title, children }) => {
        if (!isOpen) return null;
        return (
            <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6 bg-black/60 backdrop-blur-sm transition-all animate-in fade-in duration-200">
                <div className="bg-primary border border-white/10 w-full max-w-2xl max-h-[90vh] overflow-hidden rounded-3xl shadow-2xl flex flex-col">
                    <div className="px-6 py-4 border-b border-white/10 flex items-center justify-between bg-white/[0.02]">
