import { useState, useEffect } from 'react';
import { Search, Info, CheckCircle, XCircle } from 'lucide-react';
import * as adminService from '../../services/adminService';
import { toast } from 'react-hot-toast';

const ModerationPage = () => {
    const [reports, setReports] = useState([]);
    const [isLoading, setIsLoading] = useState(true);
    const [statusFilter, setStatusFilter] = useState('');
    const [searchTerm, setSearchTerm] = useState('');

    useEffect(() => {
        fetchReports();
    }, [statusFilter]);

    const fetchReports = async () => {
        setIsLoading(true);
        try {
            const result = await adminService.fetchModerationReports({ status: statusFilter });
            if (result.success) {
                setReports(result.data);
            }
        } catch (err) {
            console.error('Failed to fetch reports', err);
            toast.error('Failed to load reports');
        } finally {
            setIsLoading(false);
        }
    };

    const handleResolve = async (report, newStatus) => {
        let confirmationMessage = `Set report to ${newStatus}?`;

        if (newStatus === 'ACTION_TAKEN') {
            if (report.item_type === 'PROFILE') {
                confirmationMessage = `WARNING: Taking action on a PROFILE report will PERMANENTLY BAN the user ${report.reported?.email || ''}. Proceed?`;
            } else if (report.item_type === 'JOB') {
                confirmationMessage = `Taking action on a JOB report will PERMANENTLY DELETE the job. Proceed?`;
            } else if (report.item_type === 'PROPOSAL') {
                confirmationMessage = `Taking action on a PROPOSAL report will PERMANENTLY DELETE the proposal. Proceed?`;
            }
        }

        if (!window.confirm(confirmationMessage)) return;

        const notes = prompt(`Admin notes for setting report to ${newStatus}:`, report.admin_notes || '');
        if (notes === null) return;

        try {
            const result = await adminService.resolveModerationReport(report.id, { status: newStatus, admin_notes: notes });
            if (result.success) {
                toast.success(result.message || 'Report updated successfully');
                fetchReports();
            }
        } catch (err) {
            toast.error(err.response?.data?.message || 'Action failed');
            console.error(err);
        }
    };

    const filteredReports = reports.filter(r =>
        (r.reason || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
        (r.reported?.email || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
        (r.reporter?.email || '').toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <h1 className="text-2xl font-bold text-white flex items-center gap-2">
                    <img src="/Icons/icons8-reports-100.png" alt="Reports" className="w-8 h-8 object-contain" />
                    Content Moderation & Reports
                </h1>

                <div className="flex items-center gap-3 w-full sm:w-auto">
                    <div className="relative flex-1 sm:w-64">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-white/40" size={18} />
                        <input
                            type="text"
                            placeholder="Search reports..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full bg-transparent border border-white/10 rounded-lg pl-10 pr-4 py-2 text-white text-sm focus:outline-none focus:border-accent"
                        />
                    </div>
                    <select
                        value={statusFilter}
                        onChange={(e) => setStatusFilter(e.target.value)}
                        className="bg-transparent border border-white/10 rounded-lg px-4 py-2 text-white text-sm focus:outline-none"
                    >
                        <option value="">All Statuses</option>
                        <option value="PENDING">Pending</option>
                        <option value="INVESTIGATING">Investigating</option>
                        <option value="ACTION_TAKEN">Action Taken</option>
                        <option value="DISMISSED">Dismissed</option>
                    </select>
                </div>
            </div>

            <div className="bg-transparent border border-white/10 rounded-xl overflow-hidden shadow-sm">
                <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm text-white/70">
                        <thead className="bg-white/5 border-b border-white/10 text-white/90">
                            <tr>
                                <th className="px-6 py-4 font-medium">Target</th>
                                <th className="px-6 py-4 font-medium">Reported By</th>
                                <th className="px-6 py-4 font-medium">Reason</th>
                                <th className="px-6 py-4 font-medium">Status</th>
                                <th className="px-6 py-4 font-medium text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-white/5">
                            {isLoading ? (
                                <tr><td colSpan="5" className="px-6 py-8 text-center">Loading reports...</td></tr>
                            ) : filteredReports.length === 0 ? (
                                <tr><td colSpan="5" className="px-6 py-8 text-center text-white/50">No reports found.</td></tr>
                            ) : (
                                filteredReports.map(report => (
                                    <tr key={report.id} className="hover:bg-white/[0.02] transition-colors">
                                        <td className="px-6 py-4">
                                            <span className={`px-2 py-0.5 rounded text-[10px] uppercase font-bold mr-2 ${report.item_type === 'PROFILE' ? 'bg-blue-500/20 text-blue-400' :
                                                report.item_type === 'JOB' ? 'bg-purple-500/20 text-purple-400' :
                                                    report.item_type === 'PROPOSAL' ? 'bg-orange-500/20 text-orange-400' :
                                                        'bg-gray-500/20 text-gray-400'
                                                }`}>
                                                {report.item_type}
                                            </span>
                                            <span className="text-white block mt-1 text-xs truncate max-w-xs">{report.reported?.email || 'System / Unknown'}</span>
                                        </td>
                                        <td className="px-6 py-4">{report.reporter?.email || 'Anonymous'}</td>
                                        <td className="px-6 py-4 max-w-xs">
                                            <p className="truncate text-white" title={report.reason}>{report.reason}</p>
                                        </td>
                                        <td className="px-6 py-4">
                                            <span className={`px-2 py-1 rounded-full text-xs font-medium ${report.status === 'PENDING' ? 'bg-red-500/10 text-red-400' :
                                                report.status === 'INVESTIGATING' ? 'bg-yellow-500/10 text-yellow-400' :
                                                    report.status === 'DISMISSED' ? 'bg-gray-500/10 text-gray-400' :
                                                        'bg-green-500/10 text-green-400'
                                                }`}>
                                                {report.status}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            {report.status !== 'ACTION_TAKEN' && report.status !== 'DISMISSED' && (
                                                <div className="flex items-center justify-end gap-2">
                                                    <button onClick={() => handleResolve(report, 'INVESTIGATING')} className="text-yellow-400 hover:text-yellow-300" title="Investigate"><Info size={18} /></button>
                                                    <button onClick={() => handleResolve(report, 'ACTION_TAKEN')} className="text-red-400 hover:text-red-300" title="Take Action / Ban"><CheckCircle size={18} /></button>
                                                    <button onClick={() => handleResolve(report, 'DISMISSED')} className="text-gray-400 hover:text-gray-300" title="Dismiss"><XCircle size={18} /></button>
                                                </div>
                                            )}
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

export default ModerationPage;

