import { useState, useEffect } from 'react';
import { Search, CornerUpLeft } from 'lucide-react';
import { formatINR } from '../../utils/currencyUtils';
import * as adminService from '../../services/adminService';
import { toast } from 'react-hot-toast';

const PaymentsPage = () => {
    const [payments, setPayments] = useState([]);
    const [isLoading, setIsLoading] = useState(true);
    const [statusFilter, setStatusFilter] = useState('');
    const [searchTerm, setSearchTerm] = useState('');

    useEffect(() => {
        fetchPayments();
    }, [statusFilter]);

    const fetchPayments = async () => {
        setIsLoading(true);
        try {
            const result = await adminService.fetchPayments({ status: statusFilter });
            if (result.success) {
                setPayments(result.data);
            }
        } catch (err) {
            console.error('Failed to fetch payments', err);
            toast.error('Failed to load payments');
        } finally {
            setIsLoading(false);
        }
    };

    const handleRefund = async (paymentId) => {
        if (!confirm('Are you sure you want to issue a refund for this payment?')) return;

        try {
            const result = await adminService.issueRefund(paymentId);
            if (result.success) {
                toast.success('Refund issued successfully');
                fetchPayments();
            }
        } catch (err) {
            toast.error('Refund failed');
            console.error(err);
        }
    };

    const filteredPayments = payments.filter(p =>
        (p.id || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
        (p.payer?.email || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
        (p.payee?.email || '').toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <h1 className="text-2xl font-bold text-white flex items-center gap-2">
                    <img src="/Icons/icons8-payments-64.png" alt="Payments" className="w-8 h-8 object-contain" />
                    Financial Transactions
                </h1>

                <div className="flex items-center gap-3 w-full sm:w-auto">
                    <div className="relative flex-1 sm:w-64">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-white/40" size={18} />
                        <input
                            type="text"
                            placeholder="Search payments..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full bg-transparent border border-white/10 rounded-lg pl-10 pr-4 py-2 text-white text-sm focus:outline-none focus:border-accent"
                        />
                    </div>
                    <select
                        value={statusFilter}
                        onChange={(e) => setStatusFilter(e.target.value)}
                        className="bg-transparent border border-white/10 rounded-lg px-4 py-2 text-white text-sm focus:outline-none"
                    >
                        <option value="">All Statuses</option>
                        <option value="escrow">In Escrow</option>
                        <option value="released">Released</option>
                        <option value="refunded">Refunded</option>
                    </select>
                </div>
            </div>

            <div className="bg-transparent border border-white/10 rounded-xl overflow-hidden shadow-sm">
                <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm text-white/70">
                        <thead className="bg-white/5 border-b border-white/10 text-white/90">
                            <tr>
                                <th className="px-6 py-4 font-medium">Txn ID</th>
                                <th className="px-6 py-4 font-medium">Payer (Client)</th>
                                <th className="px-6 py-4 font-medium">Payee (Freelancer)</th>
                                <th className="px-6 py-4 font-medium">Amount</th>
                                <th className="px-6 py-4 font-medium">Status</th>
                                <th className="px-6 py-4 font-medium text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-white/5">
                            {isLoading ? (
                                <tr><td colSpan="6" className="px-6 py-8 text-center">Loading transactions...</td></tr>
                            ) : filteredPayments.length === 0 ? (
                                <tr><td colSpan="6" className="px-6 py-8 text-center text-white/50">No transactions found.</td></tr>
                            ) : (
                                filteredPayments.map(payment => (
                                    <tr key={payment.id} className="hover:bg-white/[0.02] transition-colors">
                                        <td className="px-6 py-4">
                                            <span className="text-white font-mono text-[11px] truncate block w-24" title={payment.id}>{payment.id}</span>
                                            <span className="text-white/40 text-[10px]">{new Date(payment.created_at).toLocaleDateString()}</span>
                                        </td>
                                        <td className="px-6 py-4">{payment.payer?.email || 'N/A'}</td>
                                        <td className="px-6 py-4">{payment.payee?.email || 'N/A'}</td>
                                        <td className="px-6 py-4 font-medium text-white">{formatINR(payment.amount)}</td>
                                        <td className="px-6 py-4">
                                            <span className={`px-2 py-1 rounded-full text-xs font-medium ${payment.status === 'escrow' ? 'bg-blue-500/10 text-blue-400' :
                                                payment.status === 'released' ? 'bg-green-500/10 text-green-400' :
                                                    payment.status === 'refunded' ? 'bg-red-500/10 text-red-400' :
                                                        'bg-white/10 text-white/60'
                                                }`}>
                                                {payment.status.toUpperCase()}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            {payment.status !== 'refunded' && (
                                                <button onClick={() => handleRefund(payment.id)} className="text-xs flex items-center justify-end gap-1 ml-auto text-accent hover:text-white transition">
                                                    <CornerUpLeft size={14} /> Refund
                                                </button>
                                            )}
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

export default PaymentsPage;

import React, { useState, useEffect, useCallback } from 'react';
import { Download, CheckCircle, Clock, Trash2, Filter } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { getAdminProblems, updateProblemStatus, deleteProblem } from '../../services/apiService';
import { toast } from 'react-hot-toast';
import ConfirmModal from '../../components/shared/ConfirmModal';

const ProblemsPage = () => {
    const [problems, setProblems] = useState([]);
    const [loading, setLoading] = useState(true);
    const [statusFilter, setStatusFilter] = useState('');
    const [confirmModal, setConfirmModal] = useState({ isOpen: false, id: null, type: '' });

    const loadProblems = useCallback(async () => {
        setLoading(true);
        try {
            const result = await getAdminProblems(statusFilter);
            if (result.success) {
                setProblems(result.data);
            }
        } catch (error) {
            console.error('Error loading problems:', error);
            toast.error('Failed to load user problems');
        } finally {
            setLoading(false);
        }
    }, [statusFilter]);

    useEffect(() => {
        loadProblems();
    }, [loadProblems]);

    const handleStatusUpdate = async (id, newStatus) => {
        try {
            const result = await updateProblemStatus(id, newStatus);
            if (result.success) {
                toast.success(`Problem marked as ${newStatus}`);
                setProblems(prev => prev.map(p => p.id === id ? { ...p, status: newStatus } : p));
            }
        } catch (error) {
            toast.error('Failed to update status');
        }
    };

    const handleDelete = async () => {
        try {
            const result = await deleteProblem(confirmModal.id);
            if (result.success) {
                toast.success('Problem deleted');
                setProblems(prev => prev.filter(p => p.id !== confirmModal.id));
                setConfirmModal({ isOpen: false, id: null, type: '' });
            }
        } catch (error) {
            toast.error('Failed to delete problem');
        }
    };

    const formatDate = (dateString) => {
        return new Date(dateString).toLocaleDateString(undefined, {
            year: 'numeric',
            month: 'short',
            day: 'numeric',
            hour: '2-digit',
            minute: '2-digit'
        });
    };

    return (
        <div className="space-y-8 animate-in fade-in duration-500">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <motion.div
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                >
                    <h1 className="text-3xl font-bold text-white mb-2 flex items-center gap-3">
                        <img src="/Icons/icons8-problem-solution-66.png" alt="User Problems" className="w-8 h-8 object-contain" />
                        User Problems
                    </h1>
                    <p className="text-white/50 text-sm">Review challenges and issues reported by users via the Solutions page.</p>
                </motion.div>

                <div className="flex flex-wrap items-center gap-3">
                    <div className="relative">
                        <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-white/30" size={16} />
                        <select
                            value={statusFilter}
                            onChange={(e) => setStatusFilter(e.target.value)}
                            className="bg-white/5 border border-white/10 text-white rounded-xl pl-9 pr-4 py-2.5 outline-none focus:border-accent transition-all text-sm appearance-none min-w-[140px] cursor-pointer hover:bg-white/10"
                        >
                            <option value="" className="bg-secondary">All Status</option>
                            <option value="pending" className="bg-secondary">Pending</option>
                            <option value="resolved" className="bg-secondary">Resolved</option>
                        </select>
                    </div>
                    <button className="flex items-center gap-2 bg-white/5 hover:bg-white/10 text-white px-5 py-2.5 rounded-xl border border-white/10 transition-all text-sm font-bold active:scale-95">
                        <Download size={16} />
                        Export Data
                    </button>
                </div>
            </div>

            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.1 }}
                className="bg-transparent border border-white/10 rounded-2xl overflow-hidden"
            >
                <div className="overflow-x-auto">
