import React, { useState, useEffect, useCallback } from 'react';
import { Trash2, Star, MessageSquare, Briefcase, User, Info, Search, Filter } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { getAdminProjectReviews, getAdminSiteReviews, deleteReview } from '../../services/apiService';
import { toast } from 'react-hot-toast';
import ConfirmModal from '../../components/shared/ConfirmModal';

const ReviewsManagementPage = () => {
    const [reviews, setReviews] = useState([]);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState('project'); // 'project' or 'site'
    const [confirmModal, setConfirmModal] = useState({ isOpen: false, id: null });
    const [searchTerm, setSearchTerm] = useState('');

    const loadReviews = useCallback(async () => {
        setLoading(true);
        try {
            const result = activeTab === 'project' 
                ? await getAdminProjectReviews() 
                : await getAdminSiteReviews();

            if (result.success) {
                setReviews(result.data);
            }
        } catch (error) {
            console.error(`Error loading ${activeTab} reviews:`, error);
            toast.error(`Failed to load ${activeTab} reviews`);
        } finally {
            setLoading(false);
        }
    }, [activeTab]);

    useEffect(() => {
        loadReviews();
    }, [loadReviews]);

    const handleDelete = async () => {
        try {
            const result = await deleteReview(confirmModal.id, activeTab);
            if (result.success) {
                toast.success('Review deleted successfully');
                setReviews(prev => prev.filter(r => r.id !== confirmModal.id));
                setConfirmModal({ isOpen: false, id: null });
            }
        } catch (error) {
            toast.error('Failed to delete review');
        }
    };

    const formatDate = (dateString) => {
        return new Date(dateString).toLocaleDateString(undefined, {
            year: 'numeric',
            month: 'short',
            day: 'numeric'
        });
    };

    const renderStars = (rating) => {
        return (
            <div className="flex items-center gap-1">
                {[...Array(5)].map((_, i) => (
                    <Star 
                        key={i} 
                        size={12} 
                        className={i < rating ? "fill-accent text-accent" : "fill-white/10 text-white/10"} 
                    />
                ))}
                <span className="ml-1 text-xs font-bold text-accent">{rating}.0</span>
            </div>
        );
    };

    const filteredReviews = reviews.filter(review => {
        const searchLower = searchTerm.toLowerCase();
        if (activeTab === 'project') {
            return (
                review.comment?.toLowerCase().includes(searchLower) ||
                review.reviewer_profile?.name?.toLowerCase().includes(searchLower) ||
                review.reviewee_profile?.name?.toLowerCase().includes(searchLower) ||
                review.contract?.title?.toLowerCase().includes(searchLower)
            );
        } else {
            return (
                review.comment?.toLowerCase().includes(searchLower) ||
                review.name?.toLowerCase().includes(searchLower)
            );
        }
    });

    return (
        <div className="space-y-8 animate-in fade-in duration-500">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <motion.div
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                >
                    <h1 className="text-3xl font-bold text-white mb-2 flex items-center gap-3">
                        <img src="/Icons/icons8-review-100.png" alt="Reviews" className="w-8 h-8 object-contain" />
                        Reviews Management
                    </h1>
                    <p className="text-white/50 text-sm">Monitor and moderate platform and project-based user reviews.</p>
                </motion.div>

                <div className="flex items-center gap-4">
                    <div className="relative group min-w-[300px]">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-white/20 group-focus-within:text-accent transition-colors" size={18} />
                        <input 
                            type="text"
                            placeholder="Search reviews by content or user..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="bg-white/5 border border-white/10 rounded-xl pl-10 pr-4 py-2.5 text-sm text-white outline-none focus:border-accent/50 w-full transition-all hover:bg-white/10 focus:bg-white/[0.08]"
                        />
                    </div>
                </div>
            </div>

            {/* Tabs */}
            <div className="flex items-center gap-8 border-b border-white/10 w-full">
                <button
                    onClick={() => setActiveTab('project')}
                    className={`relative pb-4 px-2 flex items-center gap-2 text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'project' ? 'text-accent' : 'text-white/30 hover:text-white'}`}
                >
                    <Briefcase size={14} />
                    Project Reviews
                    {activeTab === 'project' && (
                        <motion.div 
                            layoutId="activeTabUnderline"
                            className="absolute bottom-[-1px] left-0 right-0 h-0.5 bg-accent"
                        />
                    )}
                </button>
                <button
                    onClick={() => setActiveTab('site')}
                    className={`relative pb-4 px-2 flex items-center gap-2 text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'site' ? 'text-accent' : 'text-white/30 hover:text-white'}`}
                >
                    <Star size={14} />
                    Site Reviews
                    {activeTab === 'site' && (
                        <motion.div 
                            layoutId="activeTabUnderline"
                            className="absolute bottom-[-1px] left-0 right-0 h-0.5 bg-accent"
                        />
                    )}
                </button>
            </div>

            <motion.div
                key={activeTab}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="bg-transparent border border-white/10 rounded-2xl overflow-hidden"
            >
                <div className="overflow-x-auto">
                    <table className="w-full text-left">
                        <thead>
                            <tr className="bg-white/5 text-white/50 text-[11px] font-black uppercase tracking-widest border-b border-white/10">
                                {activeTab === 'project' ? (
                                    <>
                                        <th className="px-6 py-4">Reviewer / Contract</th>
                                        <th className="px-6 py-4">Reviewee</th>
                                        <th className="px-6 py-4">Rating & Feedback</th>
                                        <th className="px-6 py-4">Date</th>
                                    </>
                                ) : (
                                    <>
                                        <th className="px-6 py-4">Reviewer Profile</th>
                                        <th className="px-6 py-4">Rating & Feedback</th>
                                        <th className="px-6 py-4">Date</th>
                                    </>
                                )}
                                <th className="px-6 py-4 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-white/5">
                            <AnimatePresence mode="wait">
                                {loading ? (
                                    <tr key="loading">
                                        <td colSpan="5" className="px-6 py-12 text-center text-white/40">
                                            <div className="flex flex-col items-center gap-3">
                                                <div className="w-8 h-8 border-2 border-accent border-t-transparent rounded-full animate-spin"></div>
                                                <span>Loading reviews...</span>
                                            </div>
                                        </td>
                                    </tr>
                                ) : filteredReviews.length === 0 ? (
                                    <tr key="empty">
                                        <td colSpan="5" className="px-6 py-12 text-center text-white/40">
                                            <div className="flex flex-col items-center gap-2">
                                                <Info size={24} className="text-white/20" />
                                                <span>No reviews found matching your search.</span>
                                            </div>
                                        </td>
                                    </tr>
                                ) : (
                                    filteredReviews.map((review) => (
                                        <motion.tr
                                            key={review.id}
                                            initial={{ opacity: 0 }}
                                            animate={{ opacity: 1 }}
                                            exit={{ opacity: 0 }}
                                            className="hover:bg-white/[0.02] transition-colors group"
                                        >
                                            {activeTab === 'project' ? (
                                                <>
                                                    <td className="px-6 py-4 whitespace-nowrap">
                                                        <div className="flex items-center gap-3">
                                                            <div className="w-8 h-8 rounded-full bg-accent/20 flex items-center justify-center overflow-hidden border border-white/10 shadow-sm shadow-black/20">
                                                                {review.reviewer_profile?.avatar_url ? (
                                                                    <img src={review.reviewer_profile.avatar_url} alt="" className="w-full h-full object-cover" />
                                                                ) : (
                                                                    <span className="text-[10px] text-accent font-bold">
                                                                        {(review.reviewer_profile?.name || 'U').charAt(0).toUpperCase()}
                                                                    </span>
                                                                )}
                                                            </div>
                                                            <div className="flex flex-col gap-0.5">
                                                                <span className="text-white font-medium text-xs">{review.reviewer_profile?.name || 'Unknown'}</span>
                                                                <span className="text-[9px] text-white/30 flex items-center gap-1">
                                                                    <Briefcase size={10} />
                                                                    {review.contract?.title || 'Contract Deleted'}
                                                                </span>
                                                            </div>
                                                        </div>
                                                    </td>
                                                    <td className="px-6 py-4 whitespace-nowrap">
                                                        <div className="flex items-center gap-3">
                                                            <div className="w-8 h-8 rounded-full bg-accent/20 flex items-center justify-center overflow-hidden border border-white/10 shadow-sm shadow-black/20">
                                                                {review.reviewee_profile?.avatar_url ? (
                                                                    <img src={review.reviewee_profile.avatar_url} alt="" className="w-full h-full object-cover" />
                                                                ) : (
                                                                    <span className="text-[10px] text-accent font-bold">
                                                                        {(review.reviewee_profile?.name || 'U').charAt(0).toUpperCase()}
                                                                    </span>
                                                                )}
                                                            </div>
                                                            <span className="text-white font-medium text-xs">{review.reviewee_profile?.name || 'Unknown'}</span>
                                                        </div>
                                                    </td>
                                                    <td className="px-6 py-4">
                                                        <div className="flex flex-col gap-1.5">
                                                            {renderStars(review.rating)}
                                                            <p className="text-sm text-white/60 line-clamp-2 max-w-md">{review.comment}</p>
                                                        </div>
                                                    </td>
                                                </>
                                            ) : (
                                                <>
                                                    <td className="px-6 py-4">
                                                        <div className="flex items-center gap-2">
                                                            <div className="w-8 h-8 rounded-full bg-white/5 flex items-center justify-center border border-white/10">
                                                                <User size={14} className="text-accent" />
                                                            </div>
                                                            <span className="text-white font-medium">{review.name}</span>
                                                        </div>
                                                    </td>
                                                    <td className="px-6 py-4">
                                                        <div className="flex flex-col gap-1.5">
                                                            {renderStars(review.rating)}
                                                            <p className="text-sm text-white/60 line-clamp-2 max-w-md">{review.comment}</p>
                                                        </div>
                                                    </td>
                                                </>
                                            )}
                                            <td className="px-6 py-4">
                                                <span className="text-white/40 text-xs font-semibold tracking-tighter uppercase opacity-80">{formatDate(review.created_at)}</span>
                                            </td>
                                            <td className="px-6 py-4 text-right">
                                                <button
                                                    onClick={() => setConfirmModal({ isOpen: true, id: review.id })}
                                                    className="p-2.5 bg-rose-500/10 text-rose-400 hover:bg-rose-500 hover:text-white rounded-xl transition-all border border-rose-500/20 active:scale-90"
                                                    title="Delete Review"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </td>
                                        </motion.tr>
                                    ))
                                )}
                            </AnimatePresence>
                        </tbody>
                    </table>
                </div>
            </motion.div>

            <ConfirmModal
                isOpen={confirmModal.isOpen}
                onClose={() => setConfirmModal({ isOpen: false, id: null })}
                onConfirm={handleDelete}
                title="Delete Review?"
                message={`Are you sure you want to delete this ${activeTab} review? This action cannot be undone and will permanently remove it from the platform.`}
                confirmText="Delete"
                cancelText="Cancel"
                variant="danger"
                icon={<img src="/Icons/icons8-delete-user-100.png" alt="Delete" className="w-16 h-16 object-contain" />}
            />
        </div>
    );
};

export default ReviewsManagementPage;

import { useState, useEffect } from 'react';
import { Save, Settings2, Percent, Users } from 'lucide-react';
import * as adminService from '../../services/adminService';
import { toast } from 'react-hot-toast';

const SettingsPage = () => {
    const [settings, setSettings] = useState({
        platform_commission: '10',
        maintenance_mode: 'false',
    });
    const [isLoading, setIsLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);

    useEffect(() => {
        fetchSettings();
    }, []);

    const fetchSettings = async () => {
        setIsLoading(true);
        try {
            const result = await adminService.fetchPlatformSettings();
            if (result.success) {
                setSettings(prev => ({ ...prev, ...result.data }));
            }
        } catch (err) {
            console.error('Failed to fetch settings', err);
            toast.error('Failed to load settings');
        } finally {
            setIsLoading(false);
        }
    };

    const handleSave = async (key, value, description) => {
        setIsSaving(true);
        try {
            let result;
            if (key === 'platform_commission') {
                result = await adminService.updateCommission(parseFloat(value));
            } else {
                result = await adminService.updatePlatformSetting(key, value);
            }

            if (result.success) {
                toast.success(result.message || 'Setting updated');
                setSettings(prev => ({ ...prev, [key]: value }));
            }
        } catch (err) {
            toast.error('Failed to update setting');
            console.error(err);
        } finally {
            setIsSaving(false);
        }
    };

    if (isLoading) return <div className="p-8 text-white/50">Loading configurations...</div>;

    return (
        <div className="max-w-4xl mx-auto space-y-6">
            <h1 className="text-2xl font-bold text-white mb-8 flex items-center gap-2">
                <img src="/Icons/icons8-setting-100.png" alt="Settings" className="w-8 h-8 object-contain" />
                Platform Configuration
            </h1>

            <div className="bg-transparent border border-white/10 rounded-xl overflow-hidden shadow-sm">
                <div className="p-6 border-b border-white/10 bg-white/[0.02]">
                    <div className="flex items-center gap-3">
                        <Settings2 className="text-accent" />
                        <div>
                            <h2 className="text-lg font-semibold text-white">Global Settings</h2>
                            <p className="text-sm text-white/50 mt-1">Changes applied here affect the entire marketplace.</p>
                        </div>
                    </div>
                </div>

                <div className="p-6 space-y-8">

                    {/* Commission Setting */}
                    <div className="flex flex-col sm:flex-row justify-between sm:items-center gap-4 border-b border-white/5 pb-8">
                        <div className="max-w-md">
                            <h3 className="text-white font-medium flex items-center gap-2">
                                <Percent size={16} className="text-white/50" />
                                Base Commission Rate
                            </h3>
                            <p className="text-sm text-white/50 mt-1">
                                The default percentage cut taken from successful contracts. For example, enter '0.10' for 10% or '0.15' for 15%.
                            </p>
                        </div>
                        <div className="flex items-center gap-3">
                            <input
                                type="text"
                                value={settings.platform_commission}
                                onChange={(e) => setSettings({ ...settings, platform_commission: e.target.value })}
                                className="w-24 bg-primary border border-white/10 rounded-lg px-3 py-2 text-white focus:border-accent outline-none"
                            />
                            <button
                                onClick={() => handleSave('platform_commission', settings.platform_commission, 'Global commission rate for contracts')}
                                disabled={isSaving}
                                className="bg-accent/20 hover:bg-accent text-accent hover:text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
                            >
                                Update
                            </button>
                        </div>
                    </div>

                    {/* Maintenance Mode */}
                    <div className="flex flex-col sm:flex-row justify-between sm:items-center gap-4">
                        <div className="max-w-md">
                            <h3 className="text-white font-medium flex items-center gap-2">
                                Maintenance Mode
                            </h3>
                            <p className="text-sm text-white/50 mt-1">
                                When toggled on, non-admin users will see a maintenance page and API functionality will be restricted. Enter 'true' or 'false'.
                            </p>
                        </div>
                        <div className="flex items-center gap-3">
                            <select
                                value={settings.maintenance_mode}
                                onChange={(e) => setSettings({ ...settings, maintenance_mode: e.target.value })}
                                className="w-24 bg-primary border border-white/10 rounded-lg px-3 py-2 text-white focus:border-accent outline-none"
                            >
                                <option value="false">Off</option>
                                <option value="true">On</option>
                            </select>
                            <button
                                onClick={() => handleSave('maintenance_mode', settings.maintenance_mode, 'Put platform in maintenance mode')}
                                disabled={isSaving}
                                className="bg-red-500/20 hover:bg-red-500 text-red-400 hover:text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
                            >
                                Apply
                            </button>
                        </div>
                    </div>

                </div>
            </div>

            {/* Admin Account Settings */}
            <div className="bg-transparent border border-white/10 rounded-xl overflow-hidden shadow-sm">
                <div className="p-6 border-b border-white/10 bg-white/[0.02]">
                    <div className="flex items-center gap-3">
                        <Users className="text-accent" />
                        <div>
                            <h2 className="text-lg font-semibold text-white">Admin Account Settings</h2>
                            <p className="text-sm text-white/50 mt-1">Update your own administrator credentials.</p>
                        </div>
                    </div>
                </div>

                <div className="p-6 space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div>
                            <label className="block text-sm font-medium text-white/80 mb-1.5">New Email Address</label>
                            <input
                                type="email"
                                placeholder="Enter new email"
                                id="adminEmail"
                                className="w-full bg-primary border border-white/10 rounded-lg px-4 py-2 text-white focus:border-accent outline-none"
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-white/80 mb-1.5">New Password</label>
                            <input
                                type="password"
                                placeholder="Enter new password"
                                id="adminPassword"
                                className="w-full bg-primary border border-white/10 rounded-lg px-4 py-2 text-white focus:border-accent outline-none"
                            />
                        </div>
                    </div>
                    <div className="flex justify-end">
                        <button
                            onClick={async () => {
                                const email = document.getElementById('adminEmail').value;
                                const password = document.getElementById('adminPassword').value;

                                if (!email && !password) {
                                    alert('Please provide at least one field to update');
                                    return;
                                }

                                setIsSaving(true);
                                try {
                                    const result = await adminService.updateAdminProfile({ email, password });
                                    if (result.success) {
                                        toast.success('Account credentials updated successfully.');
                                        document.getElementById('adminEmail').value = '';
                                        document.getElementById('adminPassword').value = '';
                                    }
                                } catch (err) {
                                    toast.error(err.response?.data?.message || 'Failed to update account credentials');
                                } finally {
                                    setIsSaving(false);
                                }
                            }}
                            disabled={isSaving}
                            className="bg-accent hover:bg-accent/90 text-white px-6 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
                        >
                            Save Account Changes
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default SettingsPage;

