import { addSkill, deleteSkill, fetchUsers } from '../../services/adminService';
import toast from 'react-hot-toast';
import { supabase } from '../../lib/supabase';

const SkillsPage = () => {
    const [skills, setSkills] = useState([]);
    const [loading, setLoading] = useState(true);
    const [newSkill, setNewSkill] = useState({ name: '', category: 'Development' });
    const [isAdding, setIsAdding] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');

    useEffect(() => {
        loadSkills();
    }, []);

    const loadSkills = async () => {
        try {
            setLoading(true);
            const { data, error } = await supabase.from('skills').select('*').order('name');
            if (error) throw error;
            setSkills(data || []);
        } catch (error) {
            toast.error('Failed to load skills');
        } finally {
            setLoading(false);
        }
    };

    const handleAdd = async (e) => {
        e.preventDefault();
        try {
            await addSkill(newSkill);
            toast.success('Skill added successfully');
            setNewSkill({ name: '', category: 'Development' });
            setIsAdding(false);
            loadSkills();
        } catch (error) {
            toast.error('Failed to add skill');
        }
    };



    const filteredSkills = skills.filter(skill => {
        const name = (skill.name || '').toLowerCase();
        const category = (skill.category || '').toLowerCase();
        const search = searchTerm.toLowerCase();
        return name.includes(search) || category.includes(search);
    });

    const handleDelete = async (id) => {
        if (!confirm('Are you sure you want to delete this skill?')) return;
        try {
            await deleteSkill(id);
            toast.success('Skill deleted');
            loadSkills();
        } catch (error) {
            toast.error('Failed to delete skill');
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-bold text-white flex items-center gap-2">
                        <img src="/Icons/icons8-skills-100.png" alt="Skills" className="w-8 h-8 object-contain" />
                        Skill Management
                    </h1>
                    <p className="text-white/60 text-sm mt-1">Configure available talent skills and categories</p>
                </div>
                <div className="flex items-center gap-4 flex-1 justify-end">
                    <div className="relative w-64">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-white/40" size={18} />
                        <input
                            type="text"
                            placeholder="Search skills..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full bg-transparent border border-white/10 rounded-xl pl-10 pr-4 py-2 text-white text-sm focus:outline-none focus:border-accent transition-all"
                        />
                    </div>
                    <button
                        onClick={() => setIsAdding(!isAdding)}
                        className="inline-flex items-center gap-2 px-4 py-2 bg-accent text-white rounded-xl hover:bg-accent-hover transition font-bold text-sm shadow-lg shadow-accent/20 shrink-0"
                    >
                        <Plus size={18} /> {isAdding ? 'Close' : 'Add New Skill'}
                    </button>
                </div>
            </div>

            {isAdding && (
                <div className="bg-transparent border border-white/10 rounded-2xl p-6 shadow-xl animate-in fade-in slide-in-from-top-4 duration-300">
                    <form onSubmit={handleAdd} className="flex flex-col md:flex-row gap-4 items-end">
                        <div className="flex-1 space-y-2">
                            <label className="text-xs font-semibold text-white/60 uppercase">Skill Name</label>
                            <input
                                required
                                type="text"
                                value={newSkill.name}
                                onChange={(e) => setNewSkill({ ...newSkill, name: e.target.value })}
                                placeholder="e.g. React.js, Python, UI Design"
                                className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-white focus:outline-none focus:border-accent transition"
                            />
                        </div>
                        <div className="w-full md:w-64 space-y-2">
                            <label className="text-xs font-semibold text-white/60 uppercase">Category</label>
                            <select
                                value={newSkill.category}
                                onChange={(e) => setNewSkill({ ...newSkill, category: e.target.value })}
                                className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-white focus:outline-none focus:border-accent transition appearance-none"
                            >
                                <option value="Development">Development</option>
                                <option value="Design">Design</option>
                                <option value="Marketing">Marketing</option>
                                <option value="Writing">Writing</option>
                                <option value="Video">Video & Animation</option>
                            </select>
                        </div>
                        <button type="submit" className="px-8 py-2 bg-white text-black font-bold rounded-xl hover:bg-white/90 transition text-sm h-[42px]">
                            Create Skill
                        </button>
                    </form>
                </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
                {loading ? (
                    <div className="col-span-full py-12 text-center text-white/40">Loading catalog...</div>
                ) : filteredSkills.length === 0 ? (
                    <div className="col-span-full py-12 text-center text-white/40">No skills found matching your search</div>
                ) : (
                    filteredSkills.map((skill) => (
                        <div key={skill.id} className="bg-transparent border border-white/10 p-4 rounded-xl flex items-center justify-between group hover:border-accent/40 transition-colors">
                            <div>
                                <h3 className="text-white font-medium">{skill.name}</h3>
                                <span className="text-[10px] text-accent uppercase font-bold tracking-wider">{skill.category}</span>
                            </div>
                            <button
                                onClick={() => handleDelete(skill.id)}
                                className="p-2 text-white/20 hover:text-red-500 hover:bg-red-500/10 rounded-lg transition"
                            >
                                <Trash2 size={16} />
                            </button>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
};

export default SkillsPage;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { 
    ArrowLeft, Send, User, CheckCircle, Clock, 
    AlertCircle, MessageSquare, Tag, Calendar,
    UserPlus, Shield, ExternalLink
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
    fetchTicketDetailsAdmin, 
    sendTicketMessageAdmin, 
    assignTicketAdmin, 
    updateTicketStatusAdmin 
} from '../../services/supportService';
import { toast } from 'react-hot-toast';

const SupportTicketDetailPage = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const [ticket, setTicket] = useState(null);
    const [loading, setLoading] = useState(true);
    const [newMessage, setNewMessage] = useState('');
    const [sending, setSending] = useState(false);
    const messagesEndRef = useRef(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    const loadTicketDetails = useCallback(async () => {
        try {
            const result = await fetchTicketDetailsAdmin(id);
            if (result.success) {
                setTicket(result.data);
            }
        } catch (error) {
            console.error('Error loading ticket details:', error);
            toast.error('Failed to load ticket details');
            navigate('/admin/support-tickets');
        } finally {
            setLoading(false);
        }
    }, [id, navigate]);

    useEffect(() => {
        loadTicketDetails();
    }, [loadTicketDetails]);

    useEffect(() => {
        scrollToBottom();
    }, [ticket?.messages]);

    const handleSendMessage = async (e) => {
        e.preventDefault();
        if (!newMessage.trim() || sending) return;

        setSending(true);
        try {
            const result = await sendTicketMessageAdmin(id, newMessage);
            if (result.success) {
                setTicket(prev => ({
                    ...prev,
                    messages: [...(prev.messages || []), result.data]
                }));
                setNewMessage('');
                toast.success('Message sent');
            }
        } catch (error) {
            toast.error('Failed to send message');
        } finally {
            setSending(false);
        }
    };

    const handleAssign = async () => {
        try {
            const result = await assignTicketAdmin(id);
            if (result.success) {
                toast.success('Ticket assigned to you');
                loadTicketDetails();
            }
        } catch (error) {
            toast.error(error.message || 'Failed to assign ticket');
        }
    };

    const handleStatusUpdate = async (newStatus) => {
        try {
            const result = await updateTicketStatusAdmin(id, newStatus);
            if (result.success) {
                toast.success(`Ticket marked as ${newStatus}`);
                setTicket(prev => ({ ...prev, status: newStatus }));
            }
        } catch (error) {
            toast.error('Failed to update status');
        }
    };

    if (loading) {
        return (
            <div className="flex flex-col items-center justify-center min-h-[60vh] gap-4">
                <div className="w-12 h-12 border-4 border-accent border-t-transparent rounded-full animate-spin"></div>
                <p className="text-white/40 font-medium">Loading ticket conversation...</p>
            </div>
        );
    }

    if (!ticket) return null;

    return (
        <div className="max-w-[1400px] mx-auto space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
            {/* Top Navigation */}
            <div className="flex items-center justify-between">
                <button 
                    onClick={() => navigate('/admin/support-tickets')}
                    className="flex items-center gap-2 text-white/50 hover:text-white transition-colors group"
                >
                    <div className="p-2 bg-white/5 rounded-lg group-hover:bg-white/10 transition-colors border border-white/10">
                        <ArrowLeft size={18} />
                    </div>
                    <span className="font-bold text-sm uppercase tracking-widest">Back to All Tickets</span>
                </button>

                <div className="flex items-center gap-3">
                    {!ticket.assigned_to && (
                        <button 
                            onClick={handleAssign}
                            className="flex items-center gap-2 bg-accent/10 text-accent hover:bg-accent hover:text-white px-5 py-2.5 rounded-xl border border-accent/20 transition-all text-sm font-black uppercase tracking-widest active:scale-95"
                        >
                            <UserPlus size={16} />
                            Assign to Me
                        </button>
                    )}
                    {ticket.status !== 'resolved' && (
                        <button 
                            onClick={() => handleStatusUpdate('resolved')}
                            className="flex items-center gap-2 bg-emerald-500/10 text-emerald-400 hover:bg-emerald-500 hover:text-white px-5 py-2.5 rounded-xl border border-emerald-500/20 transition-all text-sm font-black uppercase tracking-widest active:scale-95"
                        >
                            <CheckCircle size={16} />
                            Mark Resolved
                        </button>
                    )}
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 h-[75vh]">
                {/* Left Column: Chat History */}
                <div className="lg:col-span-2 flex flex-col bg-secondary/40 backdrop-blur-[32px] border border-white/10 rounded-2xl overflow-hidden shadow-2xl h-full">
                    <div className="p-6 border-b border-white/5 flex items-center justify-between bg-white/[0.02]">
                        <div className="flex items-center gap-4">
                            <div className="p-3 bg-accent/20 rounded-2xl text-accent border border-accent/20 shadow-lg shadow-accent/10">
                                <MessageSquare size={24} />
                            </div>
                            <div>
                                <h2 className="text-xl font-bold text-white leading-tight">Conversation Thread</h2>
                                <p className="text-white/40 text-[11px] font-black uppercase tracking-widest mt-0.5">Ticket #{ticket.id.slice(0, 8)}</p>
                            </div>
                        </div>
                    </div>

                    {/* Chat Area */}
                    <div className="flex-1 overflow-y-auto p-6 space-y-8 scrollbar-hide">
                        {/* Original Subject & Message */}
                        <div className="flex gap-4">
                            <div className="flex-shrink-0">
                                {ticket.profiles?.avatar_url ? (
                                    <img src={ticket.profiles.avatar_url} className="w-10 h-10 rounded-full object-cover ring-2 ring-white/10" alt="" />
                                ) : (
                                    <div className="w-10 h-10 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-white/40">
                                        <User size={20} />
                                    </div>
                                )}
                            </div>
                            <div className="flex-1 max-w-[85%]">
                                <div className="bg-white/5 border border-white/10 p-5 rounded-3xl rounded-tl-none shadow-xl">
                                    <h4 className="text-accent font-black text-[10px] uppercase tracking-[0.2em] mb-2">{ticket.profiles?.name} (Customer)</h4>
                                    <h3 className="text-white font-bold mb-3 text-lg">{ticket.subject}</h3>
                                    <p className="text-white/70 text-sm leading-relaxed whitespace-pre-wrap">{ticket.message}</p>
                                </div>
                                <span className="text-white/20 text-[10px] font-black uppercase mt-2 block tracking-widest">{new Date(ticket.created_at).toLocaleString()}</span>
                            </div>
                        </div>

                        {/* Threaded Replies */}
                        {ticket.messages?.map((msg) => (
                            <div key={msg.id} className={`flex gap-4 ${msg.sender_id === ticket.user_id ? '' : 'flex-row-reverse text-right'}`}>
                                <div className="flex-shrink-0">
                                    {msg.sender?.avatar_url ? (
                                        <img src={msg.sender.avatar_url} className="w-10 h-10 rounded-full object-cover ring-2 ring-white/10" alt="" />
                                    ) : (
                                        <div className="w-10 h-10 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-white/40">
                                            <Shield size={20} />
                                        </div>
                                    )}
                                </div>
                                <div className={`flex-1 max-w-[85%] ${msg.sender_id === ticket.user_id ? '' : 'flex flex-col items-end'}`}>
                                    <div className={`p-5 rounded-3xl shadow-xl w-fit min-w-[200px] border ${
                                        msg.sender_id === ticket.user_id 
                                            ? 'bg-white/5 border-white/10 rounded-tl-none' 
                                            : 'bg-accent/10 border-accent/20 rounded-tr-none text-left'
                                    }`}>
                                        <h4 className={`font-black text-[10px] uppercase tracking-[0.2em] mb-2 ${
                                            msg.sender_id === ticket.user_id ? 'text-white/40' : 'text-accent'
                                        }`}>
                                            {msg.sender?.name || (msg.sender_id === ticket.user_id ? 'Customer' : 'Agent')}
                                            {msg.sender_id !== ticket.user_id && ' (Support Agent)'}
                                        </h4>
                                        <p className="text-white/80 text-sm leading-relaxed whitespace-pre-wrap">{msg.message}</p>
                                    </div>
                                    <span className="text-white/20 text-[10px] font-black uppercase mt-2 block tracking-widest">{new Date(msg.created_at).toLocaleString()}</span>
                                </div>
                            </div>
                        ))}
                        <div ref={messagesEndRef} />
                    </div>

                    {/* Reply Input */}
                    <div className="p-6 bg-white/[0.02] border-t border-white/5">
                        <form onSubmit={handleSendMessage} className="relative">
                            <textarea
                                value={newMessage}
                                onChange={(e) => setNewMessage(e.target.value)}
                                placeholder="Type your reply to the user..."
                                className="w-full bg-white/5 border border-white/10 text-white rounded-2xl p-5 pr-14 min-h-[120px] focus:border-accent outline-none transition-all resize-none text-sm placeholder:text-white/20 shadow-inner"
                                disabled={sending || ticket.status === 'resolved'}
                            />
                            <button
                                type="submit"
                                disabled={!newMessage.trim() || sending || ticket.status === 'resolved'}
                                className="absolute right-4 bottom-4 p-3 bg-accent text-white rounded-xl hover:scale-105 active:scale-95 disabled:opacity-50 disabled:hover:scale-100 transition-all shadow-lg shadow-accent/20"
                            >
                                {sending ? (
                                    <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                                ) : (
                                    <Send size={20} />
                                )}
                            </button>
                        </form>
                        {ticket.status === 'resolved' && (
                            <p className="text-white/30 text-xs text-center mt-4 flex items-center justify-center gap-2">
                                <CheckCircle size={14} />
                                This ticket is resolved. Reopen to send further messages.
                            </p>
                        )}
                    </div>
                </div>

                {/* Right Column: Information Panel */}
                <div className="space-y-6 overflow-y-auto pr-2 scrollbar-hide">
                    {/* Status Card */}
                    <div className="bg-secondary/40 backdrop-blur-[32px] border border-white/10 rounded-2xl p-6 shadow-2xl">
                        <h3 className="text-white/40 font-black text-[11px] uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                            <Tag size={14} className="text-accent" />
                            Ticket Details
                        </h3>

                        <div className="space-y-5">
                            <div className="flex items-center justify-between">
                                <span className="text-white/40 text-xs font-bold uppercase">Status</span>
                                <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border shadow-sm ${
                                    ticket.status === 'resolved'
                                        ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20'
                                        : ticket.status === 'in_progress'
                                        ? 'bg-amber-500/10 text-amber-400 border-amber-500/20'
                                        : 'bg-blue-500/10 text-blue-400 border-blue-500/20'
                                }`}>
                                    {ticket.status === 'resolved' ? <CheckCircle size={10} /> : <Clock size={10} />}
                                    {ticket.status.replace('_', ' ')}
                                </span>
                            </div>

                            <div className="flex items-center justify-between">
                                <span className="text-white/40 text-xs font-bold uppercase">Priority</span>
                                <span className={`inline-flex items-center gap-1.5 px-3 py-0.5 rounded text-[10px] font-black uppercase tracking-widest border shadow-sm ${
                                    ticket.priority === 'high'
                                        ? 'bg-red-500/10 text-red-400 border-red-500/20'
                                        : 'bg-blue-500/10 text-blue-400 border-blue-500/20'
                                }`}>
                                    {ticket.priority}
                                </span>
                            </div>

                            <div className="flex items-center justify-between">
                                <span className="text-white/40 text-xs font-bold uppercase">Category</span>
                                <span className="text-white text-xs font-black uppercase bg-white/5 px-2 py-1 rounded border border-white/10 tracking-widest">
                                    {ticket.category}
                                </span>
                            </div>

                            <div className="flex items-center justify-between border-t border-white/5 pt-4">
                                <span className="text-white/40 text-[10px] uppercase font-black flex items-center gap-1">
                                    <Calendar size={12} />
                                    Created
                                </span>
                                <span className="text-white/60 text-xs font-bold">{new Date(ticket.created_at).toLocaleDateString()}</span>
                            </div>
                        </div>
                    </div>

                    {/* Customer Info Card */}
                    <div className="bg-secondary/40 backdrop-blur-[32px] border border-white/10 rounded-2xl p-6 shadow-2xl">
                        <h3 className="text-white/40 font-black text-[11px] uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                            <User size={14} className="text-accent" />
                            Customer Info
                        </h3>

                        <div className="flex flex-col items-center text-center p-4 bg-white/[0.02] border border-white/5 rounded-2xl">
                            {ticket.profiles?.avatar_url ? (
                                <img src={ticket.profiles.avatar_url} className="w-16 h-16 rounded-full object-cover border-2 border-white/10 shadow-xl mb-3" alt="" />
                            ) : (
                                <div className="w-16 h-16 rounded-full bg-white/5 border-2 border-white/10 flex items-center justify-center text-white/20 mb-3">
                                    <User size={30} />
                                </div>
                            )}
                            <h4 className="text-white font-bold text-lg mb-1">{ticket.profiles?.name}</h4>
                            <p className="text-white/40 text-xs mb-4 line-clamp-1">{ticket.profiles?.email}</p>

                            <button className="flex items-center gap-2 bg-white/5 hover:bg-white/10 text-white/70 hover:text-white px-4 py-2 rounded-xl transition-all text-[11px] font-black uppercase tracking-widest border border-white/10 w-full justify-center">
                                View Profile
                                <ExternalLink size={12} />
                            </button>
                        </div>
                    </div>

                    {/* Assignment Card */}
                    <div className="bg-secondary/40 backdrop-blur-[32px] border border-white/10 rounded-2xl p-6 shadow-2xl">
                        <h3 className="text-white/40 font-black text-[11px] uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                            <Shield size={14} className="text-accent" />
                            Assignment
                        </h3>

                        {ticket.assigned_admin ? (
                            <div className="flex items-center gap-3 p-3 bg-emerald-500/[0.03] border border-emerald-500/10 rounded-xl">
                                {ticket.assigned_admin.avatar_url ? (
                                    <img src={ticket.assigned_admin.avatar_url} className="w-10 h-10 rounded-full object-cover" alt="" />
                                ) : (
                                    <div className="w-10 h-10 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-white/20">
                                        <Shield size={16} />
                                    </div>
                                )}
                                <div>
                                    <p className="text-white/40 text-[9px] font-black uppercase tracking-widest">Handled by</p>
                                    <p className="text-white font-bold text-sm">{ticket.assigned_admin.name}</p>
                                </div>
                            </div>
                        ) : (
                            <div className="p-4 bg-red-500/[0.03] border border-red-500/10 rounded-xl text-center">
                                <p className="text-red-400/60 text-[10px] font-black uppercase tracking-widest mb-1 flex items-center justify-center gap-2">
                                    <AlertCircle size={12} />
                                    No Agent Assigned
                                </p>
                                <p className="text-white/30 text-[10px]">Unassigned tickets have lower visibility.</p>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default SupportTicketDetailPage;

import React, { useState, useEffect, useCallback } from 'react';
import { Download, CheckCircle, Clock, Filter, Mail, User, Tag, Eye, UserPlus, AlertCircle } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { fetchAllTicketsAdmin, updateTicketStatusAdmin, assignTicketAdmin } from '../../services/supportService';
import { toast } from 'react-hot-toast';
import { useNavigate } from 'react-router-dom';

const SupportTicketsPage = () => {
    const [tickets, setTickets] = useState([]);
    const [loading, setLoading] = useState(true);
    const [statusFilter, setStatusFilter] = useState('all');
    const navigate = useNavigate();

    const loadTickets = useCallback(async () => {
        setLoading(true);
        try {
            const result = await fetchAllTicketsAdmin({ status: statusFilter });
            if (result.success) {
                setTickets(result.data);
            }
        } catch (error) {
            console.error('Error loading tickets:', error);
            toast.error('Failed to load support tickets');
        } finally {
            setLoading(false);
        }
    }, [statusFilter]);

    useEffect(() => {
        loadTickets();
    }, [loadTickets]);

    const handleStatusUpdate = async (id, newStatus) => {
        try {
            const result = await updateTicketStatusAdmin(id, newStatus);
            if (result.success) {
                toast.success(`Ticket marked as ${newStatus}`);
                setTickets(prev => prev.map(t => t.id === id ? { ...t, status: newStatus } : t));
            }
        } catch (error) {
            toast.error('Failed to update ticket status');
        }
    };

    const handleAssign = async (id) => {
        try {
            const result = await assignTicketAdmin(id);
            if (result.success) {
                toast.success('Ticket assigned to you');
                loadTickets(); // Refresh to get admin info
            }
        } catch (error) {
            toast.error(error.message || 'Failed to assign ticket');
        }
    };

    const formatDate = (dateString) => {
        return new Date(dateString).toLocaleDateString(undefined, {
            year: 'numeric',
            month: 'short',
            day: 'numeric',
            hour: '2-digit',
            minute: '2-digit'
        });
    };

    return (
        <div className="space-y-8 animate-in fade-in duration-500">
            {/* Header section */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <motion.div
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                >
                    <h1 className="text-3xl font-bold text-white mb-2 flex items-center gap-3">
