import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { profileApi } from "../../services/profileApi";
import { useAuth } from "../../context/AuthContext";
import ProfileCompletionBar from "../freelancer/ProfileCompletionBar";

import StepBasic from "./steps/StepBasic";
import StepCompany from "./steps/StepCompany";
import StepPersonal from "./steps/StepPersonal";
import StepContact from "./steps/StepContact";
import StepLocation from "./steps/StepLocation";

export default function ClientProfileWizard() {
    const [step, setStep] = useState(1);
    const totalSteps = 5;
    const navigate = useNavigate();
    const { refreshProfile, user } = useAuth();
    const [profileData, setProfileData] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchProfile = async () => {
            try {
                const res = await profileApi.getClientProfile();
                setProfileData(res.data);

                // If profile is already complete, redirect to dashboard
                if (res.data?.is_client_profile_complete) {
                    navigate("/client/dashboard", { replace: true });
                }
            } catch (error) {
                console.error("Failed to fetch profile:", error);
            } finally {
                setLoading(false);
            }
        };
        fetchProfile();
    }, [navigate]);

    const next = (newData) => {
        setProfileData(prev => ({ ...prev, ...newData }));
        setStep(prev => prev + 1);
        window.scrollTo(0, 0);
    };

    const back = () => {
        setStep(prev => prev - 1);
        window.scrollTo(0, 0);
    };

    const finish = async () => {
        await refreshProfile();
        navigate("/client/dashboard", { replace: true });
    };

    if (loading) {
        return (
            <div className="min-h-screen bg-primary flex justify-center items-center text-white">
                <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-accent"></div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-primary flex justify-center items-center p-4">
            <div className="bg-secondary w-full max-w-4xl p-6 md:p-10 rounded-2xl shadow-2xl border border-gray-800">
                <div className="mb-8">
                    <div className="flex justify-between items-end mb-4">
                        <div>
                            <span className="text-accent font-bold uppercase tracking-wider text-xs">Profile Setup</span>
                            <h1 className="text-2xl font-bold text-white">Client Onboarding</h1>
                        </div>
                        <span className="text-sm text-gray-500 font-medium">Step {step} of {totalSteps}</span>
                    </div>
                    <ProfileCompletionBar percentage={Math.round((step / totalSteps) * 100)} />
                </div>

                <div className="relative overflow-hidden">
                    {step === 1 && <StepBasic initialData={profileData} next={next} />}
                    {step === 2 && <StepCompany initialData={profileData} next={next} back={back} />}
                    {step === 3 && <StepPersonal initialData={profileData} next={next} back={back} />}
                    {step === 4 && <StepContact initialData={profileData} next={next} back={back} />}
                    {step === 5 && <StepLocation initialData={profileData} finish={finish} back={back} />}
                </div>
            </div>
        </div>
    );
}

import { useState, useRef } from "react";
import { motion } from "framer-motion";
import { FiCamera, FiUser, FiArrowRight } from "react-icons/fi";
import { profileApi } from "../../../services/profileApi";
import toast from "react-hot-toast";

export default function StepBasic({ next, initialData }) {
    const [loading, setLoading] = useState(false);
    const [fullName, setFullName] = useState(initialData?.name || "");
    const [photoPreview, setPhotoPreview] = useState(initialData?.avatar_url || "");
    const fileInputRef = useRef(null);

    const handlePhotoChange = async (e) => {
        const file = e.target.files[0];
        if (!file) return;

        // Preview
        const reader = new FileReader();
        reader.onloadend = () => setPhotoPreview(reader.result);
        reader.readAsDataURL(file);

        // Upload immediately
        try {
            setLoading(true);
            const res = await profileApi.uploadClientPhoto(file);
            setPhotoPreview(res.data.photo_url);
            toast.success("Photo uploaded successfully!");
        } catch (error) {
            toast.error("Failed to upload photo");
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const handleContinue = async () => {
        if (!fullName.trim()) {
            toast.error("Please enter your full name");
            return;
        }

        try {
            setLoading(true);
            await profileApi.updateClientProfile({ 
                name: fullName,
                step: 'basic'
            });
            next({ name: fullName, avatar_url: photoPreview });
        } catch (error) {
            toast.error("Failed to save progress");
        } finally {
            setLoading(false);
        }
    };

    return (
        <motion.div 
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            className="space-y-8"
        >
            <div className="text-center">
                <h2 className="text-3xl font-bold text-white mb-2">Basic Information</h2>
                <p className="text-gray-400">Let's start with the basics. This is how freelancers will see you.</p>
            </div>

            <div className="flex flex-col items-center gap-6">
                <div className="relative group">
                    <div className="w-32 h-32 rounded-full border-4 border-accent/20 overflow-hidden bg-secondary flex items-center justify-center">
                        {photoPreview ? (
                            <img src={photoPreview} alt="Profile" className="w-full h-full object-cover" />
                        ) : (
                            <FiUser className="text-5xl text-gray-500" />
                        )}
                    </div>
                    <button 
                        onClick={() => fileInputRef.current?.click()}
                        className="absolute bottom-0 right-0 p-2 bg-accent rounded-full text-primary hover:scale-110 transition-transform shadow-lg"
                    >
                        <FiCamera size={20} />
                    </button>
                    <input 
                        type="file" 
                        ref={fileInputRef} 
                        onChange={handlePhotoChange} 
                        className="hidden" 
                        accept="image/*"
                    />
                </div>

                <div className="w-full max-w-md space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-400 mb-2">Full Name</label>
                        <div className="relative">
                            <FiUser className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" />
                            <input 
                                type="text" 
                                value={fullName}
                                onChange={(e) => setFullName(e.target.value)}
                                className="w-full bg-secondary border border-gray-700 rounded-lg py-3 pl-12 pr-4 text-white focus:outline-none focus:border-accent transition-colors"
                                placeholder="John Doe"
                            />
                        </div>
                    </div>
                </div>
            </div>

            <div className="flex justify-end pt-6">
                <button 
                    onClick={handleContinue}
                    disabled={loading}
                    className="flex items-center gap-2 px-8 py-3 bg-accent text-primary font-bold rounded-lg hover:bg-accent/90 disabled:opacity-50 transition-all shadow-xl shadow-accent/10"
                >
                    {loading ? "Saving..." : "Continue"}
                    {!loading && <FiArrowRight />}
                </button>
            </div>
        </motion.div>
    );
