      setIsLoading(false);
    }
  };

  const handleDelete = async (job) => {
    if (!confirm(`Delete "${job.title}"? This cannot be undone.`)) return;
    setDeletingId(job.id);
    try {
      await deleteJob(job.id);
      setJobs(prev => prev.filter(j => j.id !== job.id));
      toast.success('Job deleted');
    } catch (err) {
      toastApiError(err, 'Failed to delete job');
    } finally {
      setDeletingId(null);
    }
  };

  // ── Real-time updates: reflect status changes (e.g. IN_PROGRESS after proposal accepted)
  const handleJobUpdated = useCallback((job) => {
    setJobs(prev => prev.map(j => j.id === job.id ? { ...j, ...job } : j));
  }, []);

  const handleJobDeleted = useCallback(({ id }) => {
    setJobs(prev => prev.filter(j => j.id !== id));
  }, []);

  useRealtimeJobs({
    onJobUpdated: handleJobUpdated,
    onJobDeleted: handleJobDeleted,
  });

  const filtered = jobs.filter(j => {
    const matchesTab = activeTab === 'all' || (j.status || '').toUpperCase() === activeTab.toUpperCase();
    const matchesSearch = !searchTerm || 
      (j.title || '').toLowerCase().includes(searchTerm.toLowerCase()) || 
      (j.description || '').toLowerCase().includes(searchTerm.toLowerCase());
    return matchesTab && matchesSearch;
  });


  const formatDate = d => new Date(d).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
  const formatBudget = job => {
    if (!job.budget_amount && !job.budget) return '—';
    const amount = job.budget_amount || job.budget;
    return formatINR(amount) + (job.budget_type === 'hourly' ? '/hr' : '');
  };

  return (
    <div className="max-w-[1630px] mx-auto px-6 md:px-10 py-8 text-light-text font-sans tracking-tight">

      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
        <div className="space-y-1">
          <h1 className="text-2xl font-semibold text-white tracking-tight">My Jobs</h1>
          <p className="text-base text-light-text/70">{jobs.length} job{jobs.length !== 1 ? 's' : ''} posted</p>
        </div>
        <Button 
          onClick={() => navigate('/client/post-job')} 
          className="rounded-full px-6 h-10 text-sm font-semibold shadow-lg shadow-accent/20 hover:scale-105 transition-all w-fit"
          icon={Plus}
        >
          Post New Job
        </Button>
      </div>

      {/* Tab System - Premium Underlined Style */}
      <div className="flex items-center gap-10 border-b border-white/5 mb-10 overflow-x-auto no-scrollbar">
        {STATUS_TABS.map(t => {
          const isActive = activeTab === t.key;
          const count = t.key === 'all' ? jobs.length : jobs.filter(j => (j.status || '').toLowerCase() === t.key.toLowerCase()).length;
          return (
            <button
              key={t.key}
              onClick={() => setActiveTab(t.key)}
              className={`pb-4 text-[11px] font-bold uppercase tracking-[0.15em] transition-all relative whitespace-nowrap ${
                isActive ? 'text-accent' : 'text-white/40 hover:text-white/80'
              }`}
            >
              <div className="flex items-center gap-2">
                {t.label}
                {count > 0 && <span className={`text-[10px] opacity-60 font-medium ${isActive ? 'text-accent' : ''}`}>({count})</span>}
              </div>
              {isActive ? (
                <div className="absolute bottom-[-1px] left-0 right-0 h-[2px] bg-accent rounded-full" />
              ) : (
                <div className="absolute bottom-[-1px] left-0 right-0 h-[2px] bg-accent/0 hover:bg-accent/20 transition-all duration-300 rounded-full" />
              )}
            </button>
          );
        })}
      </div>

      {/* Jobs List */}
      {isLoading ? (
        <div className="space-y-4">
          {[1, 2, 3].map(i => <div key={i} className="animate-pulse bg-white/5 border border-white/10 rounded-2xl h-40" />)}
        </div>
      ) : filtered.length === 0 ? (
        <div className="flex flex-col items-center justify-center p-12 sm:p-20 bg-transparent border border-white/10 rounded-2xl text-center">
          <Briefcase className="w-12 h-12 text-light-text/20 mb-6" />
          <h3 className="text-lg font-semibold text-white mb-2">No jobs found</h3>
          <p className="text-light-text/50 text-base mb-8 max-w-md mx-auto">
            {activeTab === 'all' ? "You haven't posted any jobs yet. Get started by posting your first job." : `No jobs found with status "${activeTab.toLowerCase().replace(/_/g, ' ')}".`}
          </p>
          <Button onClick={() => navigate('/client/post-job')} variant="secondary" className="rounded-full px-8">
            Post your first job →
          </Button>
        </div>
      ) : (
        <div className="space-y-4">
          {filtered.map(job => (
            <div key={job.id} className="bg-transparent border border-white/10 rounded-2xl p-6 hover:border-accent/40 transition-all shadow-sm group">
              <div className="flex flex-col md:flex-row md:items-start justify-between gap-6">
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-3 mb-2">
                    <h3 className="text-white font-semibold text-lg truncate group-hover:text-accent transition-colors tracking-tight">{job.title}</h3>
                    <span className={`px-2.5 py-0.5 rounded-full text-[10px] font-bold border uppercase tracking-widest shrink-0 ${STATUS_BADGE[job.status] || 'bg-white/5 text-white/40 border-white/10'}`}>
                      {(job.status || 'open').replace(/_/g, ' ')}
                    </span>
                  </div>

                  {job.description && (
                    <p className="text-light-text/60 text-sm line-clamp-2 mb-4 leading-relaxed">{job.description}</p>
                  )}

                  <div className="flex flex-wrap gap-x-6 gap-y-3">
                    <div className="flex flex-col">
                      <span className="text-[10px] font-bold uppercase tracking-widest text-light-text/20 mb-0.5">Budget</span>
                      <span className="text-sm font-semibold text-white/90">
                        {formatBudget(job)}
                        {job.budget_type && <span className="text-light-text/40 font-medium ml-1">({job.budget_type})</span>}
                      </span>
                    </div>
                    {job.duration && (
                      <div className="flex flex-col">
                        <span className="text-[10px] font-bold uppercase tracking-widest text-light-text/20 mb-0.5">Duration</span>
                        <span className="text-sm font-semibold text-white/90">{job.duration}</span>
                      </div>
                    )}
                    <div className="flex flex-col">
                      <span className="text-[10px] font-bold uppercase tracking-widest text-light-text/20 mb-0.5">Proposals</span>
                      <span className="text-sm font-semibold text-white/90">{job.proposal_count || 0} applications</span>
                    </div>
                    <div className="flex flex-col">
                      <span className="text-[10px] font-bold uppercase tracking-widest text-light-text/20 mb-0.5">Posted</span>
                      <span className="text-sm font-semibold text-white/90">{formatDate(job.created_at)}</span>
                    </div>
                  </div>

                  {/* Skills */}
                  {job.skills?.length > 0 && (
                    <div className="flex flex-wrap gap-1.5 mt-5">
                      {job.skills.slice(0, 5).map(skill => (
                        <span key={skill} className="px-2.5 py-0.5 bg-white/5 text-white/50 border border-white/5 rounded-md text-[10px] font-bold uppercase tracking-wider">{skill}</span>
                      ))}
                      {job.skills.length > 5 && (
                        <span className="px-2.5 py-0.5 text-light-text/30 text-[10px] font-bold tracking-widest">+{job.skills.length - 5} MORE</span>
                      )}
                    </div>
                  )}
                </div>

                {/* Actions */}
                <div className="flex items-center gap-2 shrink-0 self-end md:self-start">
                  {(job.proposal_count || 0) > 0 && (
                    <button
                      onClick={() => navigate(`/client/proposals?job=${job.id}`)}
                      className="flex items-center gap-2 px-4 py-2 bg-accent/10 text-accent border border-accent/20 rounded-xl text-xs font-bold uppercase tracking-widest hover:bg-accent/20 transition-all shadow-lg shadow-accent/5"
                    >
                      Proposals <ChevronRight size={14} />
                    </button>
                  )}
                  <button
                    onClick={() => navigate(`/client/post-job?edit=${job.id}`)}
                    className="p-2.5 text-white/40 hover:text-white hover:bg-white/5 border border-transparent hover:border-white/10 rounded-xl transition-all shadow-sm"
                    title="Edit"
                  >
                    <Edit2 size={16} />
                  </button>
                  <button
                    onClick={() => handleDelete(job)}
                    disabled={deletingId === job.id}
                    className="p-2.5 text-white/40 hover:text-red-400 hover:bg-red-500/10 border border-transparent hover:border-red-500/20 rounded-xl transition-all shadow-sm"
                    title="Delete"
                  >
                    {deletingId === job.id ? <InfinityLoader size={20} /> : <Trash2 size={16} />}
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

