        {/* Action Buttons */}
        <div className="flex flex-col sm:flex-row items-center justify-end gap-4 pt-10 border-t border-white/5">
          <button
            onClick={() => navigate('/client/jobs')}
            className="w-full sm:w-auto py-4 px-8 rounded-2xl border border-white/5 text-[10px] font-bold uppercase tracking-[0.2em] text-white/40 hover:text-white hover:bg-white/5 transition-all order-2 sm:order-1"
