import { useState, useEffect, useCallback } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { FileText, CheckCircle, XCircle, Clock, MessageCircle, User, IndianRupee, ChevronDown, ChevronUp, Briefcase, Edit2, ChevronRight, ShieldCheck } from 'lucide-react';
import { formatINR } from '../../../../utils/currencyUtils';
import { getMyJobs, getMyProposals, updateProposalStatus } from '../../../../services/apiService';
import { toast } from 'react-hot-toast';
import { toastApiError } from '../../../../utils/apiErrorToast';
import Card from '../../../ui/Card';
import Button from '../../../ui/Button';
import Tabs from '../../../ui/Tabs';
import SectionHeader from '../../../ui/SectionHeader';
import EmptyState from '../../../ui/EmptyState';
import InfinityLoader from '../../../common/InfinityLoader';
import { useRealtimeProposals } from '../../../../context/RealtimeContext';

const STATUS_TABS = [
  { key: 'all', label: 'All' },
  { key: 'PENDING', label: 'Pending' },
  { key: 'ACCEPTED', label: 'Accepted' },
  { key: 'REJECTED', label: 'Rejected' },
];

const Proposals = () => {
  const [jobs, setJobs] = useState([]);
  const [proposals, setProposals] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('all');
  const [expandedJob, setExpandedJob] = useState(null);
  const [updatingId, setUpdatingId] = useState(null);
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const focusJobId = searchParams.get('job');

  useEffect(() => { loadData(); }, []);

  const loadData = async () => {
    setIsLoading(true);
    try {
      const [jobsRes, proposalsRes] = await Promise.all([
        getMyJobs(),
        getMyProposals()
      ]);

      if (jobsRes.success) setJobs(jobsRes.data || []);
      if (proposalsRes.success) setProposals(proposalsRes.data || []);

      if (focusJobId) setExpandedJob(focusJobId);
      else if (jobsRes.data?.length > 0) setExpandedJob(jobsRes.data[0].id);
    } catch (err) {
      toastApiError(err, 'Failed to load data');
    } finally {
      setIsLoading(false);
    }
  };

  const handleStatusUpdate = async (proposalId, status) => {
    setUpdatingId(proposalId);
    try {
      const res = await updateProposalStatus(proposalId, status);
      if (res.success) {
        setProposals(prev => prev.map(p => p.id === proposalId ? { ...p, status } : p));
        toast.success(status === 'ACCEPTED' ? 'Proposal accepted! Contract will be created.' : 'Proposal rejected');
      }
    } catch (err) {
      toastApiError(err, 'Failed to update proposal');
    } finally {
      setUpdatingId(null);
    }
  };

  // ── Real-time: new proposal arrives while client is on this page ───────────
  const handleNewProposal = useCallback((proposal) => {
    setProposals(prev => {
      if (prev.some(p => p.id === proposal.id)) return prev; // deduplicate
      return [proposal, ...prev];
    });
  }, []);

  const handleStatusChanged = useCallback(({ proposal_id, status }) => {
    setProposals(prev =>
      prev.map(p => p.id === proposal_id ? { ...p, status } : p)
    );
  }, []);

  useRealtimeProposals({
    onNewProposal: handleNewProposal,
    onStatusChanged: handleStatusChanged,
  });

  const filtered = proposals.filter(p => activeTab === 'all' || p.status === activeTab);
  const grouped = {};
  filtered.forEach(p => {
    if (!grouped[p.job_id]) grouped[p.job_id] = [];
    grouped[p.job_id].push(p);
  });


  const STATUS_CONFIG = {
    PENDING: { icon: <Clock size={14} />, cls: 'bg-yellow-500/10 text-yellow-400 border-yellow-500/20' },
    ACCEPTED: { icon: <CheckCircle size={14} />, cls: 'bg-green-500/10 text-green-400 border-green-500/20' },
    REJECTED: { icon: <XCircle size={14} />, cls: 'bg-red-500/10 text-red-400 border-red-500/20' },
  };

  return (
    <div className="max-w-[1630px] mx-auto px-4 sm:px-6 lg:px-8 mt-6 pb-12 space-y-6">
      <SectionHeader 
        title="Proposals" 
        subtext={`${proposals.length} proposal${proposals.length !== 1 ? 's' : ''} received`}
      />

      {/* Tabs */}
      <Tabs 
        tabs={STATUS_TABS.map(tab => ({
          ...tab,
          count: tab.key === 'all' ? proposals.length : proposals.filter(p => p.status === tab.key).length
        }))} 
        activeTab={activeTab} 
        onChange={setActiveTab} 
      />

      {isLoading ? (
        <div className="flex items-center justify-center h-48"><InfinityLoader size={20} /></div>
      ) : jobs.length === 0 ? (
        <EmptyState 
          icon={FileText}
          title="No jobs posted yet"
          action={
            <Button onClick={() => navigate('/client/post-job')} variant="ghost" className="text-accent hover:text-accent mt-2">
              Post a job to get proposals →
            </Button>
          }
        />
      ) : (
        <div className="space-y-6">
          <div className="space-y-4">
            {jobs.map(job => {
              const jobProposals = (grouped[job.id] || []).filter(p => activeTab === 'all' || p.status === activeTab);
              if (activeTab !== 'all' && jobProposals.length === 0) return null;
              const isExpanded = expandedJob === job.id;
              return (
                <Card key={job.id} padding="p-0" className="bg-transparent overflow-hidden">
                  <button onClick={() => setExpandedJob(isExpanded ? null : job.id)}
                    className="w-full flex items-center justify-between px-5 py-4 hover:bg-accent/5 transition">
                    <div className="flex items-center gap-3">
                      <p className="text-white font-medium">{job?.title || 'Job'}</p>
                      <span className="bg-accent/10 text-accent border border-accent/20 rounded-full px-2 py-0.5 text-xs">{jobProposals.length} proposals</span>
                    </div>
                    {isExpanded ? <ChevronUp size={18} className="text-white/40" /> : <ChevronDown size={18} className="text-white/40" />}
                  </button>

                  {isExpanded && (
                    <>
                      <div className="border-t border-white/10 divide-y divide-white/5">
                        {jobProposals.length === 0 ? (
                          <div className="px-5 py-8 text-center text-white/40 text-sm">
                            No proposals received for this job yet.
                          </div>
                        ) : (
                          jobProposals.map(proposal => {
                            const sc = STATUS_CONFIG[proposal.status] || STATUS_CONFIG.PENDING;
                            return (
                              <div key={proposal.id} className="px-5 py-4 flex items-start gap-4">
                                <div className="w-10 h-10 rounded-full bg-accent/20 flex items-center justify-center shrink-0 text-accent font-bold">
                                  {(proposal.freelancer?.name || '?')[0]}
                                </div>
                                <div className="flex-1 min-w-0">
                                  <div className="flex items-center gap-2 mb-1">
                                    <div className="flex items-center gap-1.5 flex-wrap">
                                      <p 
                                        onClick={() => {
                                          const fid = proposal.freelancer_id || proposal.freelancer?.id;
                                          if (fid) navigate(`/freelancer/${fid}`);
                                        }}
                                        className="text-white font-medium text-sm hover:text-accent cursor-pointer transition-colors"
                                      >
                                        {proposal.freelancer?.name || 'Freelancer'}
                                      </p>
                                      {proposal.freelancer?.is_verified && (
                                        <span title="Identity Verified" className="text-blue-500 shrink-0">
                                          <ShieldCheck size={14} />
                                        </span>
                                      )}
                                    </div>
                                    <span className={`flex items-center gap-1 px-2 py-0.5 rounded-full text-xs border ${sc.cls}`}>
                                      {sc.icon} {proposal.status}
                                    </span>
                                  </div>
                                  {proposal.cover_letter && (
                                    <p className="text-white/50 text-sm line-clamp-2 mb-2">{proposal.cover_letter}</p>
                                  )}
                                  <div className="flex items-center gap-4 text-xs text-white/40">
                                    <span className="flex items-center gap-1">
                                      <IndianRupee size={12} className="text-accent" /> {formatINR(proposal.proposed_rate || 0)}
                                      {job?.budget_type === 'hourly' ? '/hr' : ' fixed'}
                                    </span>
                                  </div>
                                </div>
                                {proposal.status === 'PENDING' && (
                                  <div className="flex gap-2 shrink-0">
                                    <Button 
                                      onClick={() => handleStatusUpdate(proposal.id, 'ACCEPTED')}
                                      disabled={updatingId === proposal.id}
                                      isLoading={updatingId === proposal.id}
                                      icon={CheckCircle}
                                      variant="success"
                                      size="sm"
                                    > Accept </Button>
                                    <Button 
                                      onClick={() => handleStatusUpdate(proposal.id, 'REJECTED')}
                                      disabled={updatingId === proposal.id}
                                      icon={XCircle}
                                      variant="danger"
                                      size="sm"
                                    > Reject </Button>
                                  </div>
                                )}
                              </div>
                            );
                          })
                        )}
                      </div>
                      <div className="bg-transparent border-t border-white/5 px-5 py-5">
                        <div className="flex items-center justify-between mb-4">
                          <h4 className="text-white/70 text-sm font-semibold tracking-wide uppercase">Job Posting Details</h4>
                          <button 
                            onClick={() => navigate(`/client/jobs`)}
                            className="text-accent text-xs hover:underline flex items-center gap-1.5 font-medium"
                          >
                            Manage in My Jobs <ChevronRight size={14} />
                          </button>
                        </div>
                        <div className="bg-transparent border border-white/10 rounded-2xl p-6 space-y-4">
                          {job?.description && (
                            <p className="text-white/50 text-sm leading-relaxed">{job.description}</p>
                          )}
                          <div className="flex flex-wrap gap-5 pt-2">
                            <div className="space-y-1">
                              <p className="text-[10px] text-white/30 uppercase font-bold tracking-wider">Budget</p>
                              <p className="text-white/70 text-xs flex items-center gap-1">
                                <IndianRupee size={12} className="text-accent" />
                                {job?.budget_amount ? formatINR(job.budget_amount) : '—'}
                                <span className="opacity-50 font-normal">({job?.budget_type || 'fixed'})</span>
                              </p>
                            </div>
                            {job?.duration && (
                              <div className="space-y-1">
                                <p className="text-[10px] text-white/30 uppercase font-bold tracking-wider">Duration</p>
                                <p className="text-white/70 text-xs flex items-center gap-1">
                                  <Clock size={12} className="text-accent" />
                                  {job.duration}
                                </p>
                              </div>
                            )}
                            {job?.category && (
                              <div className="space-y-1">
                                <p className="text-[10px] text-white/30 uppercase font-bold tracking-wider">Category</p>
                                <p className="text-white/70 text-xs">{job.category}</p>
                              </div>
                            )}
                          </div>
                          {job?.skills?.length > 0 && (
                            <div className="pt-2 border-t border-white/5 flex flex-wrap gap-1.5">
                              {job.skills.map(s => (
                                <span key={s} className="px-2 py-0.5 bg-accent/5 text-accent/70 border border-accent/10 rounded-md text-[10px]">{s}</span>
                              ))}
                            </div>
                          )}
                        </div>
                      </div>
                    </>
                  )}
                </Card>
              );
            })}
          </div>

          {/* Page Footer Navigation */}
          <div className="pt-8 border-t border-white/10 flex justify-start">
            <button
              onClick={() => navigate('/client/jobs')}
              className="group flex items-center gap-3 px-6 py-3 bg-transparent hover:bg-white/5 text-white border border-white/10 rounded-2xl transition shadow-xl"
            >
              <div className="p-2 bg-accent/10 rounded-lg group-hover:bg-accent/20 transition">
                <Briefcase size={20} className="text-accent" />
              </div>
              <div className="text-left">
                <p className="text-sm font-semibold">Manage All Jobs</p>
                <p className="text-white/40 text-[10px]">View, edit, or close your other listings</p>
              </div>
              <ChevronRight size={18} className="ml-4 text-white/20 group-hover:text-white transition" />
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

