import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, ChevronDown, ChevronUp, Search, Filter } from 'lucide-react';

const FILTER_SECTIONS = [
  {
    id: 'experience_level',
    title: 'Experience Level',
    options: [
      { id: 'entry', label: 'Entry Level', countKey: 'entry' },
      { id: 'intermediate', label: 'Intermediate', countKey: 'intermediate' },
      { id: 'expert', label: 'Expert', countKey: 'expert' }
    ]
  },
  {
    id: 'budget_type',
    title: 'Job Type',
    options: [
      { id: 'hourly', label: 'Hourly', countKey: 'hourly' },
      { id: 'fixed', label: 'Fixed-Price', countKey: 'fixed' }
    ]
  },
  {
    id: 'proposal_count_range',
    title: 'Number of Proposals',
    options: [
      { id: '0-5', label: 'Less than 5', countKey: '0-5' },
      { id: '5-10', label: '5 to 10', countKey: '5-10' },
      { id: '10-15', label: '10 to 15', countKey: '10-15' },
      { id: '15-20', label: '15 to 20', countKey: '15-20' },
      { id: '20-50', label: '20 to 50', countKey: '20-50' }
    ]
  },
  {
    id: 'duration',
    title: 'Project Length',
    options: [
      { id: 'less_than_1_month', label: 'Less than 1 month', countKey: 'less_than_1_month' },
      { id: '1-3_months', label: '1 to 3 months', countKey: '1-3_months' },
      { id: '3-6_months', label: '3 to 6 months', countKey: '3-6_months' },
      { id: 'more_than_6_months', label: 'More than 6 months', countKey: 'more_than_6_months' }
    ]
  }
];

export default function JobFiltersModal({ isOpen, onClose, currentFilters, onApply, stats }) {
  const [tempFilters, setTempFilters] = useState(currentFilters || {});
  const [expandedSections, setExpandedSections] = useState(['experience_level', 'budget_type']);

  useEffect(() => {
    if (isOpen) setTempFilters(currentFilters || {});
  }, [isOpen, currentFilters]);

  const toggleSection = (id) => {
    setExpandedSections(prev =>
      prev.includes(id) ? prev.filter(s => s !== id) : [...prev, id]
    );
  };

  const handleCheckboxChange = (sectionId, optionId) => {
    setTempFilters(prev => {
      const current = prev[sectionId] || [];
      const updated = current.includes(optionId)
        ? current.filter(id => id !== optionId)
        : [...current, optionId];
      return { ...prev, [sectionId]: updated };
    });
  };

  const clearAll = () => {
    setTempFilters({});
  };

  const applyFilters = () => {
    onApply(tempFilters);
    onClose();
  };

  const getCount = (sectionId, countKey) => {
    if (!stats) return null;
    if (sectionId === 'experience_level') return stats.experience?.[countKey];
    if (sectionId === 'budget_type') return stats.budget_type?.[countKey];
    if (sectionId === 'proposal_count_range') return stats.proposals?.[countKey];
    if (sectionId === 'duration') return stats.duration?.[countKey];
    return null;
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-end overflow-hidden">
      {/* Backdrop */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-black/80 backdrop-blur-md"
      />

      <motion.div
        initial={{ x: '100%' }}
        animate={{ x: 0 }}
        exit={{ x: '100%' }}
        transition={{ type: 'spring', damping: 30, stiffness: 300 }}
        className="relative w-full sm:max-w-[420px] h-full bg-[#0A0A0B] border-l border-white/5 flex flex-col shadow-[0_0_50px_rgba(0,0,0,0.5)]"
      >
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-6 sm:px-8 sm:py-8 border-b border-white/5">
          <div className="space-y-1">
            <h2 className="text-xl font-black text-white tracking-tighter">Filter Criteria</h2>
            <p className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em]">Refine your search results</p>
          </div>
          <button
            onClick={onClose}
            className="w-10 h-10 flex items-center justify-center rounded-xl bg-white/5 text-white/40 hover:text-white hover:bg-white/10 transition-all active:scale-95"
          >
            <X size={18} strokeWidth={2.5} />
          </button>
        </div>

        {/* Filters Scroll Area */}
        <div className="flex-1 overflow-y-auto px-6 py-8 sm:px-8 custom-scrollbar space-y-8">
          {FILTER_SECTIONS.map((section, idx) => (
            <div key={section.id} className="last:border-0">
              <button
                onClick={() => toggleSection(section.id)}
                className="flex items-center justify-between w-full group mb-4"
              >
                <span className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40 group-hover:text-accent transition-colors">
                  {section.title}
                </span>
                <ChevronDown 
                  size={14} 
                  strokeWidth={3}
                  className={`text-white/20 transition-transform duration-500 ${expandedSections.includes(section.id) ? 'rotate-180 text-accent' : ''}`} 
                />
              </button>

              <AnimatePresence initial={false}>
                {expandedSections.includes(section.id) && (
                  <motion.div
                    initial={{ height: 0, opacity: 0 }}
                    animate={{ height: 'auto', opacity: 1 }}
                    exit={{ height: 0, opacity: 0 }}
                    transition={{ duration: 0.4, ease: [0.23, 1, 0.32, 1] }}
                    className="overflow-hidden space-y-1.5"
                  >
                    {section.options.map((option) => {
                      const isChecked = (tempFilters[section.id] || []).includes(option.id);
                      const count = getCount(section.id, option.countKey);

                      return (
                        <label
                          key={option.id}
                          className="flex items-center justify-between cursor-pointer group py-2.5 px-3 rounded-xl hover:bg-white/5 transition-all"
                        >
                          <div className="flex items-center gap-3">
                            <div className="relative flex-shrink-0">
                              <input
                                type="checkbox"
                                className="peer hidden"
                                checked={isChecked}
                                onChange={() => handleCheckboxChange(section.id, option.id)}
                              />
                              <div className={`w-5 h-5 rounded-lg border-2 flex items-center justify-center transition-all duration-300 ${
                                isChecked 
                                  ? 'bg-accent border-accent shadow-[0_0_15px_rgba(var(--color-accent-rgb),0.3)]' 
                                  : 'bg-transparent border-white/10 group-hover:border-white/20'
                              }`}>
                                {isChecked && (
                                  <motion.div 
                                    initial={{ scale: 0 }}
                                    animate={{ scale: 1 }}
                                    className="w-2.5 h-2.5 bg-primary rounded-[2px]"
                                  />
                                )}
                              </div>
                            </div>
                            <span className={`text-[13px] sm:text-sm transition-colors font-bold ${isChecked ? 'text-white' : 'text-white/40 group-hover:text-white/70'}`}>
                              {option.label}
                            </span>
                          </div>
                          {count !== null && (
                            <span className="min-w-[22px] h-[22px] px-2 flex items-center justify-center rounded-lg text-[10px] font-black tabular-nums bg-white/5 text-white/20 border border-white/5 group-hover:border-white/10 transition-all">
                              {count}
                            </span>
                          )}
                        </label>
                      );
                    })}
                  </motion.div>
                )}
              </AnimatePresence>
            </div>
          ))}

          {/* Budget Range */}
          <div className="pt-4 border-t border-white/5">
            <span className="block text-[10px] font-black uppercase tracking-[0.2em] text-white/40 mb-6 font-sans">
              Fixed Price Range
            </span>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2.5">
                <label className="text-[10px] text-white/20 font-black uppercase tracking-[0.1em]">Min Budget</label>
                <div className="relative group/input">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20 text-sm font-black">₹</span>
                  <input
                    type="number"
                    value={tempFilters.budget_min || ''}
                    onChange={(e) => setTempFilters(prev => ({ ...prev, budget_min: e.target.value }))}
                    className="w-full bg-white/5 border border-white/5 rounded-xl pl-8 pr-4 py-3.5 text-sm font-black focus:border-accent/40 focus:bg-white/10 outline-none transition-all placeholder:text-white/10 text-white shadow-inner"
                    placeholder="0"
                  />
                </div>
              </div>
              <div className="space-y-2.5">
                <label className="text-[10px] text-white/20 font-black uppercase tracking-[0.1em]">Max Budget</label>
                <div className="relative group/input">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20 text-sm font-black">₹</span>
                  <input
                    type="number"
                    value={tempFilters.budget_max || ''}
                    onChange={(e) => setTempFilters(prev => ({ ...prev, budget_max: e.target.value }))}
                    className="w-full bg-white/5 border border-white/5 rounded-xl pl-8 pr-4 py-3.5 text-sm font-black focus:border-accent/40 focus:bg-white/10 outline-none transition-all placeholder:text-white/10 text-white shadow-inner"
                    placeholder="Any"
                  />
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Footer Actions */}
        <div className="p-6 sm:p-8 border-t border-white/5 bg-[#0A0A0B] flex items-center gap-4 mt-auto">
          <button
            onClick={clearAll}
            className="flex-1 h-12 text-[10px] sm:text-[11px] font-black tracking-[0.2em] border border-white/10 rounded-2xl hover:bg-white/5 transition-all text-white/40 hover:text-white uppercase"
          >
            Reset All
          </button>
          <button
            onClick={applyFilters}
            className="flex-[1.5] h-12 px-6 text-[10px] sm:text-[11px] font-black tracking-[0.2em] bg-accent hover:bg-accent/90 text-primary rounded-2xl transition-all active:scale-[0.98] shadow-lg shadow-accent/20 uppercase"
          >
            Apply Filters
          </button>
        </div>
      </motion.div>
    </div>
  );
};

