import React, { useState } from "react";
import { X, AlertTriangle } from "lucide-react";
import { useNavigate } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { useAuth } from "../../../../context/AuthContext";
import { deleteAccount } from "../../../../services/apiService";
import { supabase } from "../../../../lib/supabase";
import SettingsCard from "../../../ui/SettingsCard";
import InfinityLoader from '../../../common/InfinityLoader';

const FreelancerAccountActionsSection = () => {
  const { profile, logout } = useAuth();
  const navigate = useNavigate();

  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [deleteReason, setDeleteReason] = useState("");
  const [deleting, setDeleting] = useState(false);
  const [deleteError, setDeleteError] = useState(null);

  const handleDelete = async () => {
    setDeleting(true);
    setDeleteError(null);
    try {
      await deleteAccount(deleteReason.trim());
      await supabase.auth.signOut();
      await logout();
      navigate("/?deleted=1", { replace: true });
    } catch (err) {
      const msg = err?.response?.data?.message || err?.message || "Something went wrong.";
      setDeleteError(msg);
    } finally {
      setDeleting(false);
    }
  };

  return (
    <div className="space-y-10">
      <SettingsCard
        title="Account Management"
        subtitle="Manage your platform presence and data privacy"
        icon="/Icons/icons8-alert-96 (1).png"
        iconClassName="w-[30px] h-[30px]"
      >
        <div className="flex flex-col sm:flex-row items-center justify-between gap-6">
          <div>
            <h4 className="text-white font-bold text-lg">Close Account</h4>
            <p className="text-white/40 text-sm font-medium mt-1">Permanently remove your freelancer profile and history.</p>
          </div>
          <button
            onClick={() => { setShowDeleteModal(true); setDeleteError(null); setDeleteReason(""); }}
            className="px-8 h-12 rounded-xl border border-red-500/20 bg-red-500/5 text-red-500 font-bold text-sm hover:bg-red-500/10 transition-all"
          >
            Close Account
          </button>
        </div>
      </SettingsCard>

      <AnimatePresence>
        {showDeleteModal && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/80 backdrop-blur-md flex items-center justify-center z-[110] p-4"
          >
            <motion.div
              initial={{ scale: 0.95, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.95, opacity: 0 }}
              className="glass-card w-full max-w-[500px] rounded-3xl overflow-hidden shadow-2xl"
            >
              <div className="p-8 lg:p-10">
                <div className="flex justify-between items-center mb-8">
                  <h2 className="text-2xl font-black text-white tracking-tight uppercase">Confirm Deletion</h2>
                  <button onClick={() => setShowDeleteModal(false)} className="text-white/20 hover:text-white transition-colors">
                    <X size={24} />
                  </button>
                </div>

                <div className="space-y-6">
                  <div className="p-4 rounded-xl bg-white/5 border border-white/10">
                    <p className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] mb-1">Authenticated Identity</p>
                    <p className="text-white font-medium">{profile?.email || "user@example.com"}</p>
                  </div>

                  <p className="text-white/50 text-sm leading-relaxed">
                    This action is permanent. All your projects, feedback, and certifications will be removed from our architecture.
                  </p>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] pl-1">Reason (Optional)</label>
                    <textarea
                      value={deleteReason}
                      onChange={e => setDeleteReason(e.target.value)}
                      placeholder="Why are you leaving us?"
                      rows={3}
                      className="w-full px-5 py-4 bg-white/5 border border-white/10 rounded-xl text-white outline-none focus:border-red-500/40 focus:bg-white/[0.07] transition-all placeholder:text-white/10 resize-none"
                    />
                  </div>

                  {deleteError && (
                    <div className="p-4 rounded-xl bg-red-500/10 border border-red-500/20 text-red-400 text-xs font-bold uppercase tracking-wider">
                      {deleteError}
                    </div>
                  )}
                </div>

                <div className="flex flex-col sm:flex-row gap-4 mt-12">
                  <button
                    onClick={handleDelete}
                    disabled={deleting}
                    className="flex-1 h-14 rounded-xl bg-red-600 text-white font-black text-sm uppercase tracking-widest hover:bg-red-500 transition-all shadow-lg shadow-red-600/20 disabled:opacity-50 flex items-center justify-center gap-2"
                  >
                    {deleting && <InfinityLoader size={20} />}
                    Delete Forever
                  </button>
                  <button
                    onClick={() => setShowDeleteModal(false)}
                    className="flex-1 h-14 rounded-xl bg-white/5 border border-white/10 text-white font-black text-sm uppercase tracking-widest hover:bg-white/10 transition-all"
                  >
                    Cancel
                  </button>
                </div>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default FreelancerAccountActionsSection;

import React, { useState } from "react";
import { Bell, Check } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { useAuth } from "../../../../context/AuthContext";
import { updateMyProfile } from "../../../../services/apiService";
import { toastApiError } from "../../../../utils/apiErrorToast";
import { toast } from "react-hot-toast";
import SettingsCard from "../../../ui/SettingsCard";
import InfinityLoader from '../../../common/InfinityLoader';

const FreelancerNotificationSection = () => {
  const { profile, refreshProfile } = useAuth();
  const [tab, setTab] = useState("email");
  const [saving, setSaving] = useState(false);

  const [notifications, setNotifications] = useState(profile?.notification_preferences || {
    email_proposals: true, email_messages: true, email_contracts: true,
    push_messages: true,
  });

  const handleNotificationSave = async () => {
    setSaving(true);
    try {
      await updateMyProfile({ notification_preferences: notifications });
      if (refreshProfile) refreshProfile();
      toast.success('Preferences saved');
    } catch (err) {
      toastApiError(err, 'Failed to save preferences');
    } finally {
      setSaving(false);
    }
  };

  const tabs = [
    { id: "email", label: "Email Intelligence" },
    { id: "push", label: "Real-time Alerts" },
  ];

  return (
    <div className="space-y-10">
      <div className="mb-10">
        <h2 className="text-3xl font-bold text-white tracking-tight leading-none mb-4">
          Communication Preferences
        </h2>
        <p className="text-white/40 text-sm font-medium">
          Control how and when you receive intelligence updates, alerts, and system notifications.
        </p>
      </div>

      {/* TABS */}
      <div className="flex gap-10 border-b border-white/5 mb-12">
        {tabs.map((t) => (
          <button
            key={t.id}
            onClick={() => setTab(t.id)}
            className={`pb-4 text-sm font-bold uppercase tracking-widest transition-all relative ${
              tab === t.id ? "text-white" : "text-white/30 hover:text-white/60"
            }`}
          >
            {t.label}
            {tab === t.id && (
              <motion.div
                layoutId="activeTabNote"
                className="absolute bottom-0 left-0 right-0 h-[2px] bg-accent shadow-[0_0_10px_rgba(56,189,248,0.5)]"
              />
            )}
          </button>
        ))}
      </div>

      <AnimatePresence mode="wait">
        <motion.div
          key={tab}
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -10 }}
          className="space-y-8"
        >
          <SettingsCard 
            title={tab === "email" ? "Email Relay System" : "Push Architecture"} 
            subtitle="Configure granular alerts for your professional workflow"
            icon={Bell}
            action={
              <button 
                onClick={handleNotificationSave} 
                disabled={saving}
                className="h-12 px-8 rounded-xl bg-accent text-white font-bold text-sm uppercase tracking-widest hover:scale-[1.01] transition-all disabled:opacity-50"
              >
                {saving ? <InfinityLoader size={20} /> : 'Save System'}
              </button>
            }
          >
            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-8">
              {tab === "email" ? (
                <>
                  {[
                    { key: 'email_proposals', label: 'Proposal & Invitation Feed' },
                    { key: 'email_messages',  label: 'Direct Correspondence' },
                    { key: 'email_contracts', label: 'Contract Milestone Updates' },
                  ].map((item) => (
                    <label key={item.key} className="flex items-center justify-between p-4 rounded-xl bg-white/5 border border-white/10 cursor-pointer group hover:border-accent/30 transition-all">
                      <div>
                        <p className="text-white font-bold text-sm">{item.label}</p>
                        <p className="text-white/30 text-xs mt-1 uppercase tracking-tighter">Primary Relay</p>
                      </div>
                      <button 
                        type="button"
                        onClick={(e) => {
                          e.preventDefault();
                          setNotifications(n => ({ ...n, [item.key]: !n[item.key] }));
                        }}
                        className={`relative w-12 h-6 rounded-full transition-colors ${notifications[item.key] ? 'bg-accent shadow-lg shadow-accent/20' : 'bg-white/10'}`}
                      >
                        <span className={`absolute top-1 w-4 h-4 bg-white rounded-full shadow transition-all ${notifications[item.key] ? 'left-7' : 'left-1'}`} />
                      </button>
                    </label>
                  ))}
                </>
              ) : (
                <>
                  {[
                    { key: 'push_messages', label: 'Real-time Message Desktop Alert' },
                  ].map((item) => (
                    <label key={item.key} className="flex items-center justify-between p-6 rounded-xl bg-gradient-to-tr from-accent/5 to-transparent border border-white/10 cursor-pointer group hover:border-accent/30 transition-all col-span-full">
                       <div>
                        <p className="text-white font-bold text-lg mb-1">{item.label}</p>
                        <p className="text-white/40 text-sm">Instant visual alerts for incoming professional communication.</p>
                      </div>
                      <button 
                        type="button"
                        onClick={(e) => {
                          e.preventDefault();
                          setNotifications(n => ({ ...n, [item.key]: !n[item.key] }));
                        }}
                        className={`relative w-14 h-7 rounded-full transition-colors ${notifications[item.key] ? 'bg-accent shadow-lg shadow-accent/20' : 'bg-white/10'}`}
                      >
                        <span className={`absolute top-1 w-5 h-5 bg-white rounded-full shadow transition-all ${notifications[item.key] ? 'left-8' : 'left-1'}`} />
                      </button>
                    </label>
                  ))}
                </>
              )}
            </div>
          </SettingsCard>
        </motion.div>
      </AnimatePresence>
    </div>
  );
};

export default FreelancerNotificationSection;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
    ChevronDown
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { connectsApi } from '../../../services/connectsApi';
import PaymentModal from '../../freelancer/connects/PaymentModal';
import InfinityLoader from '../../common/InfinityLoader';
import toast from 'react-hot-toast';

export default function BuyConnects() {
    const navigate = useNavigate();
    const [packages, setPackages] = useState([]);
    const [selectedPackage, setSelectedPackage] = useState(null);
    const [balance, setBalance] = useState(0);
    const [promoCode, setPromoCode] = useState("");
    const [appliedPromo, setAppliedPromo] = useState(null);
    const [isApplyingPromo, setIsApplyingPromo] = useState(false);
    const [loading, setLoading] = useState(true);
    const [isSelectOpen, setIsSelectOpen] = useState(false);
    const selectRef = useRef(null);

    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const [clientSecret, setClientSecret] = useState("");
    const [checkoutDetails, setCheckoutDetails] = useState({ amount: 0, connects: 0 });

    useEffect(() => {
        const fetchData = async () => {
            try {
                const [balanceRes, packagesRes] = await Promise.all([
                    connectsApi.getBalance(),
                    connectsApi.getPackages()
                ]);
                setBalance(balanceRes.data.balance);
                setPackages(packagesRes.data);
                const bestValue = packagesRes.data.find(p => p.isBestValue) || packagesRes.data[0];
                setSelectedPackage(bestValue);
            } catch (error) {
                console.error("Fetch data failed:", error);
                toast.error("Failed to load connects configurations");
            } finally {
                setLoading(false);
            }
        };
        fetchData();

        const handleClickOutside = (e) => {
            if (selectRef.current && !selectRef.current.contains(e.target)) {
                setIsSelectOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const handleApplyPromo = async () => {
        if (!promoCode) return;
        setIsApplyingPromo(true);
        try {
            const res = await connectsApi.applyPromoCode(promoCode);
            setAppliedPromo(res.data);
            toast.success(`Applied ${res.data.discount_percent}% discount!`);
        } catch (error) {
            toast.error(error.response?.data?.message || "Invalid promo code");
        } finally {
            setIsApplyingPromo(false);
        }
    };

    const handleBuyNow = async () => {
        if (!selectedPackage) return;
        try {
            const res = await connectsApi.createPaymentIntent(
                selectedPackage.id,
                appliedPromo?.code
            );
            setClientSecret(res.data.clientSecret);
            setCheckoutDetails({ amount: res.data.amount, connects: res.data.connects });
            setIsPaymentModalOpen(true);
        } catch (error) {
            console.error("Create intent failed:", error);
            toast.error("Failed to initialize payment");
        }
    };

    const calculateFinalPrice = () => {
        if (!selectedPackage) return 0;
        if (!appliedPromo) return selectedPackage.price;
        return selectedPackage.price * (1 - appliedPromo.discount_percent / 100);
    };

    if (loading) return <div className="fixed inset-0 bg-primary/95 backdrop-blur-sm z-50 flex items-center justify-center min-h-screen w-full"><InfinityLoader size={60} /></div>;

    const finalPrice = calculateFinalPrice();
    const expiryDate = new Date();
    expiryDate.setFullYear(expiryDate.getFullYear() + 1);
    const formattedExpiry = expiryDate.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });

    return (
        <div className="w-full mx-auto mt-6 pb-12 font-sans tracking-tight animate-in fade-in duration-500">
            {/* Minimal Header */}
            <div className="flex items-center justify-between gap-6 mb-12">
                <div className="flex items-center gap-6">
                    <button onClick={() => navigate(-1)} className="text-light-text/40 hover:text-light-text transition-all text-sm font-bold uppercase tracking-[0.2em]">
                        Cancel
                    </button>
                    <div className="h-4 w-px bg-white/10" />
                    <h1 className="text-3xl sm:text-4xl font-bold text-light-text tracking-tight">Buy Connects</h1>
                </div>
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
                {/* Main Content */}
                <div className="xl:col-span-8 bg-secondary/30 border border-white/5 rounded-[32px] p-8 lg:p-12 space-y-12 shadow-2xl backdrop-blur-sm">

                    {/* Current Balance */}
                    <div className="space-y-1">
                        <label className="text-light-text/30 text-[11px] font-bold uppercase tracking-[0.2em] block">Your available Connects</label>
                        <p className="text-4xl font-bold text-light-text tracking-tighter">{balance}</p>
                    </div>

                    {/* Amount Selection */}
                    <div className="space-y-4">
                        <label className="text-light-text/30 text-[11px] font-bold uppercase tracking-[0.2em] block">Select the amount to buy</label>
                        <div className="relative" ref={selectRef}>
                            <button
                                onClick={() => setIsSelectOpen(!isSelectOpen)}
                                className={`w-full md:max-w-md flex items-center justify-between px-8 py-5 rounded-2xl border transition-all ${isSelectOpen ? 'border-accent/40 shadow-xl bg-secondary/60' : 'bg-secondary/40 border-white/10 hover:border-white/20'
                                    }`}
                            >
                                <span className="text-light-text text-lg font-bold">{selectedPackage?.connects} for ${selectedPackage?.price.toFixed(2)}</span>
                                <ChevronDown size={20} className={`text-light-text/40 transition-transform ${isSelectOpen ? 'rotate-180' : ''}`} />
                            </button>

                            <AnimatePresence>
                                {isSelectOpen && (
                                    <motion.div
                                        initial={{ opacity: 0, y: 5 }}
                                        animate={{ opacity: 1, y: 0 }}
                                        exit={{ opacity: 0, y: 5 }}
                                        className="absolute top-full left-0 mt-3 w-full md:max-w-md bg-secondary border border-white/10 rounded-[24px] shadow-2xl z-50 overflow-hidden backdrop-blur-xl"
                                    >
                                        <div className="p-3 space-y-1">
                                            {packages.map((pkg) => (
                                                <button
                                                    key={pkg.id}
                                                    onClick={() => { setSelectedPackage(pkg); setIsSelectOpen(false); }}
                                                    className={`w-full flex items-center justify-between p-5 rounded-xl text-sm transition-all ${selectedPackage?.id === pkg.id ? 'bg-accent/10 text-accent font-bold' : 'text-light-text/60 hover:bg-white/5 hover:text-light-text'
                                                        }`}
                                                >
                                                    <span className="font-semibold">{pkg.connects} Connects</span>
                                                    <span className="font-bold">${pkg.price.toFixed(2)}</span>
                                                </button>
                                            ))}
                                        </div>
                                    </motion.div>
                                )}
                            </AnimatePresence>
                        </div>
                    </div>

                    {/* Cost Breakdown */}
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-10 pt-10 border-t border-white/5">
                        <div className="space-y-1">
                            <label className="text-light-text/30 text-[11px] font-bold uppercase tracking-[0.2em] block">Charge amount</label>
                            <p className="text-2xl font-bold text-light-text tracking-tight">${finalPrice.toFixed(2)}</p>
                        </div>

                        <div className="space-y-1">
                            <label className="text-light-text/30 text-[11px] font-bold uppercase tracking-[0.2em] block">New balance</label>
                            <p className="text-2xl font-bold text-accent tracking-tight">{balance + (selectedPackage?.connects || 0)}</p>
                        </div>

                        <div className="space-y-1">
                            <label className="text-light-text/30 text-[11px] font-bold uppercase tracking-[0.2em] block">Expiry date</label>
                            <p className="text-lg font-bold text-light-text/80 tracking-tight">{formattedExpiry}</p>
                        </div>
                    </div>

                    {/* Promo Code */}
                    <div className="space-y-5 pt-8 border-t border-white/5">
                        <label className="text-light-text/30 text-[11px] font-bold uppercase tracking-[0.2em] block">Promo code</label>
                        <div className="flex gap-4 max-w-sm">
                            <input
                                type="text"
                                placeholder="Enter code"
                                value={promoCode}
                                onChange={(e) => setPromoCode(e.target.value.toUpperCase())}
                                className="flex-1 bg-secondary/40 border border-white/10 rounded-2xl py-4 px-6 text-light-text text-sm font-bold tracking-widest focus:outline-none focus:border-accent/40 transition-all placeholder:text-light-text/10"
                            />
                            <button
                                onClick={handleApplyPromo}
                                disabled={isApplyingPromo || !promoCode}
                                className="h-14 px-8 bg-white/5 hover:bg-white/10 text-light-text font-bold rounded-2xl text-[11px] uppercase tracking-[0.2em] transition-all disabled:opacity-20 flex items-center justify-center border border-white/5"
                            >
                                {isApplyingPromo ? <InfinityLoader size={20} /> : "Apply"}
                            </button>
                        </div>
                        {appliedPromo && (
                            <p className="text-[11px] text-accent font-bold uppercase tracking-[0.2em]">
                                Discount Applied: -{appliedPromo.discount_percent}%
                            </p>
                        )}
                    </div>

                    {/* Footer Actions */}
                    <div className="pt-10 flex flex-col sm:flex-row items-center gap-6">
                        <button
                            onClick={handleBuyNow}
                            className="w-full sm:w-auto h-14 px-14 bg-accent text-primary font-bold rounded-2xl transition-all text-[11px] uppercase tracking-[0.2em] hover:bg-white active:scale-95 shadow-xl shadow-accent/10"
                        >
                            Buy Connects Now
                        </button>
                        <p className="text-[11px] text-light-text/20 font-bold uppercase tracking-[0.1em]">
                            Secure Stripe Checkout
                        </p>
                    </div>
                </div>

                {/* Sidebar Info */}
                <div className="xl:col-span-4 space-y-8">
                    <div className="bg-accent/5 border border-accent/10 rounded-[32px] p-10 space-y-6 relative overflow-hidden group">
                        <div className="absolute top-0 right-0 w-32 h-32 bg-accent/10 rounded-full blur-3xl -mr-16 -mt-16 group-hover:bg-accent/20 transition-all" />
                        <h3 className="text-[11px] font-bold text-accent uppercase tracking-[0.3em]">Special Offer</h3>
                        <h2 className="text-2xl font-bold text-light-text leading-tight tracking-tight">Get 50% Off Freelancer Plus</h2>
                        <p className="text-light-text/50 text-sm leading-relaxed font-medium">
                            100 Connects included monthly. Plus members win 40% more contracts on average.
                        </p>
                        <button className="w-full h-14 bg-accent text-primary font-bold rounded-2xl transition-all text-[11px] uppercase tracking-[0.2em] hover:bg-white active:scale-95">
                            Learn More
                        </button>
                    </div>

                    <div className="bg-secondary/20 rounded-[32px] p-10 border border-white/5 space-y-4">
                        <h4 className="text-[11px] font-bold text-light-text/20 uppercase tracking-[0.2em]">Safe Billing</h4>
                        <p className="text-light-text/40 text-xs leading-relaxed font-medium">
                            Your transactions are protected with industry-standard bank-level encryption. We never store your card details on our servers.
                        </p>
                    </div>
                </div>
            </div>

            <PaymentModal
                isOpen={isPaymentModalOpen}
                onClose={() => setIsPaymentModalOpen(false)}
                clientSecret={clientSecret}
                amount={checkoutDetails.amount}
                connects={checkoutDetails.connects}
                onComplete={() => {
                    toast.success("Balance updated successfully!");
                    navigate('/freelancer/dashboard');
                }}
            />
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  ArrowLeft,
  Upload,
  Send,
  CheckCircle,
  XCircle,
  Clock,
  MessageSquare,
  FileText,
  IndianRupee,
  AlertCircle
} from 'lucide-react';
import { formatINR } from '../../../utils/currencyUtils';
import { getMyContracts, submitWork, getContractSubmissions } from '../../../services/apiService';
import { toast } from 'react-hot-toast';
import Avatar from '../../Avatar';
import ReactMarkdown from 'react-markdown';
import InfinityLoader from '../../common/InfinityLoader';

const ContractDetails = () => {
  const { id } = useParams();
  const navigate = useNavigate();

  const [contract, setContract] = useState(null);
  const [submissions, setSubmissions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);

  // Submission Form State
  const [showSubmitForm, setShowSubmitForm] = useState(false);
  const [description, setDescription] = useState('');
  const [attachmentUrl, setAttachmentUrl] = useState('');

  useEffect(() => {
    fetchContractDetails();
  }, [id]);

  const fetchContractDetails = async () => {
    try {
      setLoading(true);
      // Fetch user contracts and find the one matching ID since there's no getContactById endpoint currently 
      // accessible directly for freelancers
      const response = await getMyContracts();
      if (response.success) {
        const foundContract = response.data.find(c => c.id === id);
        if (foundContract) {
          setContract(foundContract);
          await fetchSubmissions();
        } else {
          toast.error("Contract not found");
          navigate('/freelancer/contracts');
        }
      }
    } catch (error) {
      console.error("Error fetching contract:", error);
      toast.error("Failed to load contract details");
    } finally {
      setLoading(false);
    }
  };

  const fetchSubmissions = async () => {
    try {
      const response = await getContractSubmissions(id);
      if (response.success) {
        setSubmissions(response.data || []);
      }
    } catch (error) {
      console.error("Error fetching submissions:", error);
    }
  };

  const handleSubmitWork = async (e) => {
    e.preventDefault();
    if (!description.trim()) {
      return toast.error("Please provide a description of the work delivered");
    }

    try {
      setSubmitting(true);
      const response = await submitWork({
        contract_id: id,
        description: description.trim(),
        attachment_url: attachmentUrl,
        attachment_name: attachmentUrl ? attachmentUrl.split('/').pop() : ''
      });

      if (response.success) {
        toast.success("Work submitted successfully!");
        setShowSubmitForm(false);
        setDescription('');
        setAttachmentUrl('');
        fetchSubmissions();
      }
    } catch (error) {
      console.error("Error submitting work:", error);
      toast.error(error.response?.data?.message || "Failed to submit work");
    } finally {
      setSubmitting(false);
    }
  };

  const getStatusBadge = (status) => {
    switch (status) {
      case 'PENDING':
        return <span className="px-3 py-1.5 bg-yellow-500/10 text-yellow-500 border border-yellow-500/20 rounded-lg text-[9px] font-bold tracking-widest uppercase flex items-center gap-1.5"><Clock size={12} /> Pending Review</span>;
      case 'APPROVED':
        return <span className="px-3 py-1.5 bg-emerald-500/10 text-emerald-400 border border-emerald-500/20 rounded-lg text-[9px] font-bold tracking-widest uppercase flex items-center gap-1.5"><CheckCircle size={12} /> Approved</span>;
      case 'REQUEST_CHANGES':
        return <span className="px-3 py-1.5 bg-orange-500/10 text-orange-400 border border-orange-500/20 rounded-lg text-[9px] font-bold tracking-widest uppercase flex items-center gap-1.5"><AlertCircle size={12} /> Changes Requested</span>;
      case 'REJECTED':
        return <span className="px-3 py-1.5 bg-red-500/10 text-red-400 border border-red-500/20 rounded-lg text-[9px] font-bold tracking-widest uppercase flex items-center gap-1.5"><XCircle size={12} /> Rejected</span>;
      default:
        return <span className="px-3 py-1.5 bg-white/5 text-white/50 border border-white/10 rounded-lg text-[9px] font-bold tracking-widest uppercase">{status}</span>;
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] gap-4">
        <InfinityLoader size={20} />
        <p className="text-light-text/60 animate-pulse">Loading contract details...</p>
      </div>
    );
  }

  if (!contract) return null;

  const clientName = contract.client?.profiles?.name || 'Client';
  const clientAvatar = contract.client?.profiles?.avatar_url;

  return (
    <div className="max-w-[1630px] mx-auto space-y-6 pb-10 animate-in ml-10 mr-6 fade-in slide-in-from-bottom-4 duration-500 font-sans tracking-tight">

      {/* Header */}
      <button onClick={() => navigate(-1)}
        className="flex items-center gap-2 text-light-text/30 hover:text-white text-[11px] font-bold uppercase tracking-[0.2em] transition group w-fit mb-4">
        <ArrowLeft size={14} className="group-hover:-translate-x-1 transition-transform" />
        Back to Contracts
      </button>

      <div className="flex flex-col md:flex-row md:items-start justify-between gap-6 mb-8">
        <div className="flex flex-col gap-1">
          <div className="flex items-center gap-4 mb-2">
            <span className={`px-2.5 py-1 rounded-lg text-[9px] font-bold tracking-widest border uppercase bg-secondary/60 ${contract.status === 'COMPLETED' ? 'border-blue-500/20 text-blue-400' : 'border-emerald-500/20 text-emerald-400'
              }`}>
              {contract.status === 'IN_PROGRESS' ? 'ACTIVE' : contract.status}
            </span>
            <span className="text-light-text/20 text-[10px] font-bold uppercase tracking-[0.2em]">ID: {contract.id.split('-')[0].toUpperCase()}</span>
          </div>
          <h1 className="text-2xl font-semibold text-white tracking-tight leading-tight">{contract.jobs?.title || 'Contract Details'}</h1>
          <div className="flex items-center gap-3 mt-2">
            {clientAvatar
              ? <img src={clientAvatar} alt={clientName} className="w-7 h-7 rounded-full object-cover ring-1 ring-white/10" />
              : <div className="w-7 h-7 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-white/30 text-[10px] font-bold uppercase tracking-widest font-primary">{clientName[0]}</div>
            }
            <span className="text-light-text/60 text-sm font-medium">{clientName}</span>
          </div>
        </div>

        <div className="flex flex-col sm:flex-row gap-3 items-start shrink-0 mt-1">
          <div className="px-5 py-3 bg-secondary/40 border border-white/5 rounded-2xl flex items-center gap-4 backdrop-blur-md">
            <div className="p-2.5 bg-emerald-500/10 rounded-xl border border-emerald-500/10">
              <IndianRupee className="w-5 h-5 text-emerald-400" />
            </div>
            <div>
              <p className="text-[10px] text-light-text/20 uppercase tracking-widest font-bold mb-0.5">Agreed Rate</p>
              <p className="text-2xl font-bold text-white tracking-tight leading-none">
                {formatINR(contract.agreed_rate)} {contract.jobs?.project_type === 'HOURLY' ? '/hr' : ''}
              </p>
            </div>
          </div>

          <button
            onClick={() => navigate('/freelancer/messages')}
            className="px-6 py-4.5 bg-white/5 hover:bg-white/10 border border-white/10 transition rounded-2xl text-white text-[12px] font-bold uppercase tracking-widest flex items-center gap-2 active:scale-95"
          >
            <MessageSquare size={16} className="text-accent" /> Message
          </button>
        </div>
      </div>

      {/* Main Content Areas */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 items-start">
        <div className="lg:col-span-2 space-y-6">

          {/* Submissions Section */}
          <div className="border border-white/5 rounded-2xl p-6">
            <div className="flex items-center justify-between mb-8">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-accent/10 rounded-xl flex items-center justify-center border border-accent/20">
                  <FileText className="w-5 h-5 text-accent" />
                </div>
                <h2 className="text-lg font-semibold text-white tracking-tight">Work Submissions</h2>
              </div>
              {contract.status !== 'COMPLETED' && !showSubmitForm && (
                <button
                  onClick={() => setShowSubmitForm(true)}
                  className="px-5 py-2.5 bg-white/5 text-white text-[11px] font-bold uppercase tracking-widest rounded-xl border border-white/10 hover:bg-white/10 transition-all flex items-center gap-2 active:scale-95"
                >
                  <Upload size={14} className="text-accent" /> Submit Work
                </button>
              )}
            </div>

            {showSubmitForm && (
              <div className="bg-secondary/60 border border-accent/30 rounded-2xl p-6 shadow-2xl mb-8 animate-in zoom-in-95 duration-300">
                <h3 className="text-sm font-bold text-white mb-6 uppercase tracking-widest">Submit Work for Review</h3>
                <form onSubmit={handleSubmitWork} className="space-y-5">
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-light-text/20 uppercase tracking-[0.2em] ml-1">Message / Description</label>
                    <textarea
                      value={description}
                      onChange={(e) => setDescription(e.target.value)}
                      placeholder="Describe the work you are submitting..."
                      rows="4"
                      className="w-full bg-black/20 border border-white/10 rounded-xl p-4 text-white text-[14px] focus:outline-none focus:border-accent/50 focus:ring-1 focus:ring-accent/50 resize-none transition placeholder-light-text/10"
                    ></textarea>
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-light-text/20 uppercase tracking-[0.2em] ml-1">Attachment Link (Optional)</label>
                    <input
                      type="url"
                      value={attachmentUrl}
                      onChange={(e) => setAttachmentUrl(e.target.value)}
                      placeholder="https://link-to-files.com/..."
                      className="w-full bg-black/20 border border-white/10 rounded-xl p-4 text-white text-[14px] focus:outline-none focus:border-accent/50 focus:ring-1 focus:ring-accent/50 transition placeholder-light-text/10"
                    />
                  </div>

                  <div className="flex gap-4 pt-2">
                    <button
                      type="submit"
                      disabled={submitting}
                      className="flex-1 px-6 py-4 bg-accent text-white text-[12px] font-bold uppercase tracking-widest rounded-xl hover:bg-accent/90 transition flex items-center justify-center gap-2 shadow-lg shadow-accent/20 disabled:opacity-50 active:scale-95"
                    >
                      {submitting ? <InfinityLoader size={20} /> : <Send size={16} />}
                      {submitting ? 'Submitting...' : 'Submit Work'}
                    </button>
                    <button
                      type="button"
                      onClick={() => setShowSubmitForm(false)}
                      className="px-6 py-4 bg-white/5 text-white/60 text-[12px] font-bold uppercase tracking-widest rounded-xl hover:text-white transition border border-white/10 active:scale-95"
                    >
                      Cancel
                    </button>
                  </div>
                </form>
              </div>
