                    <div className="flex justify-between items-start mb-4">
                      {getStatusBadge(sub.status)}
                      <span className="text-[11px] text-light-text/20 font-bold uppercase tracking-widest">{new Date(sub.created_at).toLocaleString()}</span>
                    </div>

                    <div className="prose prose-invert max-w-none mb-6 text-[14px] text-white/70 leading-relaxed">
