                      >
                        <Upload size={14} className="text-accent" /> View Attachment
                      </a>
                    )}

                    {sub.client_feedback && (
                      <div className="mt-6 p-5 bg-black/20 border border-white/5 rounded-2xl">
                        <p className="text-[10px] font-bold text-accent uppercase tracking-[0.2em] mb-2">Client Feedback</p>
                        <p className="text-[13px] text-light-text/60 italic leading-relaxed">"{sub.client_feedback}"</p>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Sidebar / Job Info */}
