          <div className="border border-white/5 rounded-2xl p-6">
            <h3 className="text-[10px] font-bold text-light-text/40 uppercase tracking-[0.3em] mb-8 pb-4 border-b border-white/5">Contract Info</h3>

            <div className="space-y-6">
