                </div>
              )}

              {contract.end_date && (
                <div>
                  <p className="text-[10px] text-light-text/20 font-bold uppercase tracking-[0.2em] mb-1.5">Ended Date</p>
                  <p className="text-white font-bold text-[14px] tracking-tight">{new Date(contract.end_date).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}</p>
