  }, []);

  const fetchJobs = useCallback(async (force = false) => {
    if (!isFresh) return;

    // Check if we already have data for this tab and it's fresh
    const currentData = activeTab === "SAVED JOBS" ? savedJobs : jobs;
    if (!force && isFresh(`jobs_${activeTab}`) && currentData.length > 0) return;

    setLoading(true);
    try {
      if (activeTab === "SAVED JOBS") {
        const res = await getSavedJobs();
        if (res?.success) {
          setSavedJobs(res.data || []);
          if (updateJobs) updateJobs("SAVED JOBS", res.data || []);
        }
      } else {
        const res = (activeTab === "BEST MATCHES" && userId) ? await getBestMatchJobs(userId) : await getRecentJobs();
        if (res?.success) {
          setJobs(res.data || []);
          if (updateJobs) updateJobs(activeTab, res.data || []);
        }
      }
    } catch (err) { console.error(err); } finally { setLoading(false); }
  }, [activeTab, userId, isFresh, updateJobs]); // Removed jobs, savedJobs from deps

  useEffect(() => {
    if (searchQuery.trim()) {
      const timer = setTimeout(async () => {
        setLoading(true);
        try {
          const res = await searchJobs(searchQuery);
          if (res?.success) setJobs(res.data || []);
        } catch (err) { console.error(err); } finally { setLoading(false); }
      }, 400);
      return () => clearTimeout(timer);
    } else if (searchQuery === "") {
      // Revert to normal filtering without full sync if possible
      fetchJobs();
    }
  }, [searchQuery, activeTab, fetchJobs]);

  const handleToggleSave = async (jobId, isNowSaved) => {
    setSavedJobIdsInternal(prev => {
      const next = new Set(prev);
      if (isNowSaved) next.add(jobId); else next.delete(jobId);
      return next;
    });
    if (activeTab === "SAVED JOBS" && !isNowSaved) setSavedJobs(p => p.filter(j => j.id !== jobId));
    await toggleSaveJob(jobId);
  };

  const handleManualRefresh = () => { clearCache && clearCache(); fetchJobs(true); };

  const displayedJobs = React.useMemo(() => {
    let list = searchQuery.trim() ? jobs : (activeTab === "SAVED JOBS" ? savedJobs : jobs);

    // Check if any filters are active
    const hasFilters = Object.values(filters).some(val => Array.isArray(val) ? val.length > 0 : !!val);
    if (!hasFilters) return list;

    return list.filter(job => {
      // Experience Level Match
      if (filters.experience_level?.length > 0) {
        const jobExp = (job.experience_level || "").toLowerCase();
        // Match 'Entry Level' -> 'entry'
        const matches = filters.experience_level.some(fl => jobExp.includes(fl) || fl.includes(jobExp));
        if (!matches) return false;
      }

      // Budget Type Match
      if (filters.budget_type?.length > 0) {
        const jobType = (job.budget_type || "").toLowerCase();
        // Match 'Fixed-Price' -> 'fixed', 'Hourly' -> 'hourly'
        const matches = filters.budget_type.some(fl => jobType.includes(fl) || fl.includes(jobType));
        if (!matches) return false;
      }

      // Fixed Price Budget Min Match
      if (filters.budget_min && job.budget !== null && job.budget !== undefined) {
        if (Number(job.budget) < Number(filters.budget_min)) return false;
      }

      // Fixed Price Budget Max Match
      if (filters.budget_max && job.budget !== null && job.budget !== undefined) {
        if (Number(job.budget) > Number(filters.budget_max)) return false;
      }

      return true;
    });
  }, [jobs, savedJobs, activeTab, searchQuery, filters]);

  return (
    <div className="w-full space-y-8 pb-20 font-sans tracking-tight animate-in fade-in slide-in-from-bottom-4 duration-700">
      <JobFiltersModal
        isOpen={isFilterModalOpen}
        onClose={() => setIsFilterModalOpen(false)}
        currentFilters={filters}
        onApply={setFilters}
        stats={jobStats}
      />

      {/* COMPLETED PROFILE BANNER */}
      {profile && profile.profile_completion_percentage < 100 && (
        <motion.div initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} className="bg-transparent border border-white/5 rounded-2xl p-4 flex items-center justify-between gap-6 overflow-hidden relative group hover:border-white/10 transition-all">
          <div className="flex items-center gap-4 relative z-10">
            <div className="w-11 h-11 rounded-full bg-accent/10 border border-accent/20 flex items-center justify-center font-black text-accent text-xs shadow-[0_0_15px_rgba(var(--color-accent-rgb),0.1)]">
              {profile.profile_completion_percentage}%
            </div>
            <div className="space-y-0.5">
              <h4 className="font-black text-accent tracking-widest uppercase text-[10px]">Profile Incomplete</h4>
              <p className="text-white/60 font-medium text-[13px] tracking-tight">Boost your visibility by 3x by completing your profile.</p>
            </div>
          </div>
          <a href="/freelancer/setup-profile" className="px-6 py-2 bg-transparent border border-accent/40 text-accent font-black text-[11px] uppercase tracking-widest rounded-full hover:bg-accent/10 transition-all shadow-lg shadow-accent/5">
            Continue Setup
          </a>
        </motion.div>
      )}

      {/* PREMIUM PROMO SLIDER - Compact */}
      <div className="relative group rounded-[32px] border border-white/10 overflow-hidden bg-primary/20 backdrop-blur-xl h-[300px] flex items-center">
        <div className="absolute inset-0 z-0">
          <AnimatePresence mode="wait">
            <motion.img
              key={currentAd}
              initial={{ opacity: 0, scale: 1.05 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.95 }}
              transition={{ duration: 0.8 }}
              src={ads[currentAd].image}
              className="w-full h-full object-cover"
              onError={(e) => { e.target.src = '/ad-direct-contracts.png' }}
            />
          </AnimatePresence>
          <div className="absolute inset-0 bg-gradient-to-r from-primary/95 via-primary/70 to-transparent" />
        </div>

        <div className="relative z-10 flex flex-col items-start justify-center p-16 gap-8 w-full max-w-2xl">
          <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-accent/20 border border-accent/30 text-accent text-[10px] font-black uppercase tracking-[0.2em] backdrop-blur-md">
            <Zap size={12} className="fill-accent" /> Featured Highlight
          </div>
          <div className="space-y-3">
             <h2 className="text-3xl sm:text-5xl font-black text-white leading-tight tracking-tighter">
               {ads[currentAd].title}
             </h2>
             <p className="text-white/60 text-lg font-medium max-w-lg leading-relaxed">
               {ads[currentAd].text}
             </p>
          </div>
          <button className="px-8 h-14 bg-accent text-white font-black rounded-full hover:scale-105 transition-all flex items-center gap-4 active:scale-95">
            {ads[currentAd].button} <ArrowRight size={20} />
          </button>
        </div>

        <div className="absolute bottom-10 right-16 flex gap-3 z-20">
          {ads.map((_, i) => (
            <button key={i} onClick={() => setCurrentAd(i)} className={`h-2 rounded-full transition-all duration-700 ${currentAd === i ? 'w-10 bg-accent' : 'w-3 bg-white/10 hover:bg-white/30'}`} />
          ))}
        </div>
      </div>

      {/* ANALYTICS GRID - Minimalist & Compact */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-4">
        {[
          { label: "Profile Views", value: freelancerStats.profile_views, icon: "/Icons/icons8-profile-100.png" },
          { label: "Search Presence", value: freelancerStats.search_presence, icon: "/Icons/icons8-search-64.png" },
          { label: "Total Proposals", value: freelancerStats.total_proposals, icon: "/Icons/icons8-growth-100.png" },
          { label: "Connects", value: freelancerStats.connects, icon: "/Icons/link.png" }
        ].map((item, i) => (
          <motion.div
            key={i}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: i * 0.05 }}
            className="p-4 rounded-2xl group transition-all"
          >
            <div className="flex items-center gap-3 mb-2">
              <div className="w-8 h-8 flex items-center justify-center transition-transform duration-500 group-hover:scale-110">
                <img src={item.icon} alt="" className="w-full h-full object-contain opacity-80 group-hover:opacity-100 brightness-110 transition-all" />
              </div>
              <h3 className="text-white/40 text-[9px] font-black uppercase tracking-[0.2em]">{item.label}</h3>
            </div>
            <p className="text-xl font-black text-white tracking-tight">{item.value}</p>
          </motion.div>
        ))}
      </div>

      {/* FEED CONTROLS - More compact layout */}
      <div className="space-y-6">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-8 border-b border-white/5 pb-6">
           <div className="space-y-2">
             <h2 className="text-2xl font-black text-white tracking-tight">Active Market</h2>
             <p className="text-lg text-white/40 font-medium">Real-time opportunities matched to your profile.</p>
           </div>
            <div className="flex items-center gap-6">
              <button onClick={handleManualRefresh} className="flex items-center gap-3 px-6 h-11 rounded-xl text-[10px] font-black tracking-[0.2em] text-white/40 hover:text-accent border border-white/10 hover:border-accent uppercase transition-all">
                <RefreshCw size={14} className={loading ? 'animate-spin text-accent' : ''} /> SYNC
              </button>
              <button onClick={() => setIsFilterModalOpen(true)} className="flex items-center gap-3 px-8 h-11 rounded-xl text-[10px] font-black tracking-[0.2em] text-white/40 hover:text-accent border border-white/10 hover:border-accent uppercase transition-all group">
                <Filter size={14} className="group-hover:text-accent transition-colors" /> {Object.values(filters).flat().length > 0 ? `FILTERED (${Object.values(filters).flat().length})` : 'FILTER'}
              </button>
           </div>
        </div>

        <div className="relative group">
          <Search size={18} className="absolute left-6 top-1/2 -translate-y-1/2 text-white/10 group-focus-within:text-accent transition-colors" />
          <input
            type="text"
            placeholder="Search keywords, roles, or stack..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full h-11 bg-white/[0.03] border border-white/10 rounded-xl pl-16 pr-16 text-white text-sm font-medium placeholder:text-white/10 focus:outline-none focus:border-accent/40 focus:ring-4 focus:ring-accent/5 transition-all"
          />
          {searchQuery && (
            <button onClick={() => setSearchQuery("")} className="absolute right-6 top-1/2 -translate-y-1/2 h-8 w-8 flex items-center justify-center rounded-xl bg-white/5 text-white/40 hover:text-white transition-all">
              <X size={16} />
            </button>
          )}
        </div>

        <div className="flex items-center gap-16 border-b border-white/5">
          {tabs.map((tab) => (
            <button
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`pb-6 text-[10px] font-black tracking-[0.3em] transition-all relative uppercase ${activeTab === tab ? "text-accent" : "text-white/20 hover:text-white"}`}
            >
              {tab}
              {activeTab === tab && (
                <motion.div layoutId="tabLine" className="absolute bottom-[-1px] left-0 right-0 h-1 bg-accent rounded-full" />
              )}
            </button>
          ))}
        </div>

        {/* FEED GRID */}
        <div className="space-y-6 sm:space-y-10 min-h-[500px] pt-4">
           {loading ? (
             <div className="flex flex-col items-center justify-center py-20 sm:py-32 gap-6">
                <div className="w-10 h-10 border-2 border-accent/10 border-t-accent rounded-full animate-spin" />
                <p className="text-white/20 text-[10px] font-black uppercase tracking-[0.4em] animate-pulse">Syncing Network</p>
             </div>
           ) : displayedJobs.length === 0 ? (
             <div className="text-center py-20 sm:py-32">
               <Search size={48} className="text-white/5 mx-auto mb-6" />
               <h3 className="text-lg sm:text-xl font-black text-white mb-2">Zero Matches Found</h3>
               <p className="text-white/20 text-xs sm:text-sm font-medium">Try broadening your search or sync your profile tags.</p>
             </div>
           ) : (
             <div className="space-y-6 sm:space-y-8 pb-32">
               {displayedJobs.map((job) => (
                 <JobCard key={job.id} job={job} isSaved={savedJobIdsInternal.has(job.id)} onToggleSave={handleToggleSave} />
               ))}
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

