          <p className="text-light-text/60 text-sm mt-1">
            Monitor your financial overview and withdrawal history.
          </p>
        </div>
        <button
          onClick={() => navigate('/freelancer/withdraw')}
          className="flex items-center gap-2 px-5 py-2.5 rounded-2xl border border-border text-[10px] font-bold uppercase tracking-[0.2em] text-light-text/60 hover:text-accent hover:border-accent hover:bg-accent/5 transition-all shadow-sm"
        >
          <img src="/Icons/credit.png" alt="withdraw" className="w-4 h-4 object-contain opacity-60" />
          WITHDRAW FUNDS
        </button>
      </div>

      {/* Stats Overview */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-20">
        {[
          { label: 'Available Now', value: fmt$(available), icon: '/Icons/credit.png', isImg: true, color: 'text-accent' },
          { label: 'Pending Payout', value: fmt$(pending), icon: '/Icons/growth.png', isImg: true, color: 'text-blue-400' },
          { label: 'In Review', value: fmt$(inReview), icon: '/Icons/progress.png', isImg: true, color: 'text-orange-400' },
          { label: 'Total Earned', value: fmt$(total), icon: '/Icons/rupee.png', isImg: true, color: 'text-emerald-400' }
        ].map((stat, i) => (
          <div key={i} className="border border-border p-6 rounded-2xl space-y-4 hover:border-accent/30 transition-all group shadow-sm bg-transparent">
            <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${stat.isImg ? '' : 'bg-white/5'} ${stat.color} group-hover:scale-105 transition-transform`}>
              {stat.isImg ? (
                <img src={stat.icon} alt={stat.label} className="w-12 h-12 object-contain opacity-80 group-hover:opacity-100 transition-opacity" />
              ) : (
                <stat.icon size={18} />
              )}
            </div>
            <div>
              <p className="text-[10px] font-bold uppercase tracking-[0.2em] text-light-text/30 mb-1">{stat.label}</p>
              <h4 className="text-2xl font-bold text-white tracking-tight flex items-center gap-1">
                <IndianRupee size={18} className="text-white/40" />
                {stat.value.replace('₹', '')}
              </h4>
            </div>
          </div>
        ))}
      </div>

      {/* Recent Activity Section */}
      <div className="space-y-6">
        <div className="flex items-center justify-between border-b border-border pb-4">
          <div className="flex gap-8 text-[11px] font-bold uppercase tracking-[0.2em]">
            <button className="text-accent relative pb-4">
              RECENT ACTIVITY
              <motion.div layoutId="activeTab" className="absolute bottom-0 left-0 right-0 h-[2px] bg-accent rounded-full" />
            </button>
          </div>
          <div className="flex items-center gap-3">
            <span className="text-[10px] uppercase font-bold text-light-text/40 tracking-widest">Filter:</span>
            <select
              value={statusFilter}
              onChange={(e) => { setStatusFilter(e.target.value); setPage(1); }}
              className="bg-transparent border border-border text-light-text text-[10px] font-bold uppercase tracking-widest rounded-2xl px-5 py-2.5 focus:outline-none focus:border-accent/40 transition-all appearance-none cursor-pointer hover:border-accent/20 hover:bg-accent/5"
            >
              {STATUSES.map((s) => (
                <option key={s} value={s}>{s === '' ? 'ALL STATUSES' : s.toUpperCase()}</option>
              ))}
            </select>
          </div>
        </div>

        {loading ? (
          <div className="space-y-4">
            {[1, 2, 3].map((i) => (
              <div key={i} className="animate-pulse bg-transparent border border-border rounded-2xl h-24" />
