import { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Search, Filter, Briefcase, ChevronLeft, ChevronRight
} from 'lucide-react';
import { motion } from 'framer-motion';
import { findWorkJobs, toggleSaveJob } from '../../../services/apiService';
import { toastApiError } from '../../../utils/apiErrorToast';
import { toast } from 'react-hot-toast';
import JobFilterSidebar from './JobFilterSidebar';
import JobCard from '../components/JobCard';
import { useRealtimeJobs } from '../../../context/RealtimeContext';

const TABS = [
  { key: 'best_matches', label: 'Best Matches' },
  { key: 'most_recent', label: 'Most Recent' },
  { key: 'saved', label: 'Saved Jobs' },
];

export default function FreelancerFindWork() {
  const navigate = useNavigate();
  const [tab, setTab] = useState('best_matches');
  const [jobs, setJobs] = useState([]);
  const [pagination, setPagination] = useState({ total: 0, page: 1, pages: 1 });
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState(1);
  const [savingId, setSavingId] = useState(null);
  const [showFilters, setShowFilters] = useState(false);

  const [search, setSearch] = useState('');
  const [filters, setFilters] = useState({
    category: '',
    expLevel: '',
    budgetType: '',
    minBudget: '',
    maxBudget: '',
    skills: []
  });

  const debounceRef = useRef(null);

  const load = useCallback(async (params) => {
    setLoading(true);
    try {
      const res = await findWorkJobs(params);
      setJobs(res?.data ?? []);
      setPagination(res?.pagination ?? { total: res?.data?.length || 0, page: 1, pages: 1 });
    } catch (err) {
      toastApiError(err, 'Failed to load jobs');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => {
      load({
        tab,
        page,
        search,
        category: filters.category,
        experience_level: filters.expLevel,
        budget_type: filters.budgetType,
        min_budget: filters.minBudget,
        max_budget: filters.maxBudget,
        skill: filters.skills.join(','),
        limit: 20
      });
    }, 300);
    return () => clearTimeout(debounceRef.current);
  }, [tab, page, search, filters, load]);

  useEffect(() => { setPage(1); }, [tab, search, filters]);

  // ── Real-time job updates ─────────────────────────────────────────────────
  const handleNewJob = useCallback((job) => {
    // Only inject into best_matches / most_recent tabs, not saved
    if (tab === 'saved') return;
    setJobs(prev => {
      if (prev.some(j => j.id === job.id)) return prev; // deduplicate
      return [job, ...prev];
    });
    setPagination(prev => ({ ...prev, total: prev.total + 1 }));
  }, [tab]);

  const handleJobDeleted = useCallback(({ id }) => {
    setJobs(prev => prev.filter(j => j.id !== id));
    setPagination(prev => ({ ...prev, total: Math.max(0, prev.total - 1) }));
  }, []);

  const handleJobUpdated = useCallback((job) => {
    // Remove from list if no longer open
    if ((job.status || '').toUpperCase() !== 'OPEN') {
      setJobs(prev => prev.filter(j => j.id !== job.id));
    } else {
      setJobs(prev => prev.map(j => j.id === job.id ? { ...j, ...job } : j));
    }
  }, []);

  const realtimeCallbacks = useMemo(() => ({
    onNewJob: handleNewJob,
    onJobDeleted: handleJobDeleted,
    onJobUpdated: handleJobUpdated,
  }), [handleNewJob, handleJobDeleted, handleJobUpdated]);

  useRealtimeJobs(realtimeCallbacks);

  const handleApplyFilters = () => {
    setShowFilters(false);
    setPage(1);
  };

  const handleClearFilters = () => {
    setFilters({
      category: '',
      expLevel: '',
      budgetType: '',
      minBudget: '',
      maxBudget: '',
      skills: []
    });
    setPage(1);
  };

  const handleToggleSave = async (jobId, nextIsSaved) => {
    if (savingId) return;
    setSavingId(jobId);
    try {
      const res = await toggleSaveJob(jobId);
      if (tab === 'saved' && !res.saved) {
        setJobs(prev => prev.filter(j => j.id !== jobId));
      } else {
        setJobs(prev => prev.map(j => j.id === jobId ? { ...j, is_saved: res.saved } : j));
      }
      toast.success(res.saved ? 'Job saved' : 'Job unsaved');
    } catch (err) {
      toastApiError(err, 'Could not save job');
      throw err; // Propagate to JobCard for optimistic UI revert
    } finally {
      setSavingId(null);
    }
  };

  const filterCount = [filters.category, filters.expLevel, filters.budgetType, filters.minBudget, filters.maxBudget, ...filters.skills].filter(Boolean).length;

  return (
    <div className="w-full max-w-[1400px] mx-auto px-4 sm:px-6 md:px-8 space-y-6 pb-10 animate-in fade-in slide-in-from-bottom-4 duration-500 font-sans tracking-tight">

      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-semibold text-white tracking-tight">Find Work</h1>
          <p className="text-light-text/60 text-sm mt-1">Browse jobs that match your professional skills and experience</p>
        </div>
        <button
          onClick={() => setShowFilters(true)}
          className="flex items-center justify-center gap-2 px-5 py-2.5 rounded-2xl border border-border text-[10px] font-bold uppercase tracking-[0.2em] text-light-text/60 hover:text-accent hover:border-accent hover:bg-accent/5 transition-all shadow-sm w-full sm:w-auto"
        >
          <Filter size={14} className="opacity-60" />
          FILTERS{filterCount > 0 ? ` (${filterCount})` : ''}
        </button>
      </div>

      {/* Search Bar - Clean & Centered */}
      <div className="relative">
        <Search size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-light-text/20" />
        <input
          value={search}
          onChange={e => setSearch(e.target.value)}
          placeholder="Search for jobs, skills, or keywords"
          className="w-full bg-secondary border border-border rounded-xl pl-12 pr-4 py-3.5 text-sm text-light-text focus:outline-none focus:border-accent/40 shadow-sm transition-all placeholder:text-light-text/20"
        />
      </div>

      {/* Tabs - Minimal with Blue Underline & All-Caps */}
      <div className="flex gap-10 text-[11px] font-bold uppercase tracking-[0.2em] border-b border-border overflow-x-auto no-scrollbar scroll-smooth">
        {TABS.map(t => (
          <button
            key={t.key}
            onClick={() => setTab(t.key)}
            className={`pb-4 transition-all relative whitespace-nowrap min-w-max ${tab === t.key ? 'text-accent' : 'text-light-text/40 hover:text-light-text'}`}
          >
            {t.label === 'Best Matches' ? 'BEST MATCHES' : t.label === 'Most Recent' ? 'MOST RECENT' : 'SAVED JOBS'}
            {tab === t.key && (
              <motion.div
                layoutId="activeTab"
                className="absolute bottom-0 left-0 right-0 h-[2px] bg-accent rounded-full"
              />
            )}
          </button>
        ))}
      </div>

      {!loading && <p className="text-light-text/20 text-[11px] font-bold uppercase tracking-wider">{pagination.total} jobs found</p>}

      {/* Job list */}
      {loading ? (
        <div className="space-y-4">
          {[1, 2, 3].map(i => <div key={i} className="animate-pulse bg-transparent border border-border rounded-2xl h-44" />)}
        </div>
      ) : jobs.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-20 px-4 bg-transparent border border-border rounded-2xl text-center">
          <Briefcase className="w-12 h-12 text-light-text/10 mb-3" />
          <h3 className="text-lg font-semibold text-light-text/60 mb-1">No jobs found</h3>
          <p className="text-light-text/30 text-sm">Try adjusting your filters or check back later.</p>
        </div>
      ) : (
        <div className="flex flex-col gap-6">
          {jobs.map(job => (
            <JobCard
              key={job.id}
              job={job}
              isSaved={tab === 'saved' || job.is_saved}
              onToggleSave={handleToggleSave}
            />
          ))}
        </div>
      )}

      {/* Pagination */}
      {pagination.pages > 1 && (
        <div className="flex flex-col sm:flex-row items-center justify-between gap-4 text-sm text-light-text/40 pt-8 border-t border-border">
          <span>{pagination.total} jobs</span>
          <div className="flex items-center gap-2">
            <button onClick={() => setPage(p => Math.max(1, p - 1))} disabled={page <= 1}
              className="p-2 rounded-xl border border-border bg-transparent text-light-text/40 hover:text-light-text hover:bg-hover disabled:opacity-30 transition-all">
              <ChevronLeft size={18} />
            </button>
            <div className="flex items-center gap-1 px-4 text-sm font-medium">
              Page {page} of {pagination.pages}
            </div>
            <button onClick={() => setPage(p => Math.min(pagination.pages, p + 1))} disabled={page >= pagination.pages}
              className="p-2 rounded-xl border border-border bg-transparent text-light-text/40 hover:text-light-text hover:bg-hover disabled:opacity-30 transition-all">
              <ChevronRight size={18} />
            </button>
          </div>
        </div>
      )}

      <JobFilterSidebar
        isOpen={showFilters}
        onClose={() => setShowFilters(false)}
        filters={filters}
        setFilters={setFilters}
        onApply={handleApplyFilters}
        onClear={handleClearFilters}
      />
    </div>
  );
}

import React, { useState, useEffect } from "react";
import { ShieldCheck, Lock } from "lucide-react";
import { Link } from "react-router-dom";
import axios from "axios";
import { supabase } from "../../../lib/supabase";

const API_URL = import.meta.env.VITE_API_URL || "http://localhost:5001";

const FreelancerAccountHealth = () => {
  const [tab, setTab] = useState("violations");
  const [loading, setLoading] = useState(true);

  const [statusData, setStatusData] = useState({
    profile_completion: 0,
    account_status: "GOOD"
  });

  const [scoreData, setScoreData] = useState({ health_score: 100 });
  const [enforcementData, setEnforcementData] = useState({
    violations_count: 0,
    appeals_count: 0,
    history: [],
    appeals: []
  });

  useEffect(() => {
    const fetchData = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        const token = session?.access_token || localStorage.getItem('token');
        const headers = { Authorization: `Bearer ${token}` };

        const [statusRes, scoreRes, violationsRes] = await Promise.all([
          axios.get(`${API_URL}/api/freelancer/account-health/status`, { headers }),
          axios.get(`${API_URL}/api/freelancer/account-health/score`, { headers }),
          axios.get(`${API_URL}/api/freelancer/account-health/violations`, { headers })
        ]);

        if (statusRes.data?.success) setStatusData(statusRes.data.data);
        if (scoreRes.data?.success) setScoreData(scoreRes.data.data);
        if (violationsRes.data?.success) setEnforcementData(violationsRes.data.data);

      } catch (error) {
        console.error("Failed to load account health data", error);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  if (loading) {
    return (
      <div className="flex justify-center items-center h-full pt-20">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-accent"></div>
      </div>
    );
  }

  const isRestricted = statusData.account_status === "RESTRICTED";

  return (
    <div className="w-full mx-auto px-4 sm:px-6 lg:px-8 mt-6 pb-12 space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">

      {/* TITLE */}
      <div>
        <h1 className="text-2xl font-semibold text-white tracking-tight">Account health</h1>
        <p className="text-white/50 text-sm mt-1 font-medium">
          Manage your account access and stay on track with platform Trust &amp; Safety guidelines
        </p>
      </div>

      {/* TOP CARDS */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

        {/* PLATFORM ACCESS */}
        <div className="bg-transparent border border-white/10 rounded-2xl p-8 flex justify-between items-center">
          <div className="max-w-[400px]">
            <h3 className="text-lg font-bold text-white mb-2">Platform access</h3>
            <p className="text-white/50 text-sm mb-6 leading-relaxed">
              {isRestricted
                ? "Your account currently has restricted access due to policy violations. Please review your enforcement history."
                : "Your account currently has full platform access. Continue to follow Trust & Safety policies to maintain uninterrupted access."}
            </p>
            <Link
              to="/freelancer/policies"
              className="inline-flex items-center px-5 py-2.5 bg-accent text-white text-sm font-semibold rounded-xl hover:bg-accent/90 transition-all font-bold"
            >
              Learn about our policies
            </Link>
          </div>

          <div className="flex flex-col items-center gap-3 shrink-0">
            <div className={`w-16 h-16 rounded-full bg-transparent flex items-center justify-center border border-white/10 ${isRestricted ? "border-red-500/50" : ""}`}>
              <ShieldCheck size={28} className={isRestricted ? "text-red-500" : "text-accent"} />
            </div>
            <div
              className={`w-12 h-6 rounded-full relative transition-all ${!isRestricted ? "bg-accent" : "bg-white/10"}`}
            >
              <span
                className={`absolute top-1 left-1 w-4 h-4 bg-white rounded-full transition-all ${!isRestricted ? "translate-x-6" : ""}`}
              />
            </div>
            <span className={`${isRestricted ? "text-red-500" : "text-accent"} text-xs font-bold uppercase tracking-widest`}>
              {!isRestricted ? "Full Access" : "Restricted"}
            </span>
          </div>
        </div>

        {/* ACCOUNT STANDING */}
        <div className="bg-transparent border border-white/10 rounded-2xl p-8 flex justify-between items-center">
          <div className="max-w-[400px]">
            <h3 className="text-lg font-bold text-white mb-2">Account standing</h3>
            <p className="text-white/50 text-sm leading-relaxed">
              Based on your enforcement history, your account is in {statusData.account_status.toLowerCase()} standing.
              {statusData.account_status === "GOOD" ? " Continue following best practices to maintain your status." : " Please review platform rules."}
            </p>
          </div>

          <div className="flex flex-col items-center shrink-0">
            <div className={`w-20 h-10 border-t-[5px] ${statusData.account_status === 'GOOD' ? 'border-accent' : 'border-orange-500'} rounded-t-full`} />
            <span className={`text-xs font-bold uppercase tracking-widest mt-2 ${statusData.account_status === 'GOOD' ? 'text-accent' : 'text-orange-500'}`}>
              {statusData.account_status === 'GOOD' ? 'Good' : statusData.account_status}
            </span>
          </div>
        </div>
      </div>

      {/* ENFORCEMENT HISTORY */}
      <div className="bg-transparent border border-white/10 rounded-2xl overflow-hidden">
        <div className="px-8 pt-8 pb-0">
          <h3 className="text-base font-bold text-white uppercase tracking-wider mb-6">Enforcement history</h3>

          {/* TABS */}
          <div className="flex gap-8 border-b border-white/10">
            <button
