import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { getMyProposals } from '../../../services/apiService';
import { toast } from 'react-hot-toast';
import { useRealtimeProposals } from '../../../context/RealtimeContext';
import { useDashboardCache } from '../../../context/DashboardCacheContext';
import KeepAlive from 'react-activation';
import { RefreshCw, FileText, ChevronRight, Clock, IndianRupee, Briefcase } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const MyProposals = () => {
  const navigate = useNavigate();
  const { proposals: cachedProposals, updateProposals, isFresh, clearCache } = useDashboardCache();

  const [proposals, setProposals] = React.useState(cachedProposals || []);
  const [loading, setLoading] = React.useState(!isFresh('proposals'));
  const [activeTab, setActiveTab] = React.useState('Active');

  React.useEffect(() => {
    if (!isFresh('proposals')) {
      fetchProposals();
    }
  }, [isFresh]);

  const fetchProposals = async (force = false) => {
    try {
      setLoading(true);
      const res = await getMyProposals();
      if (res.success) {
        setProposals(res.data || []);
        updateProposals(res.data || []);
      }
    } catch (err) {
      console.error('Error fetching proposals:', err);
      toast.error('Failed to load proposals');
    } finally {
      setLoading(false);
    }
  };

  // ── Real-time Status Change ────────────────────────────────────────────────
  const handleStatusChanged = React.useCallback(({ proposal_id, status }) => {
    setProposals(prev =>
      prev.map(p => p.id === proposal_id ? { ...p, status } : p)
    );
  }, []);

  useRealtimeProposals({
    onStatusChanged: handleStatusChanged,
  });

  const filteredProposals = proposals.filter(p => {
    if (activeTab === 'Active') return p.status === 'PENDING' || p.status === 'ACCEPTED';
    if (activeTab === 'Archived') return p.status === 'REJECTED' || p.status === 'WITHDRAWN';
    if (activeTab === 'Offers') return p.status === 'OFFER';
    return true;
  });

  const getStatusColor = (status) => {
    switch (status) {
      case 'ACCEPTED': return 'text-emerald-400 border-emerald-500/20 bg-emerald-500/5';
      case 'PENDING': return 'text-accent border-accent/20 bg-accent/5';
      case 'REJECTED': return 'text-red-400 border-red-500/20 bg-red-500/5';
      default: return 'text-white/20 border-white/10 bg-white/5';
    }
  };

  const handleManualRefresh = () => {
    clearCache();
    fetchProposals(true);
  };

  return (
    <KeepAlive cacheKey="FreelancerProposals">
    <div className="max-w-[1630px] mx-auto space-y-6 pb-10 animate-in ml-10 mr-6 fade-in slide-in-from-bottom-4 duration-500 font-sans tracking-tight">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-1 mb-8">
        <div>
          <h1 className="text-[28px] font-bold text-white tracking-tight leading-tight">
            My Proposals
          </h1>
          <p className="text-light-text/60 text-[14px]">
            Track and manage your submitted job applications.
          </p>
        </div>
        <button
           onClick={handleManualRefresh}
           className="flex items-center justify-center gap-2 px-4 py-2.5 rounded-full text-[12px] font-bold tracking-[0.1em] text-white/40 hover:text-accent transition-all border border-white/5 hover:border-accent uppercase bg-none group"
           title="Refresh data"
         >
           <RefreshCw size={13} className={`transition-all duration-700 ${loading ? 'animate-spin text-accent' : 'text-white/20 group-hover:text-accent'}`} />
           {loading ? 'Refreshing...' : 'Refresh'}
         </button>
      </div>

      {/* Tabs - Minimal with Blue Underline & All-Caps */}
      <div className="flex gap-10 text-[11px] font-bold uppercase tracking-[0.2em] border-b border-white/5 overflow-x-auto no-scrollbar mb-8">
        {['Active', 'Archived', 'Offers'].map((tab) => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`pb-4 transition-all relative whitespace-nowrap ${activeTab === tab ? 'text-accent' : 'text-light-text/20 hover:text-white'
              }`}
          >
            {tab.toUpperCase()}
            {activeTab === tab && (
              <motion.div
                layoutId="activeTabProposals"
                className="absolute bottom-0 left-0 right-0 h-[2px] bg-accent rounded-full shadow-[0_0_8px_rgba(var(--accent-rgb),0.5)]"
              />
            )}
          </button>
        ))}
      </div>

      <div className="space-y-6">
        {loading ? (
          <div className="bg-transparent border border-white/10 rounded-2xl divide-y divide-white/5 animate-pulse overflow-hidden">
            {[1, 2, 3].map(i => (
              <div key={i} className="h-24" />
            ))}
          </div>
        ) : filteredProposals.length === 0 ? (
          <div className="text-center py-20 bg-transparent border border-dashed border-white/10 rounded-2xl">
            <div className="w-20 h-20 bg-white/5 rounded-3xl flex items-center justify-center mx-auto mb-6 border border-white/10">
              <FileText className="w-10 h-10 text-white/10" />
            </div>
            <h3 className="text-xl font-bold text-white mb-2">No {activeTab.toLowerCase()} proposals</h3>
            <p className="text-[14px] text-light-text/40 max-w-sm mx-auto mb-8 leading-relaxed">
              {activeTab === 'Active'
                ? "You haven't submitted any proposals yet. Browse jobs and start applying to see them here!"
                : `You don't have any ${activeTab.toLowerCase()} proposals at the moment.`}
            </p>
            {activeTab === 'Active' && (
              <button
                onClick={() => navigate("/freelancer/find-work")}
                className="inline-flex items-center gap-2 px-6 py-2.5 bg-accent text-white text-[11px] font-bold uppercase tracking-widest rounded-xl hover:bg-accent/90 transition shadow-lg shadow-accent/20 active:scale-95"
              >
                Browse Jobs
                <ChevronRight size={14} />
              </button>
            )}
          </div>
        ) : (
          <div className="bg-transparent border border-white/10 rounded-2xl overflow-hidden divide-y divide-white/5">
            {filteredProposals.map((proposal) => (
              <motion.div
                key={proposal.id}
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="group p-6 hover:bg-white/[0.02] transition-colors cursor-pointer"
                onClick={() => navigate(`/freelancer/jobs/${proposal.job_id}`)}
              >
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                  <div className="space-y-4 flex-1">
                    <div className="flex items-center gap-4">
                      <span className={`px-2.5 py-1 text-[9px] font-bold uppercase tracking-[0.2em] border rounded-lg ${getStatusColor(proposal.status)}`}>
                        {proposal.status}
                      </span>
                      <div className="flex items-center gap-2 text-light-text/20 text-[10px] font-bold uppercase tracking-widest">
                        <Clock size={12} className="text-accent/40" />
                        {new Date(proposal.created_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
                      </div>
                    </div>

                    <div>
                      <h3 className="text-[18px] font-bold text-white group-hover:text-accent transition-colors tracking-tight">
                        {proposal.job?.title || 'Job Application'}
                      </h3>
                      <div className="flex items-center gap-2 mt-1.5">
                        <p className="text-[12px] text-light-text/30 font-bold uppercase tracking-widest">
                          Client:
                        </p>
                        <p className="text-[13px] text-light-text/60 font-medium">
                          {proposal.job?.client?.profiles?.name || 'Private Client'}
                        </p>
                      </div>
                    </div>
                  </div>

                  <div className="flex flex-col md:items-end gap-1">
                    <div className="flex items-baseline gap-2">
                      <span className="text-[10px] text-light-text/20 font-bold uppercase tracking-[0.2em]">Bid:</span>
                      <span className="text-2xl font-bold text-white tracking-tight flex items-center gap-1">
                        <IndianRupee size={20} className="text-accent/60" />
                        {formatINR(proposal.proposed_rate).replace('₹', '')}
                      </span>
                    </div>
                    <p className="text-[11px] text-light-text/20 font-bold uppercase tracking-widest">
                      Proposed Price
                    </p>
                  </div>

                  <div className="hidden md:flex opacity-0 group-hover:opacity-100 transition-opacity">
                    <div className="w-10 h-10 flex items-center justify-center bg-white/5 border border-white/10 rounded-xl text-white/30">
                      <ChevronRight size={18} />
                    </div>
                  </div>
                </div>
              </motion.div>
            ))}
          </div>
        )}
      </div>
    </div>
    </KeepAlive>
  );
};

export default MyProposals;

