}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import {
  Zap, TrendingUp, Eye, MousePointer, BarChart2,
  Loader2, AlertCircle, CheckCircle2, Clock
} from 'lucide-react';
import { getMyPromotions, togglePromotion, getPromotionStats } from '../../../services/apiService';
import { toastApiError } from '../../../utils/apiErrorToast';
import { toast } from 'react-hot-toast';

const fmtDate = (d) => d ? new Date(d).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }) : null;
const fmtNum = (n) => n != null ? Number(n).toLocaleString() : '—';

export default function PromotePage() {
  const navigate = useNavigate();
  const [promos, setPromos] = useState(null);
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [toggling, setToggling] = useState(null); // 'availability_badge' | 'profile_boost'
  const [error, setError] = useState(null); // error message for profile_boost

  useEffect(() => {
    Promise.all([
      getMyPromotions().catch(() => null),
      getPromotionStats().catch(() => null),
    ]).then(([p, s]) => {
      setPromos(p?.data ?? p);
      setStats(s?.data ?? s);
    }).finally(() => setLoading(false));
  }, []);

  const handleToggle = async (type) => {
    setToggling(type);
    setError(null);
    try {
      const res = await togglePromotion(type);
      const updated = res?.data ?? res;
      setPromos(prev => ({ ...prev, [type]: updated }));
      toast.success(updated?.is_active ? 'Activated' : 'Deactivated');
    } catch (err) {
      const msg = err?.response?.data?.message || err?.message || 'Failed';
      if (type === 'profile_boost' && err?.response?.status === 400) {
        setError(msg);
      } else {
        toastApiError(err, msg);
      }
    } finally {
      setToggling(null);
    }
  };

  const badge = promos?.availability_badge;
  const boost = promos?.profile_boost;

  const ToggleSwitch = ({ isActive, onToggle, isToggling }) => (
    <button
      onClick={onToggle}
      disabled={isToggling}
      className={`relative w-9 h-5 rounded-full transition-colors duration-300 focus:outline-none ${isActive ? 'bg-accent' : 'bg-white/10'
        } ${isToggling ? 'opacity-50 cursor-wait' : 'cursor-pointer hover:bg-white/15'}`}
    >
      <motion.div
        animate={{ x: isActive ? 18 : 2 }}
        initial={false}
        transition={{ type: "spring", stiffness: 500, damping: 30 }}
        className="absolute top-1/2 -translate-y-1/2 w-4 h-4 bg-white rounded-full shadow-sm"
      />
    </button>
  );

  return (
    <div className="max-w-[1630px] mx-auto space-y-6 pb-10 animate-in ml-10 mr-6 fade-in slide-in-from-bottom-4 duration-500 font-sans tracking-tight">
      {/* Header matching FindWork */}
      <div className="flex flex-col gap-1">
        <h1 className="text-2xl font-semibold text-white tracking-tight">Promote with Ads</h1>
        <p className="text-light-text/60 text-sm">Increase visibility and reach more clients</p>
      </div>

      {/* Performance Stats Strip */}
      {stats && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
          {[
            { label: 'Total Impressions', value: fmtNum(stats.total_impressions), Icon: Eye },
            { label: 'Total Clicks', value: fmtNum(stats.total_clicks), Icon: MousePointer },
            { label: 'Click Through Rate', value: stats.ctr != null ? `${Number(stats.ctr).toFixed(2)}%` : '—', Icon: TrendingUp },
          ].map(({ label, value, Icon }) => (
            <div key={label} className="p-5 border border-white/5 rounded-2xl flex flex-col gap-2 group hover:border-accent/30 transition-all">
              <div className="flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest text-light-text/30 group-hover:text-light-text/50 transition-colors">
                <Icon size={12} className="text-accent/40" />
                {label}
              </div>
              <div className="text-2xl font-bold text-white tracking-tight">{value}</div>
            </div>
          ))}
        </div>
      )}

      {/* Promotions List (Single Column) */}
      <div className="flex flex-col gap-6">
        <div className="flex items-center gap-4 mb-2">
          <h2 className="text-[10px] font-bold uppercase tracking-[0.3em] text-light-text/40">AVAILABLE PROMOTIONS</h2>
          <div className="h-[1px] flex-1 bg-white/5"></div>
        </div>

        {loading ? (
          [1, 2].map(i => <div key={i} className="animate-pulse bg-secondary/50 border border-white/5 rounded-2xl h-44" />)
        ) : (
          <>
            {/* Availability Badge Card */}
            <div className={`p-6 border ${badge?.is_active ? 'border-accent' : 'border-white/10'} rounded-2xl transition-all group shadow-sm `}>
              <div className="flex justify-between items-start mb-5">
                <div className="flex items-center gap-3">
                  <span className="text-[10px] font-bold uppercase tracking-widest text-light-text/40">
                    AVAILABILITY PROMOTION
                  </span>
                </div>
                <div className="flex items-center gap-4">
                  <span className="px-2.5 py-1 bg-white/5 border border-white/5 rounded-lg text-[9px] font-bold uppercase tracking-wider text-light-text/30">
                    FREE SERVICE
                  </span>
                  <ToggleSwitch
                    isActive={badge?.is_active}
                    onToggle={() => handleToggle('availability_badge')}
                    isToggling={toggling === 'availability_badge'}
                  />
                </div>
              </div>

              <h3 className="text-lg font-semibold text-white group-hover:text-accent transition-colors tracking-tight leading-snug mb-3">
                Availability Badge
              </h3>

              <p className="text-[13.5px] text-light-text/50 mb-7 leading-relaxed font-normal max-w-2xl">
                Show clients you're actively looking for work and can start immediately. Your profile will stand out in search results with a specialized badge.
              </p>

              <div className="flex items-center gap-6 pt-5 border-t border-white/5 text-[10px] font-bold uppercase tracking-widest text-light-text/30">
                {badge?.is_active ? (
                  <>
                    <span className="flex items-center gap-1.5 text-accent/60">
                      <CheckCircle2 size={13} /> {fmtDate(badge.expires_at)}
                    </span>
                    <span className="flex items-center gap-1.5">
                      <Eye size={13} /> {fmtNum(badge.impressions)} IMPRESSIONS
                    </span>
                    <span className="flex items-center gap-1.5">
                      <MousePointer size={13} /> {fmtNum(badge.clicks)} CLICKS
                    </span>
                  </>
                ) : (
                  <span className="text-light-text/20 italic">PROMOTION INACTIVE — ENABLE TO SEE LIVE STATS</span>
                )}
              </div>
            </div>

            {/* Profile Boost Card */}
            <div className={`p-6 border ${boost?.is_active ? 'border-accent' : 'border-white/10'} rounded-2xl transition-all group shadow-sm`}>
              <div className="flex justify-between items-start mb-5">
                <div className="flex items-center gap-3">
                  <span className="text-[10px] font-bold uppercase tracking-widest text-light-text/40">
                    PROFILE BOOST
                  </span>
                </div>
                <div className="flex items-center gap-4">
                  <span className="px-2.5 py-1 bg-accent/10 border border-accent/20 rounded-lg text-[9px] font-bold uppercase tracking-wider text-accent font-extrabold">
                    10 CONNECTS
                  </span>
                  <ToggleSwitch
                    isActive={boost?.is_active}
                    onToggle={() => handleToggle('profile_boost')}
                    isToggling={toggling === 'profile_boost'}
                  />
                </div>
              </div>

              <h3 className="text-lg font-semibold text-white group-hover:text-accent transition-colors tracking-tight leading-snug mb-3">
                Ads Boost Profile
              </h3>

              <p className="text-[13.5px] text-light-text/50 mb-7 leading-relaxed font-normal max-w-2xl">
                Elevate your profile to the top of search results for a 30-day period. This significantly increases client reach and invitation probabilities.
              </p>

              {error && (
                <div className="flex items-center gap-2 mb-6 p-4 bg-red-500/5 rounded-2xl text-xs text-red-300 border border-red-500/10">
                  <AlertCircle size={14} className="shrink-0" />
                  <span>{error}</span>
                  <button onClick={() => navigate('/freelancer/buy-connects')}
                    className="underline hover:text-red-200 transition ml-auto font-bold uppercase tracking-widest text-[9px]">
                    Buy connects
                  </button>
                </div>
              )}

              <div className="flex items-center gap-6 pt-5 border-t border-white/5 text-[10px] font-bold uppercase tracking-widest text-light-text/30">
                {boost?.is_active ? (
                  <>
                    <span className="flex items-center gap-1.5 text-accent/60">
                      <Clock size={13} /> {fmtDate(boost.expires_at)}
                    </span>
                    <span className="flex items-center gap-1.5">
                      <Eye size={13} /> {fmtNum(boost.impressions)} IMPRESSIONS
                    </span>
                    <span className="flex items-center gap-1.5">
                      <MousePointer size={13} /> {fmtNum(boost.clicks)} CLICKS
                    </span>
                  </>
                ) : (
                  <span className="text-light-text/20 italic">BOOST INACTIVE — ENABLE TO FEATURE PROFILE</span>
                )}
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { Briefcase, ChevronRight } from 'lucide-react';
import { findWorkJobs, toggleSaveJob } from '../../../services/apiService';
import { toastApiError } from '../../../utils/apiErrorToast';
import { toast } from 'react-hot-toast';
import JobCard from '../components/JobCard';

export default function SavedJobs() {
  const navigate = useNavigate();
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [savingId, setSavingId] = useState(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const res = await findWorkJobs({ tab: 'saved', limit: 50 });
      setJobs(res?.data ?? []);
    } catch (err) {
      toastApiError(err, 'Could not load saved jobs');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { load(); }, [load]);

  const handleToggleSave = async (jobId, nextIsSaved) => {
    if (savingId) return;
    setSavingId(jobId);
    try {
      const res = await toggleSaveJob(jobId);
      // Since this is the SavedJobs page, if it's unsaved, we remove it from the list
      if (!res.saved) {
        setJobs(prev => prev.filter(j => j.id !== jobId));
      }
      toast.success(res.saved ? 'Job saved' : 'Job unsaved');
    } catch (err) {
      toastApiError(err, 'Could not update saved job');
      throw err; // Propagate to JobCard for optimistic UI revert
    } finally {
      setSavingId(null);
    }
  };

  return (
    <div className="max-w-[1630px] mx-auto space-y-6 pb-10 animate-in ml-10 mr-6 fade-in slide-in-from-bottom-4 duration-500 font-sans tracking-tight">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-semibold text-white tracking-tight">Saved Jobs</h1>
          <p className="text-light-text/60 text-sm mt-1">Jobs you've bookmarked to apply to later.</p>
        </div>
      </div>

      {!loading && (
        <p className="text-light-text/20 text-[11px] font-bold uppercase tracking-wider">
          {jobs.length} job{jobs.length !== 1 ? 's' : ''} saved
        </p>
      )}

      {/* Job list */}
      {loading ? (
        <div className="space-y-6">
          {[1, 2, 3].map(i => (
            <div key={i} className="animate-pulse bg-transparent border border-white/10 rounded-[32px] h-48" />
          ))}
        </div>
      ) : jobs.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-24 bg-transparent border border-dashed border-white/10 rounded-[40px] text-center">
          <div className="w-20 h-20 bg-accent/10 rounded-3xl flex items-center justify-center mx-auto mb-8 border border-accent/20">
            <Briefcase className="w-10 h-10 text-accent" />
          </div>
          <h3 className="text-xl font-bold text-light-text/30 mb-2 uppercase tracking-widest leading-none">No saved jobs yet</h3>
          <p className="text-light-text/20 text-sm mb-10 max-w-xs mx-auto font-medium">Browse jobs and save the ones you're interested in to see them here.</p>
          <button
            onClick={() => navigate('/freelancer/find-work')}
            className="flex items-center h-14 gap-3 px-10 bg-accent text-primary rounded-2xl text-[11px] font-bold uppercase tracking-[0.2em] hover:bg-accent/90 transition shadow-xl shadow-accent/20"
          >
            Browse Jobs <ChevronRight size={16} />
          </button>
        </div>
      ) : (
        <div className="flex flex-col gap-8">
          {jobs.map(job => (
            <JobCard
              key={job.id}
              job={job}
              isSaved={true}
              onToggleSave={handleToggleSave}
            />
          ))}
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import {
  ArrowLeft, Upload, X, ChevronDown,
  ToggleLeft, ToggleRight, Plus, Trash2
} from 'lucide-react';
import { createService, updateService, getMyServices, uploadServiceImage } from '../../../services/apiService';
import { toastApiError } from '../../../utils/apiErrorToast';
import { toast } from 'react-hot-toast';
import { supabase } from '../../../lib/supabase';
import InfinityLoader from '../../common/InfinityLoader';

const API_URL = import.meta.env.VITE_API_URL || 'http://localhost:5001';

const CATEGORIES = [
  'Development & IT', 'Design & Creative', 'Writing & Translation',
  'Marketing & SEO', 'AI Services', 'Finance & Accounting', 'Legal', 'HR',
];

const EMPTY_FORM = {
  title: '', description: '', category: '', price: '', delivery_days: '',
  revisions: '', tags: [], images: ['', '', ''], is_active: true,
  packages: [], faqs: [],
};

const inputCls = "w-full bg-transparent border border-white/10 rounded-xl px-4 py-3 text-white text-sm focus:outline-none focus:border-accent/50 placeholder-white/20 transition";
const labelCls = "block text-[11px] font-bold uppercase tracking-[0.2em] text-white/40 mb-2";

// â”€â”€â”€ Custom Select â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function CustomSelect({ value, onChange, options, placeholder }) {
  const [open, setOpen] = useState(false);
  return (
    <div className="relative">
      <button type="button" onClick={() => setOpen(p => !p)}
        className={`w-full flex items-center justify-between ${inputCls} text-left`}>
        <span className={value ? 'text-white' : 'text-white/20'}>{value || placeholder}</span>
        <ChevronDown size={15} className={`text-white/30 transition-transform shrink-0 ${open ? 'rotate-180' : ''}`} />
      </button>
      {open && (
        <>
          <div className="fixed inset-0 z-40" onClick={() => setOpen(false)} />
          <div className="absolute top-full left-0 right-0 mt-1 bg-secondary border border-border rounded-xl shadow-2xl z-50 overflow-hidden max-h-56 overflow-y-auto">
            {options.map(opt => (
              <button key={opt} type="button" onClick={() => { onChange(opt); setOpen(false); }}
                className={`w-full text-left px-4 py-2.5 text-sm transition hover:bg-white/5 ${value === opt ? 'text-accent bg-accent/5' : 'text-white/70'}`}>
                {opt}
              </button>
            ))}
          </div>
        </>
      )}
    </div>
  );
}

// â”€â”€â”€ Image Upload Slot â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function ImageSlot({ url, onUrl }) {
  const [uploading, setUploading] = useState(false);
  const [showUrl, setShowUrl] = useState(false);
  const ref = useRef(null);

  const handleFile = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setUploading(true);
    try {
      const data = await uploadServiceImage(file);
      const u = data?.data?.url ?? data?.url;
      if (u) {
        onUrl(u);
        toast.success('Image uploaded');
      } else {
        toast.error('No URL returned');
      }
    } catch (err) {
      toastApiError(err, 'Upload failed');
    } finally {
      setUploading(false);
      e.target.value = '';
    }
  };

  return (
    <div className="flex flex-col gap-2">
      <div className="relative aspect-video rounded-xl overflow-hidden border-2 border-dashed border-white/10 hover:border-accent/40 transition bg-white/[0.02] cursor-pointer"
        onClick={() => !url && ref.current?.click()}>
        {url ? (
          <>
            <img src={url} alt="" className="w-full h-full object-cover" />
            <div className="absolute inset-0 bg-black/50 opacity-0 hover:opacity-100 transition flex items-center justify-center gap-3">
              <button type="button" onClick={e => { e.stopPropagation(); ref.current?.click(); }}
                className="p-2 bg-white/20 hover:bg-white/30 rounded-lg transition">
                <Upload size={16} className="text-white" />
              </button>
              <button type="button" onClick={e => { e.stopPropagation(); onUrl(''); }}
                className="p-2 bg-red-500/40 hover:bg-red-500/60 rounded-lg transition">
                <X size={16} className="text-white" />
              </button>
            </div>
          </>
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center gap-2 py-6">
            {uploading
              ? <InfinityLoader size={20} />
              : <><Upload size={22} className="text-white/20" /><span className="text-white/20 text-xs">Click to upload</span></>
            }
          </div>
        )}
      </div>
      <button type="button" onClick={() => setShowUrl(p => !p)}
        className="text-white/20 hover:text-white/40 text-xs text-center transition">
        {showUrl ? 'Hide URL' : 'or paste URL'}
      </button>
      {showUrl && (
        <input placeholder="https://..." className={inputCls + ' text-xs py-2'}
          defaultValue={url}
          onBlur={e => { if (e.target.value) onUrl(e.target.value); }}
          onKeyDown={e => { if (e.key === 'Enter' && e.target.value) { onUrl(e.target.value); setShowUrl(false); } }} />
      )}
      <input ref={ref} type="file" accept="image/*" className="hidden" onChange={handleFile} />
    </div>
  );
}

// â”€â”€â”€ Section Card â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
