const inputCls = "w-full bg-hover border border-border rounded-xl px-4 py-3 text-light-text text-sm placeholder-light-text/20 focus:outline-none focus:border-accent/50 transition";

// ── Withdrawal Modal ──────────────────────────────────────────
function WithdrawalModal({ available, onClose, onSuccess }) {
  const [amount, setAmount] = useState('');
  const [method, setMethod] = useState('bank_transfer');
  const [details, setDetails] = useState({});
  const [submitting, setSubmitting] = useState(false);
  const [errors, setErrors] = useState({});

  const setDetail = (k) => (e) => setDetails(p => ({ ...p, [k]: e.target.value }));

  const validate = () => {
    const e = {};
    const amt = parseFloat(amount);
    const minINR = 10 * USD_TO_INR;
    if (!amount || isNaN(amt)) e.amount = 'Enter a valid amount';
    else if (amt < minINR) e.amount = `Minimum withdrawal is ${formatINR(10)}`;
    else if (amt > parseFloat(available || 0) * USD_TO_INR) e.amount = `Maximum is ${formatINR(available)}`;
    if (method === 'bank_transfer') {
      if (!details.bank_name?.trim()) e.bank_name = 'Required';
      if (!details.account_number?.trim()) e.account_number = 'Required';
      if (!details.routing_number?.trim()) e.routing_number = 'Required';
    } else if (method === 'paypal') {
      if (!details.paypal_email?.trim()) e.paypal_email = 'Required';
    } else if (method === 'stripe') {
      if (!details.stripe_account_id?.trim()) e.stripe_account_id = 'Required';
    }
    return e;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }
    setSubmitting(true);
    try {
      const payload = { 
        amount: convertToUSD(amount), 
        method, 
        account_details: details 
      };
      const res = await requestWithdrawal(payload);
      toast.success('Withdrawal request submitted');
      onSuccess(res?.data ?? res);
      onClose();
    } catch (err) {
      toastApiError(err, 'Failed to submit withdrawal');
    } finally {
      setSubmitting(false);
    }
  };

  const Field = ({ label, field, placeholder, type = 'text' }) => (
    <div>
      <label className="block text-xs text-white/40 mb-1.5">{label}</label>
      <input type={type} value={details[field] || ''} onChange={setDetail(field)}
        placeholder={placeholder} className={inputCls} />
      {errors[field] && <p className="text-red-400 text-xs mt-1">{errors[field]}</p>}
    </div>
  );

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
      <div className="bg-secondary border border-border rounded-2xl w-full max-w-md shadow-2xl">
        <div className="flex items-center justify-between px-6 py-4 border-b border-border">
          <h2 className="text-light-text font-semibold">Request Withdrawal</h2>
          <button onClick={onClose} className="text-light-text/40 hover:text-light-text transition"><X size={18} /></button>
        </div>

        <form onSubmit={handleSubmit} className="px-6 py-5 space-y-5">
          {/* Amount */}
          <div>
            <label className="block text-xs text-white/40 mb-1.5">Amount (₹)</label>
            <div className="relative">
              <IndianRupee size={14} className="absolute left-4 top-1/2 -translate-y-1/2 text-white/30" />
              <input type="number" min={10 * USD_TO_INR} step="1" max={Math.floor(available * USD_TO_INR)}
                value={amount} onChange={e => { setAmount(e.target.value); setErrors(p => ({ ...p, amount: undefined })); }}
                placeholder="0.00" className={inputCls + ' pl-10'} />
            </div>
            {errors.amount && <p className="text-red-400 text-xs mt-1">{errors.amount}</p>}
            <p className="text-white/30 text-xs mt-1">Available: {fmt$(available)}</p>
          </div>

          {/* Method */}
          <div>
            <label className="block text-xs text-white/40 mb-2">Withdrawal Method</label>
            <div className="grid grid-cols-3 gap-2">
              {METHODS.map(({ value, label, Icon }) => (
                <button key={value} type="button" onClick={() => { setMethod(value); setDetails({}); setErrors({}); }}
                  className={`flex flex-col items-center gap-1.5 py-3 rounded-xl border text-xs font-medium transition ${method === value ? 'border-accent/50 bg-accent/10 text-accent' : 'border-white/10 text-white/50 hover:text-white hover:border-white/20'}`}>
                  <Icon size={16} />
                  {label}
                </button>
              ))}
            </div>
          </div>

          {/* Account details */}
          {method === 'bank_transfer' && (
            <div className="space-y-3">
              <Field label="Bank Name" field="bank_name" placeholder="e.g. Chase Bank" />
              <Field label="Account Number" field="account_number" placeholder="••••••••" />
              <Field label="IFSC / Routing Number" field="routing_number" placeholder="e.g. 021000021" />
            </div>
          )}
          {method === 'paypal' && (
            <Field label="PayPal Email" field="paypal_email" placeholder="you@example.com" type="email" />
          )}
          {method === 'stripe' && (
            <Field label="Stripe Account ID" field="stripe_account_id" placeholder="acct_..." />
          )}

          <div className="flex gap-3 pt-1">
            <button type="button" onClick={onClose}
              className="flex-1 py-2.5 rounded-xl border border-border text-light-text/60 hover:text-light-text text-sm transition">
              Cancel
            </button>
            <button type="submit" disabled={submitting}
              className="flex-1 py-2.5 rounded-xl bg-accent text-white text-sm font-medium hover:bg-accent/90 transition disabled:opacity-50 flex items-center justify-center gap-2">
              {submitting && <InfinityLoader size={20} />}
              Submit Request
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

// ── Main Page ─────────────────────────────────────────────────
export default function WithdrawalsPage() {
  const [withdrawals, setWithdrawals] = useState([]);
  const [balance, setBalance] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [cancellingId, setCancellingId] = useState(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const res = await getWithdrawals();
      const d = res?.data ?? res;
      setWithdrawals(d?.withdrawals ?? d ?? []);
      setBalance(d?.balance ?? null);
    } catch (err) {
      toastApiError(err, 'Could not load withdrawals');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { load(); }, [load]);

  const handleCancel = async (id) => {
    setCancellingId(id);
    try {
      await cancelWithdrawal(id);
      setWithdrawals(prev => prev.map(w => w.id === id ? { ...w, status: 'CANCELLED' } : w));
      toast.success('Withdrawal cancelled');
    } catch (err) {
      toastApiError(err, 'Failed to cancel');
    } finally {
      setCancellingId(null);
    }
  };

  const handleCreated = (newW) => {
    if (newW?.id) setWithdrawals(prev => [newW, ...prev]);
    load(); // re-fetch to get updated balance
