        </div>
        <button onClick={() => setShowModal(true)}
          className="flex items-center gap-2 px-5 py-2.5 rounded-2xl border border-border text-[10px] font-bold uppercase tracking-[0.2em] text-light-text/60 hover:text-accent hover:border-accent hover:bg-accent/5 transition-all shadow-sm">
          <Plus size={14} /> REQUEST WITHDRAWAL
        </button>
      </div>

      {/* Balance cards */}
      {loading ? (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {[1, 2, 3, 4].map(i => <div key={i} className="animate-pulse bg-transparent border border-border rounded-2xl h-24" />)}
        </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
