    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      className="max-w-[1630px] mx-auto space-y-6 pb-10 animate-in ml-10 mr-6 fade-in slide-in-from-bottom-4 duration-500 font-sans tracking-tight"
