          <p className="text-light-text/60 text-sm mt-1">
            Log and track your hourly progress on active projects.
          </p>
        </div>
        <button
          onClick={() => setShowAddForm(!showAddForm)}
          className="px-8 h-12 bg-accent hover:bg-accent/90 text-white text-[11px] font-bold uppercase tracking-[0.2em] rounded-2xl transition shadow-xl shadow-accent/20 active:scale-[0.98]"
        >
          {showAddForm ? 'View Summary' : 'Log Hours'}
        </button>
      </div>

        {/* Stats Row - 4 Cards Style like Earnings with Icon Containers */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-16">
          {[
            { label: 'Total Period Hours', value: `${totalHours.toFixed(1)} hrs`, color: 'text-accent' },
            { label: 'Estimated Earnings', value: formatINR(estimatedEarnings), color: 'text-blue-400' },
