    if (!name.trim() || !text.trim() || rating === 0) {
      toast.error("Please fill in all fields and select a rating");
      return;
    }

    try {
      setSubmitting(true);
      const res = await axios.post(`${API_URL}/api/site-reviews`, {
        name: name.trim(),
        rating,
        comment: text.trim()
      });

      if (res.data.success) {
        toast.success("Review submitted successfully!");
        setName("");
        setText("");
        setRating(0);
        // Refresh reviews from DB
        await fetchReviews();
      }
    } catch (error) {
      const msg = error.response?.data?.message || "Failed to submit review";
      toast.error(msg);
    } finally {
      setSubmitting(false);
    }
