      <motion.h2
        initial={{ y: 40, opacity: 0 }}
        whileInView={{ y: 0, opacity: 1 }}
        transition={{ duration: 0.6 }}
        className="text-4xl font-semibold mb-8"
      >
        What Our Users Say
      </motion.h2>

      {/* Average Rating */}
      <motion.div
        initial={{ opacity: 0 }}
        whileInView={{ opacity: 1 }}
        transition={{ delay: 0.2 }}
        className="flex items-center gap-6 mb-14"
      >
        <span className="text-5xl font-bold text-white">
          {avgRating > 0 ? avgRating.toFixed(1) : "â€”"}
        </span>

        <div className="flex text-accent text-4xl gap-2">
          {[1, 2, 3, 4, 5].map((star) => (
            <FaStar
              key={star}
              className={
                star <= Math.floor(avgRating)
                  ? "text-accent"
                  : "text-white/20"
              }
            />
          ))}
        </div>

        <span className="text-white/60 text-2xl">
          ({totalReviews} {totalReviews === 1 ? "review" : "reviews"})
        </span>
      </motion.div>

      {/* Reviews List */}
      <div className="space-y-6 mb-16">
        {loading ? (
          <div className="flex justify-center items-center h-40">
            <InfinityLoader size={30} />
          </div>
        ) : reviews.length > 0 ? (
          reviews.map((review, index) => (
            <motion.div
              key={review.id}
