import React, { createContext, useContext, useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { supabase } from '../lib/supabase';
import axios from 'axios';
import toast from 'react-hot-toast';
import { ROLES, ADMIN_ROLES } from '../utils/roles';
import { logger } from '../utils/logger';

const AuthContext = createContext();

const API_URL = import.meta.env.VITE_API_URL || 'http://localhost:5001';

export function AuthProvider({ children }) {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);
    const [role, setRole] = useState(null);
    const [profile, setProfile] = useState(null);
    const [isAdmin, setIsAdmin] = useState(false);
    const [isAuthenticated, setIsAuthenticated] = useState(false);
    const syncInProgress = useRef(false);
    const skipSync = useRef(false);

    /**
     * Helper to determine dashboard route based on role
     */
    const getDashboardRoute = useCallback((userRole, userProfile) => {
        if (!userRole) return '/select-role';

        if (ADMIN_ROLES.includes(userRole)) return '/admin/dashboard';

        if (userRole === 'CLIENT') return '/client/dashboard';

        if (userRole === 'FREELANCER') {
            const isProfileCompleted =
                userProfile?.profile_completion_percentage >= 100 ||
                userProfile?.profileCompleted === true ||
                userProfile?.profile_completed === true ||
                userProfile?.profile_status === 'COMPLETED' ||
                userProfile?.is_profile_complete === true ||
                // Also check nested profile object
                userProfile?.profile?.profileCompleted === true ||
                userProfile?.profile?.profile_completed === true ||
                userProfile?.profile?.profile_completion_percentage >= 100;
            return isProfileCompleted ? '/freelancer/dashboard' : '/freelancer/setup-profile';
        }
        // Default fallback for authenticated users with no specific role match
        return '/select-role';
    }, []);

    /**
     * Sync user role and profile with backend
     */
    const syncUserRole = useCallback(async (session, intendedRole = null) => {
        if (syncInProgress.current || !session) return;
        // Don't overwrite role from a direct login with OAuth sync
        if (localStorage.getItem('login_source') === 'direct') {
            logger.log('[AuthContext] Skipping sync — direct login role is authoritative');
            return;
        }
        syncInProgress.current = true;

        try {
            const roleToSync = intendedRole || localStorage.getItem('oauth_intended_role');

            const response = await axios.post(`${API_URL}/api/auth/sync-oauth`, 
                { role: roleToSync || undefined }, 
                { headers: { Authorization: `Bearer ${session.access_token}` } }
            );

            if (response.data.success) {
                const { role: fetchedRole, profile: fetchedProfile } = response.data.data;

                setRole(fetchedRole);
                setProfile(fetchedProfile);
                setIsAdmin(ADMIN_ROLES.includes(fetchedRole));

                // Persist minimal state for hydration
                localStorage.setItem('user_role', fetchedRole);
                localStorage.setItem('user_profile', JSON.stringify(fetchedProfile));

                if (roleToSync) localStorage.removeItem('oauth_intended_role');
                return { role: fetchedRole, profile: fetchedProfile };
            }
        } catch (error) {
            logger.error('[AuthContext] Role sync failed:', error);
            if (error.response?.status === 401) logout();
        } finally {
            syncInProgress.current = false;
        }
    }, []);

    const login = async (email, password) => {
        try {
            // ── Always clear any stale session before logging in ──────────
            // This prevents a CLIENT session from persisting when a FREELANCER
            // logs in, or vice versa (the core cause of the role mismatch bug).
            try {
                await supabase.auth.signOut();
            } catch { /* ignore signout errors */ }
            localStorage.removeItem('user_role');
            localStorage.removeItem('user_profile');
            // Cleanup existing tokens
            sessionStorage.removeItem('token');
            localStorage.removeItem('login_source');


            const response = await axios.post(`${API_URL}/api/auth/login`, { email, password });

            if (response.data.success) {
                const data = response.data.data;
                if (!data || !data.session || !data.user) {
                    throw new Error('Invalid response from server. Please try again.');
                }
                const { session, user: userData, role: userRole } = data;
                const profileData = userData?.profile || null;
                const resolvedRole = userRole || userData?.role || null;

                skipSync.current = true;
                await supabase.auth.setSession(session);

                // ── Standardize Token Persistence ─────────────────────
                if (session?.access_token) {
                    localStorage.setItem('token', session.access_token);
                    sessionStorage.setItem('token', session.access_token);
                }

                // ── Update Global State IMMEDIATELY ─────────────────
                setUser(userData);
                setRole(resolvedRole);
                setProfile(profileData);
                setIsAdmin(ADMIN_ROLES.includes(resolvedRole));
                setIsAuthenticated(true);

                localStorage.setItem('user_role', resolvedRole);
                localStorage.setItem('user_profile', JSON.stringify(profileData));
                localStorage.setItem('user', JSON.stringify({ ...userData, role: resolvedRole }));

                // Mark that we just did a direct login — block ALL syncs for this session
                localStorage.setItem('login_source', 'direct');


                return response.data;
            }
        } catch (error) {
            const message = error.response?.data?.message || 
                (error.code === 'ERR_NETWORK' ? 'Unable to connect to server. Please check your connection.' : 'Login failed');
            toast.error(message);
            throw new Error(message);
        }
    };

    const updateUserRole = async (newRole) => {
        try {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error('No active session');

            const response = await axios.put(`${API_URL}/api/auth/update-role`, 
                { role: newRole },
                { headers: { Authorization: `Bearer ${session.access_token}` } }
            );

            if (response.data.success) {
                const { role: updatedRole, profile: updatedProfile } = response.data.data;
                setRole(updatedRole);
                setProfile(updatedProfile);
                setIsAdmin(ADMIN_ROLES.includes(updatedRole));

                // Update user object locally
                const updatedUser = user ? { ...user, role: updatedRole } : { id: session.user.id, email: session.user.email, role: updatedRole };
                setUser(updatedUser);

                localStorage.setItem('user_role', updatedRole);
                localStorage.setItem('user_profile', JSON.stringify(updatedProfile));
                localStorage.setItem('user', JSON.stringify(updatedUser));

                toast.success(`Account set up as ${updatedRole}`);
                return true;
            }
            return false;
        } catch (error) {
            logger.error('[AuthContext] Update role failed:', error);
            const message = error.response?.data?.message || 'Failed to update role';
            toast.error(message);
            return false;
        }
    };

    const logout = async () => {
        try {
            await supabase.auth.signOut();
        } catch (err) {
            logger.error('[AuthContext] SignOut error:', err);
        } finally {
            setUser(null);
            setRole(null);
            setProfile(null);
            setIsAdmin(false);
            setIsAuthenticated(false);
            localStorage.removeItem('user_role');
            localStorage.removeItem('user_profile');
            localStorage.removeItem('user');
            localStorage.removeItem('token');
            localStorage.removeItem('oauth_intended_role');
            sessionStorage.removeItem('token');
        }
    };

    useEffect(() => {
        const initAuth = async () => {
            try {
                const { data, error } = await supabase.auth.getSession();

                if (error) {
                    logger.warn('[AuthContext] Session fetch error:', error.message);
                    if (error.message.includes('Invalid Refresh Token')) {
                        await logout();
                    }
                    setLoading(false);
                    return;
                }

                const session = data?.session;

                if (session) {
                    // Initial hydration from localStorage
                    const storedRole = localStorage.getItem('user_role');
                    const storedProfile = localStorage.getItem('user_profile');
                    const storedUser = localStorage.getItem('user');

                    if (storedUser) {
                        try {
                            const parsedUser = JSON.parse(storedUser);
                            setUser(parsedUser);
                        } catch (e) {
                            setUser(session.user);
                        }
                    } else {
                        setUser(session.user);
                    }

                    if (storedRole) {
                        setRole(storedRole);
                        setIsAdmin(ADMIN_ROLES.includes(storedRole));
                    }

                    if (storedProfile) {
                        try {
                            setProfile(JSON.parse(storedProfile));
                        } catch (e) {
                            logger.error('[AuthContext] Profile parse error:', e);
                        }
                    }

                    setIsAuthenticated(true);

                    // Only sync with backend if this was NOT a direct login
                    const isDirectLogin = localStorage.getItem('login_source') === 'direct';
                    if (!isDirectLogin) {
                        const syncedData = await syncUserRole(session);
                        if (syncedData) {
                            const updatedUser = { ...session.user, role: syncedData.role };
                            setUser(updatedUser);
                            localStorage.setItem('user', JSON.stringify(updatedUser));
                        }
                    } else {
                        logger.log('[AuthContext] Direct login detected — skipping background sync');
                        localStorage.removeItem('login_source');
                    }
                } else {
                    setIsAuthenticated(false);
                }
            } catch (error) {
                logger.error('[AuthContext] Initialization failed:', error);
                if (error.message?.includes('refresh_token')) {
                    await logout();
                }
            } finally {
                setLoading(false);
            }
        };

        initAuth();

        const { data: authListener } = supabase.auth.onAuthStateChange(async (event, session) => {
            logger.log(`[AuthContext] Auth event: ${event}`);

            if (event === 'SIGNED_IN' || event === 'TOKEN_REFRESHED') {
                const isDirectLogin = localStorage.getItem('login_source') === 'direct';

                if (session) {
                    setUser(session.user);
                    setIsAuthenticated(true);

                    if (session.access_token) {
                        localStorage.setItem('token', session.access_token);
                        sessionStorage.setItem('token', session.access_token);
                    }

                    if (skipSync.current || isDirectLogin) {
                        logger.log('[AuthContext] Skipping redundant sync');
                        skipSync.current = false;
                    } else if (event === 'TOKEN_REFRESHED') {
                        // Only update token, don't re-sync role on token refresh
                        sessionStorage.setItem('token', session.access_token);
                    } else {
                        await syncUserRole(session);
                    }
                }
            } else if (event === 'SIGNED_OUT') {
                setUser(null);
                setRole(null);
                setProfile(null);
                setIsAdmin(false);
                setIsAuthenticated(false);
                localStorage.removeItem('user_role');
                localStorage.removeItem('user_profile');
                localStorage.removeItem('token');
                sessionStorage.removeItem('token');
            } else if (event === 'USER_UPDATED') {
                // Restore email verification sync
                setUser(session?.user || null);
                if (session?.user?.email_confirmed_at) {
                    logger.log('[AuthContext] Email verification detected. Notifying backend...');
                    try {
                        axios.post(`${API_URL}/api/auth/mark-email-verified`, {}, {
                            headers: { Authorization: `Bearer ${session.access_token}` }
                        }).then(res => {
                            if (res.data.success) {
                                setProfile(prev => prev ? { ...prev, is_email_verified: true, email_verified: true } : null);
                            }
                        });
                    } catch (err) {
                        logger.error('[AuthContext] Verification sync failed:', err);
                    }
                }
            }

            // Only set loading to false if we haven't already initialized
            // This prevents multiple redundant loader toggles
            setLoading(false);
        });

        return () => authListener.subscription.unsubscribe();
    }, [syncUserRole]);

    // Use OUR profile definition, not Supabase's immediate stamp
    const isEmailVerified = !!(profile?.is_email_verified || profile?.email_verified);

    const refreshProfile = useCallback(async () => {
        const { data: { session } } = await supabase.auth.getSession();
        if (session) {
            return await syncUserRole(session);
        }
    }, [syncUserRole]);

    const value = useMemo(() => ({
        user,
        role,
        profile,
        loading,
        isAdmin,
        isAuthenticated,
        isEmailVerified,
        login,
        logout,
        refreshProfile,
        updateUserRole,
        getDashboardRoute
    }), [
        user, role, profile, loading, isAdmin, isAuthenticated, isEmailVerified,
        login, logout, refreshProfile, updateUserRole, getDashboardRoute
    ]);

    return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export const useAuth = () => {
    const context = useContext(AuthContext);
    if (!context) throw new Error('useAuth must be used within an AuthProvider');
    return context;
};

import React, { createContext, useContext, useState, useCallback, useRef } from 'react';

const DashboardCacheContext = createContext(null);

const CACHE_TTL = 5 * 60 * 1000; // 5 minutes

export function DashboardCacheProvider({ children }) {
    const [stats, setStats] = useState(null);
    const [jobs, setJobs] = useState({
        "BEST MATCHES": [],
        "MOST RECENT": [],
        "SAVED JOBS": []
    });
    const [proposals, setProposals] = useState([]);
    const [savedJobIds, setSavedJobIds] = useState(new Set());
    const [lastUpdated, setLastUpdated] = useState({});

    const isFresh = useCallback((key) => {
        const timestamp = lastUpdated[key];
        if (!timestamp) return false;
        return (Date.now() - timestamp) < CACHE_TTL;
    }, [lastUpdated]);

    const updateStats = useCallback((newStats) => {
        setStats(newStats);
        setLastUpdated(prev => ({ ...prev, stats: Date.now() }));
    }, []);

    const updateJobs = useCallback((tab, newJobs) => {
        setJobs(prev => ({ ...prev, [tab]: newJobs }));
        setLastUpdated(prev => ({ ...prev, [`jobs_${tab}`]: Date.now() }));
    }, []);

    const updateProposals = useCallback((newProposals) => {
        setProposals(newProposals);
        setLastUpdated(prev => ({ ...prev, proposals: Date.now() }));
    }, []);

    const clearCache = useCallback(() => {
        setStats(null);
        setJobs({ "BEST MATCHES": [], "MOST RECENT": [], "SAVED JOBS": [] });
        setProposals([]);
        setLastUpdated({});
    }, []);

    const value = {
        stats,
        jobs,
        proposals,
        savedJobIds,
        setSavedJobIds,
        updateStats,
        updateJobs,
        updateProposals,
        isFresh,
        clearCache
    };

    return (
        <DashboardCacheContext.Provider value={value}>
            {children}
        </DashboardCacheContext.Provider>
    );
}

export function useDashboardCache() {
    const context = useContext(DashboardCacheContext);
    if (!context) {
        throw new Error('useDashboardCache must be used within a DashboardCacheProvider');
    }
    return context;
}

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';

const NotificationContext = createContext(null);

/**
 * Global provider for IOS-style notifications.
 * Handles visibility, timing, and content of notifications.
 */
export const NotificationProvider = ({ children }) => {
  const [notification, setNotification] = useState({
    show: false,
    title: '',
    message: '',
    type: 'default', // success, error, info
    duration: 5000,
  });

  const showNotification = useCallback(({ title, message, type = 'default', duration = 4000 }) => {
    // If already showing, hide first to re-trigger animation
    setNotification(prev => ({ ...prev, show: false }));

    // Use a tiny timeout to ensure re-render
    setTimeout(() => {
      setNotification({
        show: true,
        title,
        message,
        type,
        duration,
      });
    }, 10);
  }, []);

  const hideNotification = useCallback(() => {
    setNotification(prev => ({ ...prev, show: false }));
  }, []);

  useEffect(() => {
    if (notification.show) {
      const timer = setTimeout(() => {
        hideNotification();
      }, notification.duration);

      return () => clearTimeout(timer);
    }
  }, [notification.show, notification.duration, hideNotification]);

  return (
    <NotificationContext.Provider value={{ notification, showNotification, hideNotification }}>
      {children}
    </NotificationContext.Provider>
  );
};

export const useNotificationContext = () => {
  const context = useContext(NotificationContext);
  if (!context) {
    throw new Error('useNotificationContext must be used within a NotificationProvider');
  }
  return context;
};

import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import { useAuth } from './AuthContext';
import { profileApi } from '../services/profileApi';
import { connectsApi } from '../services/connectsApi';

const ProfileContext = createContext(null);

const PROFILE_CACHE_TTL = 30 * 1000; // 30 seconds cache TTL

export function ProfileProvider({ children }) {
    const { user, role: authRole } = useAuth();
    const [status, setStatus] = useState(null);
    const [balance, setBalance] = useState(0);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    const lastFetchedAt = useRef(null);
    const isFetching = useRef(false);

    const fetchProfile = useCallback(async (force = false) => {
        if (!user) {
            setLoading(false);
            return;
        }

        // Debounce: skip if already fetching
        if (isFetching.current) return;

        // Cache: skip if data is fresh (unless forced)
        const now = Date.now();
        if (!force && lastFetchedAt.current && (now - lastFetchedAt.current) < PROFILE_CACHE_TTL) return;

        isFetching.current = true;
        try {
            setLoading(true);
            setError(null);

            // Parallel fetch: profile status + connects balance
            const isFreelancer = authRole === 'FREELANCER';
            const [profileRes, balanceRes] = await Promise.all([
                profileApi.getStatus().catch(e => ({ success: false, error: e.message })),
                isFreelancer
                    ? connectsApi.getBalance().catch(() => ({ success: false }))
                    : Promise.resolve({ success: false }),
            ]);

            if (profileRes.success) {
                setStatus(profileRes.data);
            } else {
                setError(profileRes.message || 'Failed to load profile');
            }

            if (balanceRes.success) {
                setBalance(balanceRes.data?.balance ?? 0);
            }

            lastFetchedAt.current = Date.now();
        } catch (err) {
            setError(err.message || 'Failed to fetch profile');
        } finally {
            setLoading(false);
            isFetching.current = false;
        }
    }, [user, authRole]);

    // Initial fetch once on mount
    useEffect(() => {
        fetchProfile();
    }, [fetchProfile]);

    return (
        <ProfileContext.Provider value={{ status, balance, loading, error, refetch: () => fetchProfile(true) }}>
            {children}
        </ProfileContext.Provider>
    );
}

export function useProfile() {
    const ctx = useContext(ProfileContext);
    if (!ctx) throw new Error('useProfile must be used within ProfileProvider');
    return ctx;
}

import React, {
  createContext,
  useContext,
  useEffect,
  useRef,
  useCallback,
  useState,
} from 'react';
import { useAuth } from './AuthContext';
import { connectSocket, getSocket } from '../services/socketService';
import { useNotification } from '../hooks/useNotification';
import { logger } from '../utils/logger';

const RealtimeContext = createContext(null);

/**
 * Global real-time context.
 *
 * Manages the socket connection lifecycle and exposes typed listeners
 * that individual components can subscribe to without maintaining their
 * own socket connections.
 */
export function RealtimeProvider({ children }) {
  const { user } = useAuth();
  const { notify } = useNotification();
  const socketRef = useRef(null);
  const [isConnected, setIsConnected] = useState(false);

  // ── Listener registries (component callbacks keyed by event) ──────────────
  const listeners = useRef({
    'new-job': new Set(),
    'job-deleted': new Set(),
    'job-updated': new Set(),
    'new-proposal': new Set(),
    'proposal-status-changed': new Set(),
    'new-notification': new Set(),
  });

  // ── Dispatch to all registered callbacks for an event ─────────────────────
  const dispatch = useCallback((event, data) => {
    listeners.current[event]?.forEach((cb) => {
      try { cb(data); } catch (err) {
        logger.error(`[Realtime] Listener error for "${event}"`, err);
      }
    });
  }, []);

  // ── Connect socket and wire all real-time events ───────────────────────────
  useEffect(() => {
    if (!user?.id) return;

    let active = true;

    const connect = async () => {
      try {
        const socket = await connectSocket();
        if (!active) return;
        socketRef.current = socket;
        setIsConnected(true);

        // ── Job events ─────────────────────────────────────────────────────
        socket.on('new-job', (job) => {
          dispatch('new-job', job);
        });

        socket.on('job-deleted', ({ id }) => {
          dispatch('job-deleted', { id });
        });

        socket.on('job-updated', (job) => {
          dispatch('job-updated', job);
        });

        // ── Proposal events ────────────────────────────────────────────────
        socket.on('new-proposal', (proposal) => {
          dispatch('new-proposal', proposal);
          // Show iOS-style toast for the client
          notify({
            title: '📋 New Proposal',
            message: `Someone applied to "${proposal.job_title || 'your job'}"`,
            type: 'info',
            duration: 5000,
          });
        });

        socket.on('proposal-status-changed', (payload) => {
          dispatch('proposal-status-changed', payload);
          // Show iOS-style toast for the freelancer
          const accepted = payload.status === 'ACCEPTED';
          notify({
            title: accepted ? '🎉 Proposal Accepted!' : 'Proposal Rejected',
            message: accepted
              ? `Your proposal for "${payload.job_title}" was accepted!`
              : `Your proposal for "${payload.job_title}" was not selected.`,
            type: accepted ? 'success' : 'error',
            duration: 6000,
          });
        });

        // ── Notification events ────────────────────────────────────────────
        socket.on('new-notification', (notif) => {
          dispatch('new-notification', notif);
          notify({
            title: notif.title || 'New Notification',
            message: notif.content || '',
            type: 'info',
            duration: 5000,
          });
        });

        logger.log('[Realtime] Real-time listeners attached');
      } catch (err) {
        logger.warn('[Realtime] Socket connection failed:', err);
      }
    };

    connect();

    return () => {
      active = false;
      // Remove all real-time listeners but keep the socket alive for chat/calls
      const socket = socketRef.current || getSocket();
      if (socket) {
        ['new-job', 'job-deleted', 'job-updated', 'new-proposal', 'proposal-status-changed', 'new-notification']
          .forEach((ev) => socket.off(ev));
      }
      setIsConnected(false);
    };
  }, [user?.id, dispatch, notify]);

  // ── Public API: register / unregister typed listeners ─────────────────────
  const subscribe = useCallback((event, callback) => {
    if (!listeners.current[event]) {
      logger.warn(`[Realtime] Unknown event subscribed: "${event}"`);
      return () => {};
    }
    listeners.current[event].add(callback);
    return () => listeners.current[event].delete(callback);
  }, []);

  const value = { isConnected, subscribe };

  return (
    <RealtimeContext.Provider value={value}>
      {children}
    </RealtimeContext.Provider>
  );
}

export function useRealtime() {
  const ctx = useContext(RealtimeContext);
  if (!ctx) throw new Error('useRealtime must be used within RealtimeProvider');
  return ctx;
}

/**
 * Subscribe to new-job events. Callback receives the full job object.
 * Cleans up automatically on unmount.
 */
export function useRealtimeJobs({ onNewJob, onJobDeleted, onJobUpdated } = {}) {
  const { subscribe } = useRealtime();

  useEffect(() => {
    const unsubs = [];
    if (onNewJob) unsubs.push(subscribe('new-job', onNewJob));
    if (onJobDeleted) unsubs.push(subscribe('job-deleted', onJobDeleted));
    if (onJobUpdated) unsubs.push(subscribe('job-updated', onJobUpdated));
    return () => unsubs.forEach((fn) => fn());
  }, [subscribe, onNewJob, onJobDeleted, onJobUpdated]);
}

/**
 * Subscribe to proposal events. Callbacks receive proposal payloads.
 */
export function useRealtimeProposals({ onNewProposal, onStatusChanged } = {}) {
  const { subscribe } = useRealtime();

  useEffect(() => {
    const unsubs = [];
    if (onNewProposal) unsubs.push(subscribe('new-proposal', onNewProposal));
    if (onStatusChanged) unsubs.push(subscribe('proposal-status-changed', onStatusChanged));
    return () => unsubs.forEach((fn) => fn());
  }, [subscribe, onNewProposal, onStatusChanged]);
}

/**
 * Subscribe to notification events.
 */
export function useRealtimeNotifications({ onNewNotification } = {}) {
  const { subscribe } = useRealtime();

  useEffect(() => {
    const unsubs = [];
    if (onNewNotification) unsubs.push(subscribe('new-notification', onNewNotification));
    return () => unsubs.forEach((fn) => fn());
  }, [subscribe, onNewNotification]);
}

import React, { createContext, useContext, useEffect, useState } from 'react';

const ThemeContext = createContext();

export const ThemeProvider = ({ children }) => {
  const [theme, setTheme] = useState(() => {
    return localStorage.getItem('theme') || 'auto';
  });

  useEffect(() => {
    const root = window.document.documentElement;

    // Function to apply theme
    const applyTheme = (currentTheme) => {
      root.classList.remove('light', 'dark');

      if (currentTheme === 'auto') {
        const systemTheme = window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
        root.classList.add(systemTheme);
      } else {
        root.classList.add(currentTheme);
      }

      localStorage.setItem('theme', currentTheme);
    };

    applyTheme(theme);

    // Listen for system theme changes if set to auto
    if (theme === 'auto') {
      const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
      const handleChange = () => applyTheme('auto');
      mediaQuery.addEventListener('change', handleChange);
      return () => mediaQuery.removeEventListener('change', handleChange);
    }
  }, [theme]);

  return (
    <ThemeContext.Provider value={{ theme, setTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
};

