    const timer = setTimeout(async () => {
      try {
        const token = localStorage.getItem('token');
        const headers = token ? { Authorization: `Bearer ${token}` } : {};
        let url = '';
        if (searchType === 'Jobs') url = `${API_URL}/api/jobs/all?search=${encodeURIComponent(searchQuery)}&limit=5&status=OPEN`;
        else if (searchType === 'Talent') url = `${API_URL}/api/profile/freelancers?search=${encodeURIComponent(searchQuery)}&limit=5`;
        else if (searchType === 'Projects') url = `${API_URL}/api/services?search=${encodeURIComponent(searchQuery)}&limit=5`;
        if (!url) return;
        const res = await fetch(url, { headers });
        const data = await res.json();
        const items = (data?.data || []).slice(0, 5);
        setSuggestions(items);
        setShowSuggestions(items.length > 0);
