      </div>

      <div
        className="relative"
        onMouseEnter={() => openDropdown("deliver")}
        onMouseLeave={closeDropdown}
      >
        <button 
          onClick={() => setOpenMenu(openMenu === "deliver" ? null : "deliver")}
          className={`nav-item w-full md:w-auto flex items-center justify-between py-3 px-4 md:py-2 md:px-0 ${openMenu === "deliver" ? "nav-active" : ""}`}
        >
          Deliver work
          <Arrow />
        </button>
        {openMenu === "deliver" && <DeliverWorkDropdown />}
      </div>

      <div
        className="relative"
        onMouseEnter={() => openDropdown("finance")}
        onMouseLeave={closeDropdown}
      >
        <button 
          onClick={() => setOpenMenu(openMenu === "finance" ? null : "finance")}
          className={`nav-item w-full md:w-auto flex items-center justify-between py-3 px-4 md:py-2 md:px-0 ${openMenu === "finance" ? "nav-active" : ""}`}
        >
          Manage finances
          <Arrow />
        </button>
        {openMenu === "finance" && <FinanceDropdown />}
      </div>

      <Link to="/freelancer/messages" className="nav-item w-full md:w-auto py-3 px-4 md:py-2 md:px-0 block md:inline-block">
        Messages
      </Link>

      <div className="relative" onMouseEnter={() => openDropdown("meetings")} onMouseLeave={closeDropdown}>
        <button 
