            <button
              onClick={() => { navigate('/meeting/create'); setOpenMenu(null); }}
              className="dropdown-item w-full text-left py-3 px-4 md:py-2 md:px-3"
            >
              Create Meeting
            </button>
            <button
              onClick={() => { setIsJoinModalOpen(true); setOpenMenu(null); }}
              className="dropdown-item w-full text-left py-3 px-4 md:py-2 md:px-3"
            >
              Join Meeting
            </button>
          </div>
        )}
      </div>

      <JoinMeetingModal 
        isOpen={isJoinModalOpen} 
