                  </div>
                  <div className="min-w-0 flex-1">
                    <p className="text-sm text-light-text font-semibold truncate group-hover:text-accent transition-colors tracking-tight">{label}</p>
                    {sub && <p className="text-[11px] text-white/40 truncate mt-1 group-hover:text-white/60 transition-colors uppercase tracking-wider font-medium">{sub}</p>}
                  </div>
                  <div className="mt-1 opacity-0 group-hover:opacity-100 -translate-x-2 group-hover:translate-x-0 transition-all duration-300">
