            </button>
          </div>
        </div>
      )}
    </>
  );

  const [openAI, setOpenAI] = useState(false);

  const rightActions = (
    <div className="flex items-center gap-2">
      {/* AI Assistant button */}
      <div className="relative">
        <button
          onClick={() => setOpenAI(o => !o)}
