    const loadNotifications = useCallback(async () => {
        try {
            setLoading(true);
            const data = await fetchUnifiedNotifications(role);
            setItems(data);
            setUnreadCount(getUnifiedUnreadCount(data));
        } catch (err) {
            console.error(err);
