import { useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import logger from '../utils/logger';

export default function AuthCallback() {
    const navigate = useNavigate();
    const { user, role, profile, loading, getDashboardRoute } = useAuth();
    const hasSynced = useRef(false);

    useEffect(() => {
        if (hasSynced.current) return; // prevent double-run on re-renders
        if (loading) return;

        hasSynced.current = true;
        let retryCount = 0;
        const maxRetries = 20;

        const checkAuth = async () => {
            const { data: { session } } = await supabase.auth.getSession();

            if (session) {
                if (user) {
                    const dashboardRoute = getDashboardRoute(role, profile);
                    const savedPath = localStorage.getItem('oauth_redirect_path');
                    const redirectUrl = (savedPath && savedPath !== '/') ? savedPath : dashboardRoute;

                    logger.log(`[AuthCallback] Sync complete! Redirecting to: ${redirectUrl}`);
                    localStorage.removeItem('oauth_redirect_path');
                    navigate(redirectUrl, { replace: true });
                } else if (retryCount < maxRetries) {
                    logger.log(`[AuthCallback] Session found, waiting for user sync... (${retryCount}/${maxRetries})`);
                    retryCount++;
                    setTimeout(checkAuth, 500);
                } else {
                    logger.warn('[AuthCallback] Sync timed out. Forcing login.');
                    navigate('/login');
                }
            } else {
                logger.log('[AuthCallback] No session found, redirecting to login.');
                navigate('/login');
            }
        };

        checkAuth();
    }, [loading]); // only re-run if loading state changes, not on every auth update

    return (
        <div className="flex bg-primary min-h-screen items-center justify-center">
            <div className="text-accent opacity-70">Authenticating...</div>
        </div>
    );
}

