import React, { useState, useEffect } from "react";
import InfinityLoader from "../components/common/InfinityLoader";
import { motion } from "framer-motion";
import { useSearchParams, useLocation } from "react-router-dom";
import Navbar from "../components/Navbar";
import Footer from "../components/Footer";
import TalentFilterSidebar from "../components/filters/TalentFilterSidebar";
import { getAllJobs } from "../services/apiService";
import { toast } from "react-hot-toast";
import { useAuth } from "../context/AuthContext";
import { useNavigate } from "react-router-dom";
import logger from "../utils/logger";

const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.08,
    },
  },
};

const itemVariants = {
  hidden: { opacity: 0, y: 25 },
  visible: { opacity: 1, y: 0 },
};

const FindWork = () => {
  const [searchParams] = useSearchParams();
  const location = useLocation();
  const isDashboard = location.pathname.startsWith('/freelancer');
  const queryParam = searchParams.get("q") || "";

  const [selectedCategory, setSelectedCategory] = useState("All Categories");
  const [searchTerm, setSearchTerm] = useState(queryParam);
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const { user, role } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    setSearchTerm(queryParam);
  }, [queryParam]);

  useEffect(() => {
    fetchJobs();
  }, [selectedCategory, searchTerm]);


  const fetchJobs = async () => {
    try {
      setLoading(true);
      const filters = { status: 'OPEN' };
      if (selectedCategory && selectedCategory !== "All Categories") filters.category = selectedCategory;
      if (searchTerm) filters.search = searchTerm;

      const response = await getAllJobs(filters);
      if (response.success) {
        setJobs(response.data);
      }
    } catch (error) {
      logger.error("Failed to fetch jobs", error);
      toast.error("Failed to load jobs");
    } finally {
      setLoading(false);
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 15 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -15 }}
      transition={{ duration: 0.4 }}
      className={`relative ${isDashboard ? '' : 'bg-primary min-h-screen'}`}
    >
      {!isDashboard && <Navbar />}

      {/* Header */}
      <motion.div
        initial={{ opacity: 0, y: 15 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.1 }}
        className={`${isDashboard ? '' : 'max-w-[1550px] mx-auto px-6 md:px-10 lg:px-14 pt-8 pb-2 w-full text-center md:text-left'}`}
      >
        <h1 className={`${isDashboard ? 'text-2xl font-bold mb-2' : 'text-2xl md:text-2xl font-semibold mb-3 tracking-tight'} text-white`}>
          Find Jobs
        </h1>
        <p className="text-white/60 text-base">
          Browse open jobs and submit proposals to clients.
        </p>
      </motion.div>

      {/* Main Layout */}
      <div className={`flex flex-col lg:flex-row gap-8 lg:gap-10 ${isDashboard ? 'py-8' : 'max-w-[1550px] mx-auto px-6 md:px-10 lg:px-14 py-10 lg:py-14'} flex-1`}>


        {/* Sidebar */}
        <motion.div
          initial={{ opacity: 0, x: -30 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ delay: 0.2 }}
          className="w-full lg:w-[280px] lg:sticky lg:top-24 lg:self-start"
        >
          <TalentFilterSidebar
            selectedCategory={selectedCategory}
            setSelectedCategory={setSelectedCategory}
            searchTerm={searchTerm}
            setSearchTerm={setSearchTerm}
          />
        </motion.div>

        {/* Job Cards */}
        <div className="flex-1">
          {loading ? (
            <div className="flex justify-center items-center h-64">
              <InfinityLoader size={40} />
            </div>
          ) : jobs.length > 0 ? (
            <motion.div
              variants={containerVariants}
              initial="hidden"
              animate="visible"
              className="grid grid-cols-1 gap-6"
            >
              {jobs?.map((job) => (
                <motion.div
                  key={job?.id || Math.random()}
                  variants={itemVariants}
                  onClick={() => {
                    if (!user) {
                      navigate('/login');
                      return;
                    }
                    if (role === 'CLIENT') {
                      toast.error("Job details are accessible to freelancers.");
                      return;
                    }
                    navigate(`/freelancer/jobs/${job.id}`);
                  }}
                  className="bg-transparent border border-white/10 rounded-2xl p-8 hover:border-accent transition-all duration-300 cursor-pointer shadow-sm hover:shadow-2xl hover:shadow-accent/5 group"
                >
                  <div className="flex justify-between items-start mb-4">
                    <h3 className="text-lg font-semibold text-white group-hover:text-accent transition-colors">
                      {job.title}
                    </h3>
                    <span className="text-accent font-bold text-lg">
                      ${job.budget_amount || job.budget} {job.budget_type === 'fixed' ? 'Fixed' : '/hr'}
                    </span>
                  </div>

                  <p className="text-white/60 text-sm mb-6 line-clamp-3 leading-relaxed">
                    {job.description}
                  </p>

                  <div className="flex justify-between items-center">
                    <div className="flex gap-2">
                      <span className="text-white/40 text-xs bg-white/5 px-4 py-1.5 rounded-lg border border-white/5 capitalize tracking-wide">
                        {job.experience_level || job.level}
                      </span>
                    </div>
                  </div>
                </motion.div>
              ))}
            </motion.div>
          ) : (
            <div className="text-center py-24 bg-transparent rounded-2xl border border-dashed border-white/10">
              <p className="text-gray-400 text-lg font-light">No jobs found matching your criteria.</p>
            </div>
          )}
        </div>

      </div>

      {!isDashboard && <Footer />}
    </motion.div>

  );
};

export default FindWork;

import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Mail, ArrowLeft, CheckCircle } from 'lucide-react';
import AuthInput from '../components/AuthInput';
import { forgotPassword } from '../services/authService';

const ForgotPassword = () => {
    const [email, setEmail] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState(false);

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!email) {
            setError('Please enter your email address.');
            return;
        }

        setLoading(true);
        setError('');

        const result = await forgotPassword(email);

        if (result.success) {
            setSuccess(true);
        } else {
            setError(result.message);
        }
        setLoading(false);
    };

    return (
        <div className="min-h-screen bg-primary flex items-center justify-center px-4 py-12">
            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5 }}
                className="max-w-md w-full"
            >
                <div className="bg-secondary/30 backdrop-blur-xl border border-white/10 p-8 rounded-3xl shadow-2xl">
                    <div className="mb-8 flex flex-col items-center">
                        <Link to="/" className="mb-6">
                            <img src="/Logo2.png" alt="Connect Logo" className="h-10 object-contain" />
                        </Link>
                        <h2 className="text-3xl font-bold text-white mb-2">Forgot Password?</h2>
                        <p className="text-white/50 text-center text-sm">
                            {success
                                ? "Check your email for a link to reset your password."
                                : "No worries, we'll send you reset instructions."
                            }
                        </p>
                    </div>

                    {success ? (
                        <div className="text-center">
                            <div className="bg-green-500/20 border border-green-500/50 p-6 rounded-2xl mb-8 flex flex-col items-center">
                                <CheckCircle className="text-green-500 mb-2" size={32} />
                                <p className="text-green-100 text-sm">
                                    Resent link has been sent to <strong>{email}</strong>
                                </p>
                            </div>
                            <Link
                                to="/login"
                                className="inline-flex items-center text-accent hover:text-accent/80 font-medium transition-colors"
                            >
                                <ArrowLeft size={16} className="mr-2" />
                                Back to log in
                            </Link>
                        </div>
                    ) : (
                        <form onSubmit={handleSubmit} className="space-y-6">
                            {error && (
                                <div className="bg-red-500/20 border border-red-500 text-red-100 px-4 py-2 rounded-xl text-sm text-center">
                                    {error}
                                </div>
                            )}

                            <AuthInput
                                label="Email address"
                                type="email"
                                placeholder="name@company.com"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                icon={Mail}
                                required
                            />

                            <button
                                type="submit"
                                disabled={loading}
                                className="w-full bg-accent hover:bg-accent/90 disabled:opacity-50 text-white font-semibold py-3.5 rounded-xl transition-all shadow-lg shadow-accent/20 active:scale-[0.98]"
                            >
                                {loading ? "Sending link..." : "Send Reset Link"}
                            </button>

                            <div className="text-center">
                                <Link
                                    to="/login"
                                    className="inline-flex items-center text-white/40 hover:text-white font-medium text-sm transition-colors"
                                >
                                    <ArrowLeft size={16} className="mr-2" />
                                    Back to log in
                                </Link>
                            </div>
                        </form>
                    )}
                </div>
            </motion.div>
        </div>
    );
};

export default ForgotPassword;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { AnimatePresence, motion } from 'framer-motion';
import { 
    User, MapPin, Star, ShieldCheck, Mail, Phone, 
    Globe, Calendar, Briefcase, Award, CheckCircle2, 
    ExternalLink, MessageSquare, Heart, Share2, 
    ChevronRight, ArrowLeft, AlertCircle,
    X, Check, Clock, FileText, Camera, IndianRupee
} from 'lucide-react';
import { formatINR, convertToUSD, USD_TO_INR } from '../utils/currencyUtils';
import { profileApi } from '../services/profileApi';
import ProfileImageModal from '../components/dashboard/client/settings/ProfileImageModal';
import { getIdentityStatus } from '../services/apiService';
import { useAuth } from '../context/AuthContext';
import { useProfile } from '../context/ProfileContext';
import { toast } from 'react-hot-toast';
import Navbar from '../components/Navbar';
import ClientTopbar from '../layouts/components/ClientTopbar';
import FreelancerTopbar from '../layouts/components/FreelancerTopbar';
import Footer from '../components/Footer';
import InfinityLoader from '../components/common/InfinityLoader';
import logger from '../utils/logger';

const FreelancerProfilePage = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user: currentUser, refreshProfile, role } = useAuth();
    const { refetch: refetchProfileContext } = useProfile();

    const [loading, setLoading] = useState(true);
    const [profile, setProfile] = useState(null);
    const [activeTab, setActiveTab] = useState('about');
    const [showVerifyModal, setShowVerifyModal] = useState(false);
    const [verifyType, setVerifyType] = useState(null); // 'email' or 'document'
    const [uploading, setUploading] = useState(false);
    const [showPhotoModal, setShowPhotoModal] = useState(false);

    // Edit Mode State
    const [editSection, setEditSection] = useState(null); // 'header', 'about', 'skills', 'contact', 'basic'
    const [editData, setEditData] = useState({});

    // IDV State (Only for own profile)
    const [idvStatus, setIdvStatus] = useState(null);

    const handlePhotoSelected = (avatarUrl) => {
        setProfile(prev => prev ? { ...prev, avatar_url: avatarUrl } : prev);
        refetchProfileContext();
    };

    useEffect(() => {
        if (currentUser && currentUser.id === id) {
            getIdentityStatus().then(res => setIdvStatus(res?.data ?? res)).catch(() => {});
        }
    }, [id, currentUser]);

    useEffect(() => {
        if (id) {
            fetchProfile();
        }
    }, [id]);

    const fetchProfile = async () => {
        try {
            setLoading(true);
            const response = await profileApi.getPublicProfile(id);
            if (response.success) {
                const data = response.data;
                // Normalize email verified field — API may return either name
                setProfile({
                    ...data,
                    is_email_verified: data.is_email_verified ?? data.email_verified ?? false,
                    skills: Array.isArray(data.skills) ? data.skills : [],
                });
            } else {
                logger.error('API returned success:false', response);
                setProfile(null);
            }
        } catch (error) {
            logger.error('Error fetching profile', error);
            // toast.error('Failed to load profile');
            setProfile(null);
        } finally {
            setLoading(false);
        }
    };

    const handleUpdateProfile = async () => {
        try {
            setUploading(true);
            const payload = { ...editData };

            if (payload.experience !== undefined || payload.experience_years !== undefined) {
                const exp = payload.experience || payload.experience_years;
                payload.step_data = {
                    ...(profile?.step_data || {}),
                    professional_info: {
                        ...(profile?.step_data?.professional_info || {}),
                        experience: exp
                    }
                };
            }
            delete payload.experience;
            delete payload.experience_years;
            delete payload.years_of_experience;

            if (payload.hourly_rate) {
                payload.hourly_rate = convertToUSD(payload.hourly_rate);
            }

            const res = await profileApi.updateProfile(payload);
            if (res.success) {
                toast.success('Profile updated successfully');
                setEditSection(null);
                fetchProfile();
                refetchProfileContext(); // Sync global UI
            }
        } catch {
            toast.error('Update failed. Please try again.');
        } finally {
            setUploading(false);
        }
    };

    const handleImageUpload = async (e) => {
        const file = e.target.files[0];
        if (!file) return;

        // Validation
        if (!file.type.startsWith('image/')) {
            toast.error('Please upload an image file');
            return;
        }
        if (file.size > 2 * 1024 * 1024) {
            toast.error('File size must be less than 2MB');
            return;
        }

        try {
            setUploading(true);
            const res = await profileApi.uploadAvatar(file);
            if (res.success) {
                toast.success('Avatar updated successfully');
                fetchProfile();
                refetchProfileContext(); // Sync global UI
            }
        } catch {
            toast.error('Upload failed');
        } finally {
            setUploading(false);
        }
    };

    const handleSendOtp = async () => {
        try {
            const res = await profileApi.verifyEmailSend();
            if (res.success) {
                toast.success('Verification link sent to your email');
                setVerifyType('email');
                setShowVerifyModal(true);
            }
        } catch {
            toast.error('Failed to send verification link');
        }
    };


    const handleDocUpload = async (e) => {
        const file = e.target.files[0];
        if (!file) return;

        try {
            setUploading(true);
            const res = await profileApi.uploadDocument(file);
            if (res.success) {
                toast.success('Document uploaded for verification');
                fetchProfile();
            }
        } catch {
            toast.error('Upload failed');
        } finally {
            setUploading(false);
        }
    };


    if (loading) {

    return (
            <div className="min-h-screen bg-primary flex flex-col items-center justify-center gap-4">
                <InfinityLoader size={60} />
                <p className="text-white/60 font-medium animate-pulse">Fetching premium profile...</p>
            </div>
        );
    }

    if (!profile) {

    return (
            <div className="min-h-screen bg-primary flex flex-col items-center justify-center p-6 text-center">
                <AlertCircle className="w-16 h-16 text-red-400 mb-4" />
                <h2 className="text-2xl font-bold text-white mb-2">Profile Not Found</h2>
                <p className="text-white/60 mb-6">The freelancer you are looking for does not exist or has a private profile.</p>
                <button 
                    onClick={() => navigate(-1)}
                    className="flex items-center gap-2 text-accent hover:underline font-medium"
                >
                    <ArrowLeft size={18} /> Back to previous page
                </button>
            </div>
        );
    }

    const isOwnProfile = currentUser?.id === (profile.user_id || profile.id);


    return (
        <div className="min-h-screen bg-primary text-light-text selection:bg-accent/30 selection:text-accent font-sans">
            {/* True Navigation Bar */}
            {!currentUser ? (
                <Navbar />
            ) : role === 'CLIENT' ? (
                <ClientTopbar />
            ) : (
                <FreelancerTopbar />
            )}

            <div className="max-w-7xl mx-auto px-6 py-12">
                {/* 1. TOP HEADER SECTION */}
                <div className="bg-secondary rounded-[40px] border border-border shadow-sm overflow-hidden mb-12">
                    <div className="flex flex-col md:flex-row p-10 gap-12 items-center md:items-start">
                        {/* Profile Image Column */}
                        <div className="relative shrink-0">
                            <div className="relative group">
                                <div className="w-28 h-28 rounded-full border-2 border-accent overflow-hidden shadow-2xl bg-secondary relative z-10">
                                    {profile.avatar_url ? (
                                        <img src={profile.avatar_url} alt={profile.name} className="w-full h-full object-cover" />
                                    ) : (
                                        <div className="w-full h-full flex items-center justify-center">
                                            <User size={40} className="text-white/10" />
                                        </div>
                                    )}
                                </div>
                                {isOwnProfile && (
                                    <label className="absolute inset-0 z-20 flex items-center justify-center bg-black/60 rounded-full opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer">
                                        <Camera className="text-white w-6 h-6" />
