          <h2 className="text-3xl md:text-4xl font-bold text-white mb-4 tracking-tight">One last step!</h2>
          <p className="text-white/60 mb-10 max-w-md mx-auto text-lg">
            Tell us how you'll be using Connect so we can customize your experience.
          </p>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-10">
            {/* Client Option */}
            <motion.div 
