              )}
              <div className={`w-20 h-20 rounded-2xl flex items-center justify-center mb-6 transition-all duration-500 ${
                selectedRole === 'client' ? 'bg-accent text-white rotate-3' : 'bg-secondary text-white/40 group-hover:text-white/60'
              }`}>
                <FiUsers size={40} />
              </div>
              <h3 className={`text-xl font-bold mb-2 transition-colors ${selectedRole === 'client' ? 'text-white' : 'text-white/60'}`}>
                I'm a Client
              </h3>
              <p className="text-white/40 text-sm leading-relaxed">
                I want to post jobs, find expert talent, and manage projects.
              </p>
            </motion.div>

            {/* Freelancer Option */}
            <motion.div 
              whileHover={{ y: -4, borderColor: 'rgba(59, 130, 246, 0.5)' }}
              whileTap={{ scale: 0.98 }}
              onClick={() => setSelectedRole('freelancer')}
              className={`group cursor-pointer p-8 rounded-2xl border transition-all duration-300 flex flex-col items-center text-center relative ${
                selectedRole === 'freelancer' 
                  ? 'bg-accent/10 border-accent shadow-[0_0_40px_rgba(59,130,246,0.15)]' 
                  : 'bg-primary/30 border-white/5 hover:bg-white/5'
              }`}
            >
              {selectedRole === 'freelancer' && (
                <motion.div 
                  initial={{ scale: 0 }} 
                  animate={{ scale: 1 }} 
                  className="absolute top-4 right-4 text-accent"
                >
                  <FiCheckCircle size={24} />
                </motion.div>
              )}
              <div className={`w-20 h-20 rounded-2xl flex items-center justify-center mb-6 transition-all duration-500 ${
                selectedRole === 'freelancer' ? 'bg-accent text-white -rotate-3' : 'bg-secondary text-white/40 group-hover:text-white/60'
              }`}>
                <FiBriefcase size={40} />
              </div>
              <h3 className={`text-xl font-bold mb-2 transition-colors ${selectedRole === 'freelancer' ? 'text-white' : 'text-white/60'}`}>
                I'm a Freelancer
