          >
            <div>
              <h1 className="text-2xl font-semibold text-white tracking-tight">
                Browse Services
              </h1>
              <p className="text-base text-light-text/70 mt-1">
                Discover pre-packaged custom services created by top-tier freelancers.
              </p>
            </div>

            {/* SEARCH & FILTERS */}
            <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
              <div className="relative flex-1 sm:w-80 group">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20 group-focus-within:text-accent transition-colors" size={16} />
                <input
                  type="text"
                  placeholder="Search services..."
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  className="w-full bg-secondary/50 border border-white/10 rounded-full py-2.5 pl-11 pr-4 text-sm text-white focus:border-accent/50 focus:ring-4 focus:ring-accent/5 transition-all outline-none"
                />
              </div>
              <button className="flex items-center justify-center gap-2 bg-secondary border border-white/10 rounded-full px-6 py-2.5 hover:bg-white/5 transition-all group text-sm font-medium text-white/70">
                <Filter size={16} className="text-white/40 group-hover:text-accent transition-colors" />
                <span>Filters</span>
              </button>
            </div>
          </motion.div>

          {/* CATEGORY TABS - Dashboard Pill Style */}
          <div className="flex gap-2 overflow-x-auto hide-scrollbar py-1 mt-8">
            {CATEGORIES.map((cat) => (
              <button
                key={cat}
                onClick={() => setActiveCategory(cat)}
                className={`whitespace-nowrap px-4 py-2 rounded-full text-sm font-medium transition ${activeCategory === cat
                  ? "bg-accent/10 text-accent border border-accent/20"
                  : "text-white/50 border border-transparent hover:text-white"
                  }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </section>

        {/* SERVICES GRID */}
        {loading ? (
          <div className="py-40">
            <InfinityLoader />
          </div>
        ) : services.length === 0 ? (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="py-32 flex flex-col items-center justify-center text-center bg-transparent rounded-3xl border border-dashed border-white/10 backdrop-blur-sm"
          >
            <div className="w-20 h-20 bg-white/5 rounded-full flex items-center justify-center mb-6">
              <ShoppingBag size={32} className="text-white/20" />
            </div>
            <h3 className="text-xl font-bold text-white mb-2">No services found</h3>
            <p className="text-light-text/50 max-w-sm">
