            </p>
            <button
              onClick={() => { setSearch(""); setActiveCategory("All"); }}
              className="mt-8 text-accent font-bold uppercase text-[10px] tracking-widest hover:underline"
            >
              Clear all filters
            </button>
          </motion.div>
        ) : (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 sm:gap-8"
          >
            {services.map((service, idx) => (
              <ServiceCard key={service.id || idx} service={service} index={idx} />
            ))}
          </motion.div>
        )}
      </main>

      <Footer />
    </div>
  );
};

