  const [showPassword, setShowPassword] = useState(false);
  const navigate = useNavigate();

  const {
    register,
    handleSubmit,
    formState: { errors, isSubmitting }
  } = useForm({
    resolver: zodResolver(registerSchema)
  });

  const onSubmit = async (data) => {
    try {
      const response = await axios.post(
        `${import.meta.env.VITE_API_URL || 'http://localhost:5001'}/api/auth/register`,
        {
          email: data.email,
          password: data.password,
          name: `${data.firstName} ${data.lastName}`,
          role: "CLIENT"
        }
      );

      if (response.data.success) {
        toast.success("Registration successful! You can now log in.");
        navigate("/login");
      }
    } catch (error) {
      logger.error("Registration error", error);
      toast.error(error.response?.data?.message || "An error occurred during registration.");
    }
  };

  const handleGoogleLogin = async () => {
    try {
      localStorage.setItem('oauth_intended_role', 'CLIENT');
      const { error } = await supabase.auth.signInWithOAuth({
        provider: 'google',
        options: {
          redirectTo: window.location.origin + '/auth/callback'
        }
      });
      if (error) throw error;
    } catch (error) {
      logger.error("Error logging in with Google", error);
    }
  };

  const handleAppleLogin = async () => {
    try {
      localStorage.setItem('oauth_intended_role', 'CLIENT');
      const { error } = await supabase.auth.signInWithOAuth({
        provider: 'apple',
        options: {
          redirectTo: window.location.origin + '/auth/callback'
        }
      });
      if (error) throw error;
    } catch (error) {
      logger.error("Error logging in with Apple", error);
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ duration: 0.6 }}
      className="min-h-[10px] bg-primary text-light-text font-sans selection:bg-accent/30"
    >

      {/* Header */}
      <header className="sticky top-0 z-50 bg-primary px-8 md:px-12 lg:px-24 py-4 max-w-[1630px] mx-auto flex items-center justify-between">
        <div className="flex items-center pl-4">
          <Link to="/" className="flex items-center group">
            <img
              src="/Logo2.png"
              alt="Connect Logo"
              className="h-10 md:h-10 object-contain invert dark:invert-0"
            />
          </Link>
        </div>

        <div className="text-[16px] text-light-text/80">
          Looking for work?{" "}
          <Link
            to="/signup-freelancer"
            className="text-accent font-medium"
          >
            Apply as talent
          </Link>
        </div>
      </header>

      {/* Form Container */}
      <motion.main
        initial={{ y: 40, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        transition={{ duration: 0.6, delay: 0.2 }}
        className="max-w-[600px] mx-auto px-6 pt-4 pb-20"
      >

          <>
            <h1 className="text-[32px] font-semibold text-center mb-10 tracking-tight leading-tight">
              Sign up to hire talent
            </h1>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-3 mb-4">
              <motion.button
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                type="button"
                onClick={handleAppleLogin}
                className="flex items-center justify-center gap-2 border border-[var(--color-border)] bg-secondary rounded-full py-2 px-4 hover:bg-[var(--color-hover)] transition text-light-text"
              >
                <FaApple size={18} />
                <span className="text-[14px] font-medium">Continue with Apple</span>
              </motion.button>

              <motion.button
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                type="button"
                onClick={handleGoogleLogin}
                className="flex items-center justify-center gap-2 border border-[var(--color-border)] bg-secondary rounded-full py-2 px-4 hover:bg-[var(--color-hover)] transition text-light-text"
              >
                <FcGoogle size={18} />
                <span className="text-[14px] font-medium">Continue with Google</span>
              </motion.button>
            </div>

            <div className="relative flex py-8 items-center">
              <div className="flex-grow border-t border-[var(--color-border)]"></div>
              <span className="flex-shrink mx-4 text-text-muted text-sm">or</span>
              <div className="flex-grow border-t border-[var(--color-border)]"></div>
            </div>

            <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[14px] font-medium mb-2 text-light-text">First name</label>
                  <input
                    {...register("firstName")}
                    className={`w-full bg-secondary border rounded-lg px-3 py-2 transition focus:border-accent outline-none text-light-text ${errors.firstName ? 'border-red-500' : 'border-[var(--color-border)]'}`}
