                  >
                    {showPassword ? <FiEyeOff size={18} /> : <FiEye size={18} />}
                  </button>
                </div>
                {errors.password && <p className="text-red-400 text-xs mt-1">{errors.password.message}</p>}
              </div>

              <div>
                <label className="block text-[14px] font-medium mb-2 text-white/90">Country</label>
                <select
                  {...register("country")}
                  className={`w-full bg-secondary border rounded-lg px-3 py-2 transition focus:border-accent outline-none appearance-none ${errors.country ? 'border-red-500' : 'border-white/20'}`}
