import axios from 'axios';
import { supabase } from '../lib/supabase';
import { logger } from '../utils/logger';

const API_URL = import.meta.env.VITE_API_URL || 'http://localhost:5001';

const getHeaders = async () => {
    try {
        const { data: { session } } = await supabase.auth.getSession();
        const token = session?.access_token || localStorage.getItem('token') || localStorage.getItem('adminToken');
        return {
            headers: {
                Authorization: `Bearer ${token}`
            }
        };
    } catch (e) {
        logger.error("Failed to retrieve auth headers for notifications", e);
        return { headers: {} };
    }
};

/**
 * Fetches both platform announcements and user-specific notifications
 * @param {string} role - CLIENT or FREELANCER (or ALL)
 */
export const fetchUnifiedNotifications = async (role) => {
    try {
        const isAdmin = role && role.includes('ADMIN') || role === 'MODERATOR';

        // 1. Fetch public announcements from backend proxy (avoiding direct Supabase connection issues)
        let activeAnnouncements = [];
        try {
            const headers = await getHeaders();
            const annResponse = await axios.get(`${API_URL}/api/notifications/announcements`, headers);
            const announcements = annResponse.data.data || [];

            // Filter out dismissed announcements
            const dismissedIds = JSON.parse(localStorage.getItem('dismissed_announcements') || '[]');
            activeAnnouncements = announcements.filter(a => !dismissedIds.includes(a.id));
        } catch (e) {
            logger.error("NotificationService: Failed to fetch announcements", e);
            // Fallback: stay as empty array, keep the rest of the flow working
        }

        // 2. Fetch private notifications from API
        let notifications = [];
        try {
            const headers = await getHeaders();
            const response = await axios.get(`${API_URL}/api/notifications`, headers);
            notifications = response.data.data || [];
        } catch (e) {
            logger.error("NotificationService: Failed to fetch private notifications", e);
        }

        // 3. Merge and sort
        const unified = [
            ...activeAnnouncements.map(a => ({ ...a, type: 'ANNOUNCEMENT' })),
            ...notifications.map(n => ({ ...n, type: 'NOTIFICATION' }))
        ].sort((a, b) => new Date(b.created_at) - new Date(a.created_at));

        return unified;
    } catch (error) {
        logger.error("NotificationService: Critical error in unified notification fetch", error);
        return [];
    }
};

/**
 * Dismisses/Deletes a single item
 */
export const dismissUnifiedItem = async (item) => {
    if (!item) return false;

    try {
        if (item.type === 'ANNOUNCEMENT') {
            // Store in local dismissed list
            const dismissedIds = JSON.parse(localStorage.getItem('dismissed_announcements') || '[]');
            if (!dismissedIds.includes(item.id)) {
                localStorage.setItem('dismissed_announcements', JSON.stringify([...dismissedIds, item.id]));
            }
            return true;
        } else {
            // Call API to delete private notification
            const headers = await getHeaders();
            await axios.delete(`${API_URL}/api/notifications/${item.id}`, headers);
            return true;
        }
    } catch (error) {
        logger.error("NotificationService: Failed to dismiss notification item", error);
        return false;
    }
};

/**
 * Marks items as read
 */
export const markUnifiedAsRead = async (items) => {
    if (!items || items.length === 0) return;

    // Separate announcements (local storage) and notifications (API)
    const announcementIds = items.filter(i => i.type === 'ANNOUNCEMENT').map(i => i.id);
    const notificationIds = items.filter(i => i.type === 'NOTIFICATION' && !i.is_read).map(i => i.id);

    // 1. Mark announcements in localStorage
    if (announcementIds.length > 0) {
        const readIds = JSON.parse(localStorage.getItem('read_announcements') || '[]');
        const updatedIds = [...new Set([...readIds, ...announcementIds])];
        localStorage.setItem('read_announcements', JSON.stringify(updatedIds));
    }

    // 2. Mark notifications in API
    if (notificationIds.length > 0) {
        try {
            const headers = await getHeaders();
            await axios.put(`${API_URL}/api/notifications/read`, { id: notificationIds }, headers);
        } catch (e) {
            logger.error("NotificationService: Failed to mark notifications as read", e);
        }
    }
};

/**
 * Gets count of unread unified items
 */
export const getUnifiedUnreadCount = (items) => {
    if (!items) return 0;
    const readAnnIds = JSON.parse(localStorage.getItem('read_announcements') || '[]');

    return items.filter(item => {
        if (item.type === 'ANNOUNCEMENT') return !readAnnIds.includes(item.id);
        return !item.is_read;
    }).length;
};

// --- Backwards Compatibility ---
export const fetchAnnouncements = async (role) => {
    const data = await fetchUnifiedNotifications(role);
    return data.filter(i => i.type === 'ANNOUNCEMENT');
};

export const markAsRead = (announcements) => {
    markUnifiedAsRead(announcements.map(a => ({ ...a, type: 'ANNOUNCEMENT' })));
};

export const getUnreadCount = (announcements) => {
    return getUnifiedUnreadCount(announcements.map(a => ({ ...a, type: 'ANNOUNCEMENT' })));
};

import { io } from 'socket.io-client';
import { supabase } from '../lib/supabase';
import { logger } from '../utils/logger';

const API_URL = import.meta.env.VITE_API_URL || 'http://localhost:5001';

let socket = null;
let _connecting = false;

export async function connectSocket() {
    if (socket?.connected) return socket;

    // Prevent multiple simultaneous connection attempts
    if (_connecting) {
        // Wait for existing connection attempt
        await new Promise(resolve => {
            const check = setInterval(() => {
                if (socket?.connected || !_connecting) {
                    clearInterval(check);
                    resolve();
                }
            }, 100);
            setTimeout(() => { clearInterval(check); resolve(); }, 5000);
        });
        if (socket?.connected) return socket;
    }

    _connecting = true;

    try {
        // Wait for valid session (up to 3s)
        let session = null;
        for (let i = 0; i < 6; i++) {
            const { data } = await supabase.auth.getSession();
            if (data?.session?.access_token) { session = data.session; break; }
            await new Promise(r => setTimeout(r, 500));
        }
        if (!session?.access_token) throw new Error('Not authenticated');

        // If socket exists with wrong token, disconnect it first
        if (socket) {
            socket.disconnect();
            socket = null;
        }

        socket = io(API_URL, {
            auth: { token: session.access_token },
            transports: ['websocket', 'polling'],
            reconnectionAttempts: 5,
            reconnectionDelay: 2000,
            timeout: 10000,
        });

        // Wait for connection
        await new Promise((resolve, reject) => {
            const t = setTimeout(() => reject(new Error('Connection timeout')), 10000);
            socket.once('connect', () => { clearTimeout(t); resolve(); });
            socket.once('connect_error', (err) => { clearTimeout(t); reject(err); });
        });

        socket.on('connect', () => {
            logger.log('[Socket] Connected:', socket.id);
            // Flush any listeners registered before connection
            _pendingOnlineUsersListeners.forEach(cb => {
                socket.off('online-users', cb);
                socket.on('online-users', cb);
            });
            _pendingOnlineUsersListeners.length = 0;
            // Re-request online users on every reconnect
            setTimeout(() => socket.emit('get-online-users'), 200);

            // Heartbeat — immediate ping on connect, then every 30s
            socket.emit('heartbeat');
            const heartbeatInterval = setInterval(() => {
                if (socket.connected) socket.emit('heartbeat');
            }, 30000);
            socket.once('disconnect', () => clearInterval(heartbeatInterval));
        });

        socket.on('disconnect', (reason) => {
            logger.log('[Socket] Disconnected:', reason);
        });

        socket.on('connect_error', (err) => {
            logger.error('[Socket] Connection Error:', err);
        });

        socket.onAny((event) => {
            if (event.startsWith('call') || event === 'incoming-call') {
                logger.log('[Socket] Call event:', event);
            }
        });

        let lastToken = null;
        supabase.auth.onAuthStateChange((event, sess) => {
            if (event === 'TOKEN_REFRESHED' && sess?.access_token && socket) {
                if (lastToken === sess.access_token) return; // guard against loop
                lastToken = sess.access_token;
                socket.auth = { token: sess.access_token };
                // Update auth without full reconnect — avoids triggering another auth event
                socket.io.opts.auth = { token: sess.access_token };
            }
        });

        return socket;
    } finally {
        _connecting = false;
    }
}

export function getSocket() { return socket; }

export function disconnectSocket() {
    if (socket) { socket.disconnect(); socket = null; }
}

export function joinConversation(id) { socket?.emit('join-conversation', id); }
export function leaveConversation(id) { socket?.emit('leave-conversation', id); }
export function sendSocketMessage(conversationId, data) { socket?.emit('send-message', { conversationId, ...data }); }
export function onNewMessage(cb) { socket?.on('new-message', cb); return () => socket?.off('new-message', cb); }
export function onSocketError(cb) { socket?.on('error', cb); return () => socket?.off('error', cb); }
export function emitTyping(id) { socket?.emit('typing', { conversationId: id }); }
export function emitStopTyping(id) { socket?.emit('stop-typing', { conversationId: id }); }
export function onUserTyping(cb) { socket?.on('user-typing', cb); return () => socket?.off('user-typing', cb); }
export function onUserStopTyping(cb) { socket?.on('user-stop-typing', cb); return () => socket?.off('user-stop-typing', cb); }
export function markMessagesRead(id) { socket?.emit('mark-read', { conversationId: id }); }
export function onMessagesRead(cb) { socket?.on('messages-read', cb); return () => socket?.off('messages-read', cb); }
export function requestOnlineUsers() { socket?.emit('get-online-users'); }
// Pending listeners registered before socket connects
const _pendingOnlineUsersListeners = [];

export function onOnlineUsers(cb) {
    if (socket) {
        socket.off('online-users', cb);
        socket.on('online-users', cb);
    } else {
        _pendingOnlineUsersListeners.push(cb);
    }
    return () => socket?.off('online-users', cb);
}
export function onUserOnline(cb) { socket?.on('user-online', cb); return () => socket?.off('user-online', cb); }
export function onUserOffline(cb) { socket?.on('user-offline', cb); return () => socket?.off('user-offline', cb); }

// ─── CALL SIGNALING ──────────────────────────────────────────────────────────
export function onIncomingCall(cb) { socket?.on('incoming-call', cb); return () => socket?.off('incoming-call', cb); }
export function onCallAccepted(cb) { socket?.on('call-accepted', cb); return () => socket?.off('call-accepted', cb); }
export function onCallRejected(cb) { socket?.on('call-rejected', cb); return () => socket?.off('call-rejected', cb); }
export function onCallEnded(cb) { socket?.on('call-ended', cb); return () => socket?.off('call-ended', cb); }
export function onIceCandidate(cb) { socket?.on('ice-candidate', cb); return () => socket?.off('ice-candidate', cb); }
export function onCallUnavailable(cb) { socket?.on('call-unavailable', cb); return () => socket?.off('call-unavailable', cb); }
export function initiateCall(targetUserId, callType, offer) { socket?.emit('call-request', { targetUserId, callType, offer }); }
export function acceptCall(callerId, answer) { socket?.emit('call-accept', { callerId, answer }); }
export function rejectCall(callerId) { socket?.emit('call-reject', { callerId }); }
export function sendIceCandidate(targetUserId, candidate) { socket?.emit('ice-candidate', { targetUserId, candidate }); }
export function endCall(targetUserId, callType, duration) { socket?.emit('call-end', { targetUserId, callType, duration }); }

// ─── MEETING INVITES ──────────────────────────────────────────────────────────
export function onMeetingInvite(cb) {
    if (socket) {
        socket.off('meeting-invite', cb);
        socket.on('meeting-invite', cb);
    }
    // Also register for when socket connects later
    const originalConnect = connectSocket;
    return () => socket?.off('meeting-invite', cb);
}

// ─── REAL-TIME DATA EVENTS ────────────────────────────────────────────────────
// Job events
export function onNewJob(cb) { socket?.on('new-job', cb); return () => socket?.off('new-job', cb); }
export function onJobDeleted(cb) { socket?.on('job-deleted', cb); return () => socket?.off('job-deleted', cb); }
export function onJobUpdated(cb) { socket?.on('job-updated', cb); return () => socket?.off('job-updated', cb); }

// Proposal events
export function onNewProposal(cb) { socket?.on('new-proposal', cb); return () => socket?.off('new-proposal', cb); }
export function onProposalStatusChanged(cb) { socket?.on('proposal-status-changed', cb); return () => socket?.off('proposal-status-changed', cb); }

// Notification events
export function onNewNotification(cb) { socket?.on('new-notification', cb); return () => socket?.off('new-notification', cb); }

import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

const loadImage = (url) => {
  return new Promise((resolve, reject) => {
    const img = new window.Image();
    img.crossOrigin = 'Anonymous';
    img.onload = () => resolve(img);
    img.onerror = (e) => reject(e);
    img.src = url;
  });
};

export const generateCustomPDF = async ({ filename, title, tableColumns, tableRows, summaryRows = [] }) => {
  const doc = new jsPDF();
  const pageWidth = doc.internal.pageSize.width;

  // Timestamps on right side
  const timestamp = new Date().toLocaleString();
  doc.setFont("helvetica", "normal");
  doc.setFontSize(9);
  doc.setTextColor(100, 100, 100);
  doc.text(`Generated: ${timestamp}`, pageWidth - 14, 25, { align: 'right' });

  // Try to load logo
  try {
    const logoImg = await loadImage('/Logo2.png');
    doc.addImage(logoImg, 'PNG', 14, 15, 35, 12);
  } catch (err) {
    // If it fails, fallback to text
    doc.setFont("helvetica", "bold");
    doc.setFontSize(24);
    doc.setTextColor(14, 165, 233); // Website cyan color
    doc.text("Connect", 14, 25);
  }

  // Billed To Info
  const user = JSON.parse(localStorage.getItem('user') || '{}');
  const clientName = user.name || 'Client Name';
  const clientEmail = user.email || 'client@example.com';
  const clientPhone = user.phone || '+1 234 567 8900';

  doc.setFontSize(10);
  doc.setTextColor(40, 40, 40);
  doc.setFont("helvetica", "bold");
  doc.text("Billed To:", 14, 40);

  doc.setFont("helvetica", "normal");
  doc.text(clientName, 14, 45);
  doc.text(clientEmail, 14, 50);
  doc.text(clientPhone, 14, 55);

  // Set Title
  doc.setFont("helvetica", "bold");
  doc.setFontSize(14);
  doc.text(title, 14, 70);

  // Add Table
  autoTable(doc, {
    head: [tableColumns],
    body: tableRows,
    startY: 75,
    theme: 'plain',
    headStyles: { textColor: [14, 165, 233], fontStyle: 'bold' },
    styles: { fontSize: 9, cellPadding: 4, textColor: [60, 60, 60] },
    willDrawCell: function (data) {
      if (data.section === 'head') {
        doc.setDrawColor(14, 165, 233);
        doc.setLineWidth(0.5);
        doc.line(data.cell.x, data.cell.y + data.cell.height, data.cell.x + data.cell.width, data.cell.y + data.cell.height);
      } else if (data.section === 'body') {
        doc.setDrawColor(220, 220, 220);
        doc.setLineWidth(0.1);
        doc.line(data.cell.x, data.cell.y + data.cell.height, data.cell.x + data.cell.width, data.cell.y + data.cell.height);
      }
    }
  });

  let finalY = doc.lastAutoTable.finalY + 10;

  if (summaryRows.length > 0) {
    autoTable(doc, {
      body: summaryRows,
      startY: finalY,
      theme: 'plain',
      styles: { fontSize: 10, fontStyle: 'bold', textColor: [40, 40, 40] }
    });
    finalY = doc.lastAutoTable.finalY + 10;
  }

  // --- FOOTER ---
  const pageHeight = doc.internal.pageSize.height;

  // Dark background bar at the bottom
  doc.setFillColor(35, 35, 35);
  doc.rect(0, pageHeight - 30, pageWidth, 30, 'F');

  // Decorative geometric shapes on left (cyan)
  doc.setFillColor(14, 165, 233);
  doc.triangle(0, pageHeight - 30, 60, pageHeight, 0, pageHeight, 'F');

  doc.setFillColor(2, 132, 199);
  doc.triangle(0, pageHeight - 15, 30, pageHeight, 0, pageHeight, 'F');

  // Contact Info
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(9);
  doc.setFont("helvetica", "normal");

  const textY = pageHeight - 16;

  // Contact Info Column 1
  doc.text("Contact Info", 70, textY - 4);
  doc.text("connect_com@admin", 70, textY + 6);

  // Column 2
  doc.text("+91 XXXXXXXX58", 120, textY + 6);

  // Column 3
  doc.text("Nashik, Maharashtra", 160, textY - 4);
  doc.text("www.connect.or.com", 160, textY + 6);

  doc.save(filename);
};
